if(!window.MM) window.MM={};
window.MM['oph_p2_lens']=[
  {q:"A 68-year-old diabetic patient presents with gradual painless diminution of vision and glare while driving at night. Which type of cataract most commonly produces disabling glare despite relatively preserved distance vision initially?",o:["Posterior subcapsular cataract","Hypermature cataract","Morgagnian cataract","Polar cataract","Sutural cataract"],a:0,e:"Posterior subcapsular cataract scatters light near the nodal point of the eye and therefore causes disproportionate glare and difficulty in bright illumination.<br><br>PSC characteristically affects younger patients and diabetics, producing marked near-vision and glare symptoms disproportionate to the visual acuity.<br><br>Morgagnian cataract (C) refers to liquefaction of cortex with sinking nucleus and does not primarily present with early glare symptoms.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract is classically associated with complicated chronic anterior uveitis?",o:["Posterior subcapsular cataract","Nuclear sclerosis","Lamellar cataract","Blue-dot cataract","Coronary cataract"],a:0,e:"Chronic uveitis and prolonged corticosteroid therapy commonly produce posterior subcapsular cataract formation.<br><br>Of its association with steroids, diabetes, radiation, and inflammation.<br><br>Lamellar cataract (C) is usually congenital rather than inflammatory in origin.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A hypermature cataract leaking lens proteins through an intact capsule may produce which complication?",o:["Endophthalmitis","Acute retinal necrosis","Phacolytic glaucoma","Retinal detachment","Central retinal vein occlusion"],a:2,e:"Phacolytic glaucoma develops when high-molecular-weight lens proteins leak from a hypermature cataract and obstruct trabecular outflow.<br><br>Endophthalmitis (A) usually follows infection or surgery rather than spontaneous leakage of lens proteins. Phacolytic glaucoma from leaking hypermature lens proteins is a classic lens-induced emergency.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which type of cataract is most strongly associated with aging?",o:["Nuclear sclerosis","Lamellar cataract","Traumatic cataract","Rosette cataract","Total congenital cataract"],a:0,e:"Nuclear sclerosis is the commonest senile cataract and results from progressive compaction and yellowing of lens nucleus proteins with age.<br><br>Of its characteristic myopic shift.<br><br>Rosette cataract (D) is typically associated with blunt trauma rather than senility.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with progressive nuclear sclerosis reports temporary improvement in near vision without glasses. What is this phenomenon called?",o:["Second sight","Monocular diplopia","Metamorphopsia","Photopsia","Nyctalopia"],a:0,e:"Nuclear sclerosis increases refractive index of the lens nucleus, inducing myopia and temporarily improving near vision in elderly patients.<br><br>Monocular diplopia (B) may occur with irregular lens changes but does not describe temporary near-vision improvement.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which congenital cataract is most commonly associated with maternal rubella infection?",o:["Coronary cataract","Blue-dot cataract","Posterior polar cataract","Total congenital cataract","Sutural cataract"],a:3,e:"Congenital rubella syndrome classically produces dense bilateral congenital cataracts along with deafness and cardiac defects.<br><br>Maternal infection during the first trimester is particularly associated with severe fetal ocular abnormalities.<br><br>Sutural cataracts (E) are usually visually insignificant developmental opacities.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract morphology is classically associated with blunt ocular trauma?",o:["Rosette cataract","Lamellar cataract","Coronary cataract","PSC cataract","Cerulean cataract"],a:0,e:"Blunt trauma commonly produces rosette-shaped posterior cortical lens opacities due to shock-wave disruption of lens fibers.<br><br>Lamellar cataract (B) is congenital and unrelated to trauma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which complication may occur during cataract surgery in pseudoexfoliation syndrome?",o:["Strong zonules","Small pupil with zonular weakness","Retinal artery occlusion","Corneal dystrophy","Optic neuritis"],a:1,e:"Pseudoexfoliation syndrome weakens zonules and often produces poor pupillary dilation, increasing surgical difficulty and complication risk.<br><br>Of its operative implications.<br><br>Strong zonules (A) are opposite to the expected finding in pseudoexfoliation syndrome.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which congenital cataract is usually visually insignificant and discovered incidentally?",o:["Total cataract","Lamellar cataract","Blue-dot cataract","Nuclear cataract","Membranous cataract"],a:2,e:"Blue-dot cataracts are small punctate congenital opacities that usually do not significantly impair vision.<br><br>Recognition of visually insignificant congenital cataracts is important in pediatric ophthalmology assessment.<br><br>Total congenital cataract (A) causes marked visual deprivation requiring urgent management.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which symptom is most characteristic of early posterior subcapsular cataract?",o:["Peripheral field loss","Diplopia only at distance","Severe glare in bright light","Sudden painful vision loss","Floaters and flashes"],a:2,e:"Posterior subcapsular cataracts scatter centrally entering light rays and therefore produce disproportionate glare and difficulty with bright illumination.<br><br>Patients often complain of poor near vision and troublesome night-driving symptoms despite mild lens opacity.<br><br>Peripheral field loss (A) is characteristic of glaucoma rather than cataract.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which type of cataract is commonly associated with diabetes mellitus?",o:["Posterior subcapsular cataract","Coronary cataract","Cerulean cataract","Sutural cataract","Anterior polar cataract"],a:0,e:"Diabetes mellitus accelerates cataractogenesis and is particularly associated with posterior subcapsular lens opacity formation.<br><br>Cerulean cataract (C) is congenital and not specifically linked with diabetes.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is most essential before cataract surgery for intraocular lens power calculation?",o:["Biometry","Visual field testing","Gonioscopy","Fluorescein angiography","Hess charting"],a:0,e:"Biometry measures axial length and corneal curvature for accurate intraocular lens power calculation before cataract surgery.<br><br>Precise IOL calculation is critical for optimal postoperative refractive outcomes.<br><br>Fluorescein angiography (D) evaluates retinal vasculature rather than lens implant power.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract surgery technique is currently considered the standard modern procedure worldwide?",o:["Intracapsular cataract extraction","Extracapsular extraction only","Phacoemulsification","Couching","Discission"],a:2,e:"Phacoemulsification uses ultrasonic fragmentation of the lens nucleus through a small incision and is the standard modern cataract surgery technique.<br><br>Rapid rehabilitation and reduced astigmatism make phacoemulsification the preferred approach.<br><br>Intracapsular extraction (A) is now rarely performed except in selected situations.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which postoperative complication of cataract surgery is caused by posterior capsule opacification?",o:["After-cataract","Endophthalmitis","Corneal ulcer","Iris bombe","Suprachoroidal hemorrhage"],a:0,e:"Posterior capsule opacification results from proliferation of residual lens epithelial cells and is commonly termed after-cataract.<br><br>Endophthalmitis (B) is an infective complication rather than posterior capsule fibrosis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which pediatric cataract requires urgent surgery to prevent amblyopia?",o:["Dense bilateral congenital cataract","Small sutural cataract","Peripheral blue-dot cataract","Coronary cataract","Cerulean cataract"],a:0,e:"Dense congenital cataracts obstruct visual development and may produce irreversible deprivation amblyopia if not treated early.<br><br>Sutural cataracts (B) are often visually insignificant and may not require surgery.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which metabolic disorder is classically associated with sunflower cataract?",o:["Wilson disease","Galactosemia","Diabetes mellitus","Homocystinuria","Hyperparathyroidism"],a:0,e:"Copper deposition in Wilson disease may produce characteristic sunflower cataract and Kayser-Fleischer rings.<br><br>Galactosemia (B) more commonly produces oil-droplet cataract.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which cataract is associated with chronic exposure to infrared radiation in glassblowers?",o:["Glassblower's cataract","Lamellar cataract","Blue-dot cataract","Cerulean cataract","Polar cataract"],a:0,e:"Chronic infrared radiation exposure damages the lens and produces posterior cortical opacities termed glassblower's cataract.<br><br>Occupational cataracts are classic high-yield ophthalmology recall topics.<br><br>Lamellar cataract (B) is congenital and unrelated to infrared exposure.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which postoperative cataract surgery complication presents with severe pain, hypopyon, and marked visual loss?",o:["Posterior capsule opacification","Endophthalmitis","Cystoid macular edema","Corneal astigmatism","Posterior vitreous detachment"],a:1,e:"Postoperative endophthalmitis is a devastating intraocular infection presenting with pain, redness, hypopyon, and profound visual loss.<br><br>Posterior capsule opacification (A) causes gradual painless visual decline rather than acute severe inflammation. Acute postoperative endophthalmitis presenting with pain and hypopyon is an instantly recognisable emergency.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which congenital cataract is characterized by opacity surrounding the fetal nucleus?",o:["Coronary cataract","Lamellar cataract","Posterior polar cataract","Blue-dot cataract","Sutural cataract"],a:1,e:"Lamellar cataract involves a circumferential opacity around the fetal nucleus and is among the commonest congenital cataracts.<br><br>It may be hereditary or associated with metabolic disturbances during lens development.<br><br>Posterior polar cataract (C) involves the posterior capsule rather than the fetal nucleus.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which treatment is standard for visually significant posterior capsule opacification after cataract surgery?",o:["Trabeculectomy","Repeat phacoemulsification","Nd:YAG laser capsulotomy","Penetrating keratoplasty","Vitrectomy"],a:2,e:"Nd:YAG laser posterior capsulotomy creates an opening in the opacified posterior capsule and rapidly restores vision.<br><br>Repeat phacoemulsification (B) is unnecessary because the original cataractous lens has already been removed.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 72-year-old patient complains that his distance vision has worsened, but he can suddenly read newspapers without glasses again. Which cataract change best explains this?",o:["Nuclear sclerosis causing myopic shift","Posterior capsule fibrosis","Cortical hydration","Zonular dehiscence","Corneal astigmatism"],a:0,e:"Progressive nuclear sclerosis increases the refractive index of the lens nucleus, producing acquired myopia and temporary improvement in near vision.<br><br>Posterior capsule fibrosis (B) occurs after surgery and does not produce myopic shift.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which cataract morphology is most classically associated with blunt ocular trauma?",o:["Rosette cataract","Lamellar cataract","Blue-dot cataract","Coronary cataract","Cerulean cataract"],a:0,e:"Blunt trauma transmits shock waves through the lens, producing characteristic stellate or rosette-shaped posterior cortical opacities.<br><br>Lamellar cataract (B) is congenital rather than traumatic.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which congenital cataract is most visually significant and commonly requires early surgery?",o:["Blue-dot cataract","Sutural cataract","Dense total congenital cataract","Coronary cataract","Cerulean cataract"],a:2,e:"Dense congenital cataracts obstruct visual development and can rapidly produce irreversible deprivation amblyopia if untreated.<br><br>Early surgery and amblyopia therapy are essential in pediatric cataract management.<br><br>Sutural cataracts (B) are usually visually insignificant incidental findings.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract is particularly associated with prolonged corticosteroid use?",o:["Posterior subcapsular cataract","Cortical cataract","Nuclear sclerosis","Traumatic cataract","Coronary cataract"],a:0,e:"Long-term corticosteroid therapy commonly induces posterior subcapsular cataract formation.<br><br>It also occurs in asthma, uveitis, and transplant patients.<br><br>Traumatic cataract (D) follows ocular injury rather than steroid exposure.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which cataract surgery complication typically presents weeks later with painless gradual visual decline?",o:["Endophthalmitis","Suprachoroidal hemorrhage","Posterior capsule opacification","Expulsive hemorrhage","Acute angle closure"],a:2,e:"Posterior capsule opacification develops from residual lens epithelial cell proliferation after cataract surgery.<br><br>It is the commonest late postoperative complication and is treated with Nd:YAG capsulotomy. Delayed-onset chronic pseudophakic endophthalmitis is a classic indolent-presentation question.<br><br>Endophthalmitis (A) usually presents acutely with pain and severe inflammation.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which metabolic disorder is classically associated with oil-droplet cataract?",o:["Galactosemia","Diabetes mellitus","Wilson disease","Hyperparathyroidism","Homocystinuria"],a:0,e:"Galactose accumulation within the lens produces osmotic damage leading to characteristic oil-droplet cataract formation.<br><br>Wilson disease (C) is associated with sunflower cataract rather than oil-droplet cataract.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which finding is most characteristic of hypermature Morgagnian cataract?",o:["Liquefied cortex with sunken nucleus","Posterior capsule rupture only","Dense posterior polar opacity","Lamellar cortical opacity","Blue punctate opacities"],a:0,e:"Morgagnian cataract develops when the lens cortex liquefies and the dense nucleus sinks inferiorly within the capsule.<br><br>Posterior polar opacity (C) describes posterior polar cataract rather than Morgagnian change.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is most essential for accurate intraocular lens power calculation before cataract surgery?",o:["Gonioscopy","Pachymetry","Biometry","Automated perimetry","Fluorescein angiography"],a:2,e:"Biometry measures axial length and corneal curvature to calculate appropriate intraocular lens power before surgery.<br><br>Accurate IOL calculation is fundamental for optimal postoperative refractive outcome.<br><br>Perimetry (D) evaluates visual fields rather than refractive planning.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which cataract surgery technique uses ultrasonic fragmentation of the lens nucleus?",o:["Intracapsular extraction","Couching","Discission","Phacoemulsification","Linear extraction"],a:3,e:"Phacoemulsification uses ultrasound energy to emulsify the lens nucleus through a small incision.<br><br>It is currently the standard modern cataract surgery worldwide due to rapid visual rehabilitation.<br><br>Intracapsular extraction (A) involves removal of the entire lens with capsule and is now rarely performed.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract is most commonly associated with diabetes mellitus?",o:["Posterior subcapsular cataract","Lamellar cataract","Coronary cataract","Cerulean cataract","Sutural cataract"],a:0,e:"Diabetes accelerates cataract formation and is strongly associated with posterior subcapsular lens opacity.<br><br>PSC cataracts often produce disproportionate glare and near-vision symptoms in diabetic patients.<br><br>Cerulean cataract (D) is congenital rather than metabolic in origin.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom is most typical of posterior subcapsular cataract?",o:["Peripheral field constriction","Severe glare in bright light","Sudden painful blindness","Floaters and flashes","Diplopia only in dim light"],a:1,e:"Posterior subcapsular cataracts lie near the nodal point of the eye and scatter centrally entering light rays, producing disabling glare.<br><br>Patients often complain of difficulty reading and night-driving despite relatively mild lens opacity.<br><br>Peripheral field constriction (A) suggests glaucoma rather than cataract.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which postoperative cataract surgery complication presents with hypopyon and severe ocular pain?",o:["Posterior capsule opacification","Corneal astigmatism","Endophthalmitis","Cystoid macular edema","Retinal pigment epithelial detachment"],a:2,e:"Postoperative endophthalmitis is a severe intraocular infection characterized by pain, redness, hypopyon, and profound visual loss.<br><br>Recognition of this emergency is heavily emphasized in cataract surgery recalls. Acute postoperative endophthalmitis with hypopyon is a high-stakes emergency pattern.<br><br>Posterior capsule opacification (A) causes gradual painless visual deterioration rather than acute inflammation.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which congenital cataract typically appears as opacity surrounding the fetal nucleus?",o:["Posterior polar cataract","Lamellar cataract","Coronary cataract","Blue-dot cataract","Membranous cataract"],a:1,e:"Lamellar cataract involves circumferential opacity around the fetal nucleus and is among the commonest congenital cataracts.<br><br>It may result from hereditary factors or metabolic disturbances during lens development.<br><br>Posterior polar cataract (A) involves posterior capsule opacity rather than lamellar fetal nucleus involvement.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which occupational exposure classically predisposes to glassblower's cataract?",o:["Infrared radiation","Ultraviolet radiation","X-ray exposure only","Chemical alkali fumes","Welding sparks only"],a:0,e:"Chronic infrared exposure damages the lens and produces posterior cortical opacities termed glassblower's cataract.<br><br>Ultraviolet radiation (B) contributes more broadly to cortical lens aging rather than classic glassblower's cataract.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which lens-induced glaucoma occurs because of swollen intumescent cataract causing angle closure?",o:["Phacomorphic glaucoma","Pigmentary glaucoma","Phacolytic glaucoma","Neovascular glaucoma","Juvenile glaucoma"],a:0,e:"Intumescent mature cataract may push the iris forward, narrowing the angle and precipitating secondary angle-closure glaucoma.<br><br>Phacolytic glaucoma (C) results from leakage of lens proteins rather than lens swelling.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract is most strongly associated with myotonic dystrophy?",o:["Christmas-tree cataract","Blue-dot cataract","Lamellar cataract","Coronary cataract","Posterior polar cataract"],a:0,e:"Polychromatic needle-like lens opacities called Christmas-tree cataracts are classically associated with myotonic dystrophy.<br><br>Posterior polar cataract (E) has no strong association with myotonic dystrophy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which treatment is standard for visually significant posterior capsule opacification?",o:["Repeat cataract extraction","Penetrating keratoplasty","Nd:YAG laser capsulotomy","Vitrectomy","Trabeculectomy"],a:2,e:"Nd:YAG laser capsulotomy creates an opening in the opacified posterior capsule and rapidly restores visual clarity.<br><br>Vitrectomy (D) is unnecessary because the opacity lies within the posterior capsule rather than vitreous cavity.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which cataract type is usually bilateral and hereditary?",o:["Traumatic cataract","Lamellar cataract","Rosette cataract","Glassblower's cataract","Phacolytic cataract"],a:1,e:"Lamellar cataracts are commonly bilateral, hereditary, and associated with developmental disturbances during lens formation.<br><br>This congenital cataract frequently appears in pediatric ophthalmology recalls.<br><br>Rosette cataracts (C) are traumatic rather than hereditary.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which structure is preserved during extracapsular cataract extraction?",o:["Posterior capsule","Entire lens capsule","Lens nucleus","Zonular fibers","Corneal endothelium"],a:0,e:"Extracapsular cataract extraction removes the lens nucleus and cortex while preserving the posterior capsule for intraocular lens support.<br><br>Posterior capsule preservation reduces vitreous loss and improves postoperative stability.<br><br>The entire capsule (B) is removed only during intracapsular extraction.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which congenital infection is classically associated with cataract, deafness, and cardiac defects?",o:["Rubella","Herpes simplex","Cytomegalovirus","Toxoplasmosis","Syphilis"],a:0,e:"Congenital rubella syndrome classically causes cataract, sensorineural deafness, and congenital cardiac anomalies.<br><br>Maternal infection during early pregnancy carries the highest fetal ocular risk.<br><br>Toxoplasmosis (D) more commonly causes chorioretinitis rather than congenital cataract triad.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 65-year-old man presents with gradual painless loss of vision. Slit-lamp examination reveals a central brown opacity of the lens. Which type of cataract is this?",o:["Cortical cataract","Posterior subcapsular cataract","Nuclear sclerotic cataract","Anterior subcapsular cataract","Morgagnian"],a:2,e:"Nuclear sclerotic cataract results from progressive hardening and yellowing of the lens nucleus due to protein aggregation and denaturation; it is the most common age-related cataract type.<br><br>The nucleus undergoes increased light scattering as insoluble proteins accumulate; patients often experience index myopia, temporarily improving near vision, a phenomenon called second sight. Distinguishing nuclear from cortical opacities on slit-lamp is a classic morphology question.<br><br>Cortical cataract (A) presents with spoke-like opacities; posterior subcapsular (B) causes glare and near vision difficulty; Morgagnian (E) is a hypermature liquefied variant.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A diabetic patient develops cataract at a younger age than expected. Which biochemical pathway is primarily responsible?",o:["Sorbitol accumulation via aldose reductase pathway","Maillard glycation pathway","Oxidative stress via superoxide dismutase deficiency","Calcium-dependent protease activation","Glutathione"],a:0,e:"In hyperglycaemia, excess glucose enters the polyol pathway; aldose reductase converts it to sorbitol, which accumulates within lens fibres causing osmotic swelling, hydration, and opacity.<br><br>Sorbitol cannot cross cell membranes efficiently; the resulting osmotic gradient draws water into lens fibres, disrupting their architecture and accelerating cataract formation in diabetic patients.<br><br>Maillard glycation (B) contributes to nuclear browning; oxidative stress (C) plays a secondary role; calcium-dependent proteases (D) are relevant in traumatic cataract.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which type of cataract is classically associated with long-term systemic corticosteroid use?",o:["Nuclear cataract","Cortical cataract","Anterior subcapsular cataract","Posterior subcapsular cataract","Lamellar cataract"],a:3,e:"Posterior subcapsular cataract is the classic steroid-induced type; it develops at the posterior pole of the lens just beneath the capsule and causes disproportionate visual disturbance relative to its size.<br><br>The opacity interferes maximally with vision in bright light and during near work because miosis concentrates light through the affected posterior pole, worsening glare and reading difficulty.<br><br>Nuclear cataract (A) is age-related; cortical (B) is spoke-like; anterior subcapsular (C) follows trauma or uveitis; lamellar (E) is congenital in origin.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A patient with hypocalcaemia following thyroid surgery develops bilateral cataracts. What is the characteristic morphology?",o:["Polychromatic lens opacities with cortical flakes","Posterior subcapsular plaque","Brown nuclear opacity","Anterior polar opacity","Morgagnian liquefaction"],a:0,e:"Hypocalcaemic cataract, seen in hypoparathyroidism, produces characteristic polychromatic iridescent opacities and cortical flakes separated from the capsule by a clear zone; bilateral presentation is typical.<br><br>Low calcium levels disrupt lens fibre ionic homeostasis; calcium is essential for maintaining membrane integrity, and its deficiency causes abnormal hydration and protein precipitation within the cortex.<br><br>Brown nuclear opacity (C) is age-related nuclear sclerosis; posterior subcapsular plaque (B) is steroid-induced; anterior polar (D) is congenital; Morgagnian (E) is hypermature.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which investigation is most important before cataract surgery to determine the power of the intraocular lens to be implanted?",o:["Corneal topography","A-scan ultrasonography biometry","B-scan ultrasonography","Specular microscopy","Optical coherence tomography"],a:1,e:"A-scan biometry measures axial length of the eye, which along with keratometry readings, is used in the SRK/T or Holladay formula to calculate the required IOL power for emmetropia.<br><br>Accurate axial length measurement is the single most critical determinant of IOL power; even a 1 mm error in axial length measurement results in approximately 2.5 dioptres of postoperative refractive error.<br><br>Corneal topography (A) assesses corneal shape, not axial length; B-scan (C) detects posterior segment pathology; specular microscopy (D) evaluates endothelial cell count; OCT (E) assesses macula.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A newborn is found to have a dense unilateral cataract. What is the most critical reason for urgent surgical intervention?",o:["Prevention of amblyopia","Risk of secondary glaucoma","Risk of lens-induced uveitis","Cosmetic improvement","Prevention of strabismus"],a:0,e:"Dense unilateral congenital cataract deprives the visual cortex of patterned stimulation during the critical period of visual development; this leads to deprivation amblyopia, which becomes irreversible if not treated promptly.<br><br>Surgery is recommended within the first 6 to 10 weeks of life, followed immediately by optical rehabilitation and occlusion therapy of the fellow eye to stimulate the amblyopic eye effectively.<br><br>Secondary glaucoma (B) is a complication, not the primary indication; lens-induced uveitis (C) occurs with hypermature cataracts; cosmesis (D) and strabismus (E) are secondary concerns.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which suture pattern of the embryonic lens nucleus is Y-shaped anteriorly and inverted Y-shaped posteriorly?",o:["Infantile nucleus sutures","Fetal nucleus sutures","Adult nucleus sutures","Embryonic nucleus sutures","Cortical sutures"],a:1,e:"The fetal nucleus, formed between the third month of gestation and birth, develops Y-shaped sutures anteriorly and inverted Y-shaped sutures posteriorly where secondary lens fibres meet during intrauterine growth.<br><br>These suture lines are clinically important because congenital cataracts frequently follow these patterns, producing stellate or sutural opacities visible on slit-lamp examination in affected neonates.<br><br>Embryonic nucleus (D) is the earliest core with no sutures; infantile nucleus (A) forms after birth; adult nucleus (C) has more complex branching sutures; cortical sutures (E) are peripheral.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A mature cataract in which the entire lens content has liquefied and the nucleus sinks to the bottom is called:",o:["Intumescent cataract","Hypermature cataract","Morgagnian cataract","Brunescent cataract","Sclerotic cataract"],a:2,e:"Morgagnian cataract is an advanced hypermature stage in which the cortex completely liquefies, allowing the hard brown nucleus to sink inferiorly within the capsule due to gravity.<br><br>The liquefied cortex may leak through the capsule, triggering phacolytic glaucoma or lens-induced uveitis; the sunken nucleus is visible on slit-lamp examination as a dense inferior opacity.<br><br>Intumescent cataract (A) is swollen with intact cortex; hypermature (B) is the broader category; brunescent (D) refers to brown nuclear hardening; sclerotic (E) describes nuclear density increase.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Phacolytic glaucoma occurs due to leakage of lens proteins through an intact capsule in which stage of cataract?",o:["Immature cataract","Mature cataract","Intumescent cataract","Hypermature cataract","Nuclear sclerotic cataract"],a:3,e:"In hypermature cataract, the lens capsule becomes permeable; liquefied cortical proteins leak into the anterior chamber, where they are engulfed by macrophages that subsequently block the trabecular meshwork.<br><br>This macrophage-mediated trabecular obstruction raises intraocular pressure acutely; it is an open-angle mechanism, distinguishing it from phacomorphic glaucoma, which is angle-closure due to an intumescent lens.<br><br>Immature cataract (A) has an intact barrier; mature (B) is fully opaque but capsule is still intact; intumescent (C) causes angle closure; nuclear sclerotic (E) does not cause glaucoma directly.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Phacomorphic glaucoma is caused by:",o:["Pupil block by an intumescent swollen lens","Leakage of lens proteins through the capsule","Deposition of lens material in the trabecular meshwork","Posterior synechiae formation around the lens","Subluxation of the lens into the anterior chamber"],a:0,e:"Phacomorphic glaucoma is a secondary angle-closure glaucoma caused by an intumescent swollen lens pushing the iris-lens diaphragm anteriorly, narrowing the angle and obstructing aqueous outflow at the trabecular meshwork.<br><br>The swollen lens causes relative pupil block, shallowing of the anterior chamber; it is treated by lens extraction, which relieves the mechanical obstruction and restores normal anterior chamber depth.<br><br>Lens protein leakage (B) causes phacolytic glaucoma; trabecular deposition (C) occurs in phacolytic type; posterior synechiae (D) cause iris bombe; subluxation (E) causes lens-particle glaucoma.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A patient undergoes extracapsular cataract extraction. Which structure is deliberately left behind?",o:["Anterior lens capsule","Lens nucleus","Posterior lens capsule","Lens cortex","Zonular fibres"],a:2,e:"In extracapsular cataract extraction and phacoemulsification, the posterior capsule is deliberately preserved to support the intraocular lens within the capsular bag and maintain the barrier between anterior and posterior segments.<br><br>Preserving the posterior capsule reduces the risk of vitreous prolapse, cystoid macular oedema, and retinal detachment, which are significantly more common following intracapsular extraction where the entire capsule is removed. The capsular structures delineated during ECCE are a recurring anatomy-of-surgery question.<br><br>The anterior capsule (A) is opened via capsulorhexis; the nucleus (B) is emulsified; cortex (D) is aspirated; zonular fibres (E) are preserved but not the target of deliberate retention.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Posterior capsule opacification following cataract surgery is caused by proliferation of which cells?",o:["Residual lens epithelial cells","Corneal endothelial cells","Keratocytes","Fibroblasts of the vitreous","Trabecular meshwork cells"],a:0,e:"Posterior capsule opacification, or after-cataract, results from proliferation and migration of residual lens epithelial cells from the equatorial region onto the posterior capsule, forming Elschnig pearls or a fibrous membrane.<br><br>These cells undergo epithelial-mesenchymal transformation, producing collagen and causing capsular wrinkling and fibrosis; it is the most common late complication of cataract surgery, treated with Nd:YAG laser capsulotomy.<br><br>Keratocytes (C) are corneal stromal cells; corneal endothelial cells (B) line Descemet's membrane; vitreous fibroblasts (D) are unrelated; trabecular meshwork cells (E) regulate aqueous outflow.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which congenital cataract is associated with Galactosaemia and presents with an oil droplet appearance on retroillumination?",o:["Lamellar cataract","Nuclear cataract","Oil droplet cataract","Sutural cataract","Posterior lenticonus"],a:2,e:"Oil droplet cataract is the classic finding in galactosaemia and galactokinase deficiency; accumulation of galactitol within the lens via the polyol pathway causes osmotic swelling producing a central oil droplet appearance on retroillumination.<br><br>Early dietary restriction of galactose can reverse the opacity in galactokinase deficiency; in classic galactosaemia, systemic complications of enzyme deficiency are more severe, requiring urgent dietary intervention beyond the eye alone. The oil-droplet galactosaemia cataract is a classic reversible congenital association.<br><br>Lamellar cataract (A) is zonular and associated with hypocalcaemia; nuclear cataract (B) is central but not oil droplet; sutural (D) follows fetal nucleus sutures; posterior lenticonus (E) is a capsular bulge.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which syndrome is associated with bilateral posterior subcapsular cataract, sensorineural deafness, and renal failure in a young male?",o:["Marfan syndrome","Alport syndrome","Lowe syndrome","Nance-Horan syndrome","Fabry disease"],a:1,e:"Alport syndrome is an X-linked disorder caused by mutations in type IV collagen genes; it presents with progressive nephritis, sensorineural hearing loss, and bilateral anterior lenticonus, though posterior subcapsular cataract also occurs.<br><br>The disease predominantly affects males; type IV collagen is essential for the basement membrane of the lens capsule, glomeruli, and cochlea, explaining the triad of ocular, renal, and auditory involvement.<br><br>Marfan syndrome (A) causes ectopia lentis; Lowe syndrome (C) causes congenital cataract with renal tubular acidosis; Nance-Horan (D) causes dense nuclear cataract; Fabry (E) causes corneal verticillata.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient presents with sudden decrease in vision after blunt trauma to the eye. Slit-lamp shows a rosette-shaped opacity. What is the diagnosis?",o:["Traumatic rosette cataract","Nuclear sclerotic cataract","Posterior subcapsular cataract","Cortical spoke cataract","Anterior polar"],a:0,e:"Traumatic rosette cataract follows blunt ocular trauma; the concussive force disrupts lens fibre architecture along suture lines, producing a characteristic stellate or rosette-shaped opacity typically in the posterior cortex.<br><br>Early rosette cataracts may be reversible if the trauma is mild; persistent opacities tend to progress to dense cortical or total cataract requiring surgical intervention depending on visual impact.<br><br>Nuclear sclerotic cataract (B) is age-related and central; posterior subcapsular (C) follows steroid use or radiation; spoke cataract (D) is cortical and age-related; anterior polar (E) is congenital.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Cataract associated with atopic dermatitis is characteristically:",o:["Anterior subcapsular shield cataract","Nuclear brunescent cataract","Posterior subcapsular cataract","Lamellar cataract","Morgagnian"],a:0,e:"Atopic cataract is characteristically an anterior subcapsular shield-shaped opacity, appearing as a dense plaque just beneath the anterior capsule; it typically develops in young patients with severe chronic atopic dermatitis.<br><br>The mechanism involves chronic inflammation, frequent eye rubbing, and possibly inflammatory mediators; the opacity often matures rapidly and may require early surgical intervention in affected young adults.<br><br>Nuclear brunescent (B) is age-related; posterior subcapsular (C) is steroid or radiation-induced; lamellar (D) is congenital; Morgagnian (E) is the hypermature liquefied stage.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which cataract is characteristically seen in myotonic dystrophy?",o:["Posterior subcapsular cataract","Nuclear cataract","Christmas tree cataract","Anterior polar cataract","Lamellar cataract"],a:2,e:"Christmas tree cataract, also called polychromatic or iridescent cataract, is the hallmark of myotonic dystrophy; it consists of multicoloured needle-shaped crystals scattered throughout the lens cortex and nucleus.<br><br>Myotonic dystrophy is an autosomal dominant condition; ocular features include ptosis, external ophthalmoplegia, and Christmas tree cataract, which often precedes systemic manifestations and may be the presenting ophthalmic finding.<br><br>Posterior subcapsular cataract (A) is steroid-related; nuclear cataract (B) is age-related; anterior polar (D) is congenital; lamellar cataract (E) is associated with neonatal hypocalcaemia or hypoglycaemia.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Second sight in nuclear cataract refers to:",o:["Improvement in distance vision due to corneal compensation","Temporary improvement in near vision due to index myopia","Recovery of colour vision after cataract surgery","Improved vision in dim light due to pupil dilation","Reversal of cataract opacity after treatment"],a:1,e:"Second sight occurs in nuclear sclerotic cataract when increased refractive index of the hardening nucleus causes index myopia; previously presbyopic patients notice temporary improvement in near vision without spectacles.<br><br>This improvement is transient; as the cataract progresses, the opacity increases light scattering and the myopic shift can no longer compensate, leading to progressive deterioration of both near and distance vision.<br><br>Distance vision improvement (A) does not occur; colour vision recovery (C) is post-surgical; dim light improvement (D) describes night myopia; reversal of opacity (E) does not occur in nuclear cataract.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Elschnig pearls seen after cataract surgery are formed by:",o:["Proliferating residual lens epithelial cells on the posterior capsule","Retained cortical material in the anterior chamber","Calcium deposits on the intraocular lens surface","Fibrin deposits following surgical inflammation","Vitreous prolapse through the posterior capsule"],a:0,e:"Elschnig pearls are bladder-like cells formed by proliferation of residual equatorial lens epithelial cells that migrate to the posterior capsule after cataract surgery; they are a form of posterior capsule opacification.<br><br>These cells retain their capacity for division; they form clusters of vacuolated, swollen cells resembling fish eggs on the posterior capsule, causing visual disturbance treated effectively with Nd:YAG laser capsulotomy.<br><br>Retained cortical material (B) causes postoperative inflammation; calcium deposits (C) cause IOL calcification; fibrin deposits (D) cause early postoperative haze; vitreous prolapse (E) is a surgical complication.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following best describes the mechanism of action of Nd:YAG laser capsulotomy?",o:["Thermal coagulation of posterior capsule","Photochemical disruption of capsular collagen","Photodisruption creating a central opening in the posterior capsule","Photoablation of residual lens epithelial cells","Photocoagulation of proliferating epithelial cells"],a:2,e:"Nd:YAG laser capsulotomy uses short high-energy pulses to create a plasma at the focal point; this photodisruptive effect vaporises the posterior capsule, creating a central optical opening that clears the visual axis.<br><br>The procedure is performed as an outpatient; complications include transient IOP spike, IOL pitting, cystoid macular oedema, and rarely retinal detachment, particularly in myopic eyes with pre-existing peripheral retinal degeneration.<br><br>Thermal coagulation (A) describes diode laser; photochemical disruption (B) describes UV photoablation in PRK; photoablation (D) and photocoagulation (E) are mechanisms of other laser modalities.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Cataract in Wilson's disease is characterised by which specific finding?",o:["Oil droplet opacity","Sunflower cataract","Christmas tree opacity","Posterior subcapsular plaque","Anterior polar opacity"],a:1,e:"Sunflower cataract is pathognomonic of Wilson's disease; copper deposited in the anterior and posterior lens capsule forms a disc-shaped central opacity with petal-like radiations resembling a sunflower, best seen on slit-lamp.<br><br>Wilson's disease is an autosomal recessive disorder of copper metabolism; the sunflower cataract does not significantly impair vision and may regress with chelation therapy using D-penicillamine or zinc supplementation.<br><br>Oil droplet opacity (A) is seen in galactosaemia; Christmas tree opacity (C) occurs in myotonic dystrophy; posterior subcapsular plaque (D) is steroid-induced; anterior polar opacity (E) is congenital in origin.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following is the most common cause of bilateral cataract in a neonate?",o:["Galactosaemia","Rubella","Lowe syndrome","Idiopathic or hereditary","Hypoparathyroidism"],a:3,e:"The most common cause of bilateral congenital cataract is idiopathic or hereditary; autosomal dominant inheritance is the most frequent genetic pattern, with mutations in crystallin genes or connexin proteins responsible in many cases.<br><br>Systematic evaluation for metabolic and infectious causes is still essential; however, in the majority of bilateral cases no systemic cause is identified, and careful family history and genetic counselling form the cornerstone of management.<br><br>Galactosaemia (A) and rubella (B) are important but less common causes; Lowe syndrome (C) is X-linked and rare; hypoparathyroidism (E) causes lamellar cataract but is not the most common aetiology.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Cataract extraction is combined with trabeculectomy in a patient with coexisting glaucoma. This combined procedure is called:",o:["Phaco-vitrectomy","Phacotrabeculectomy","Phaco-iridectomy","Triple procedure","Combined extracapsular extraction"],a:1,e:"Phacotrabeculectomy combines phacoemulsification cataract extraction with trabeculectomy in a single surgical sitting; it is indicated when both visually significant cataract and uncontrolled glaucoma coexist and require simultaneous surgical management.<br><br>The combined approach reduces the total number of surgeries and anaesthetic exposures; however, trabeculectomy success rates are slightly lower in combined procedures compared to trabeculectomy performed as a standalone operation. Combined phaco-trabeculectomy in coexisting cataract and glaucoma is an emphasised management option.<br><br>Phaco-vitrectomy (A) combines cataract surgery with vitreoretinal work; phaco-iridectomy (C) is not a standard term; triple procedure (D) refers to corneal graft with cataract extraction and IOL; option E is non-specific.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A patient presents with ectopia lentis, tall stature, arachnodactyly, and high arched palate. The lens is displaced in which direction in this condition?",o:["Superiorly and temporally","Inferiorly and nasally","Inferiorly and temporally","Superiorly and nasally","Centrally with no displacement"],a:0,e:"In Marfan syndrome, ectopia lentis is bilateral and characteristically displaced superiorly and temporally due to weakness of the zonular fibres in the inferonasal quadrant where they are structurally deficient.<br><br>The zonules remain visible and are not broken, distinguishing Marfan ectopia lentis from homocystinuria, where the lens dislocates inferiorly and nasally due to complete zonular rupture from fibrillin-related connective tissue defects.<br><br>Inferior and nasal displacement (B) is characteristic of homocystinuria; inferotemporal (C) and superonasal (D) are not classic patterns for Marfan; central position (E) describes a normally positioned lens.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which type of intraocular lens is preferred in a patient with posterior capsule rupture during phacoemulsification?",o:["Posterior chamber IOL in the capsular bag","Anterior chamber IOL or sulcus-fixated posterior chamber IOL","Multifocal IOL in the capsular bag","Toric IOL in the capsular bag","Accommodating IOL in the"],a:1,e:"When posterior capsule rupture occurs during phacoemulsification, the capsular bag can no longer support a standard posterior chamber IOL; the surgeon must place the lens either in the anterior chamber or in the ciliary sulcus behind the iris.<br><br>Sulcus fixation requires a lens with appropriate haptic design and larger overall diameter; anterior chamber IOLs carry risks of corneal endothelial damage and angle injury, making sulcus fixation the preferred option when sulcus support is adequate. IOL choice with a deficient posterior capsule is a recurring surgical-decision point.<br><br>Capsular bag placement (options A, C, D, E) is contraindicated with posterior capsule rupture as the supporting structure is absent; multifocal and toric lenses are specifically avoided in sulcus placement due to optical and rotational stability concerns.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A patient presents with white reflex in the pupil of a 3-month-old infant. Which is the most important differential diagnosis to exclude before labelling it as congenital cataract?",o:["Persistent hyperplastic primary vitreous","Retinoblastoma","Coats disease","Toxocara endophthalmitis","Retinopathy of prematurity"],a:1,e:"Leukocoria in an infant must have retinoblastoma excluded as the highest priority; it is the most common intraocular malignancy of childhood and carries life-threatening implications if diagnosis is delayed beyond early presentation.<br><br>Retinoblastoma presents with leukocoria, strabismus, and occasionally secondary glaucoma; urgent ophthalmoscopy under anaesthesia, ocular ultrasound, and MRI are performed before any surgical intervention on the eye.<br><br>Persistent hyperplastic primary vitreous (A), Coats disease (C), toxocara (D), and retinopathy of prematurity (E) all cause leukocoria but are not life-threatening, making retinoblastoma the mandatory first exclusion.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following congenital cataracts has the worst visual prognosis if left untreated?",o:["Unilateral dense nuclear cataract","Bilateral sutural cataract","Bilateral lamellar cataract","Bilateral anterior polar cataract","Bilateral coronary cataract"],a:0,e:"Unilateral dense congenital cataract carries the worst visual prognosis because complete visual deprivation of one eye during the critical period leads to severe irreversible deprivation amblyopia if not corrected within the first weeks of life.<br><br>The fellow eye competes aggressively during visual cortex development; even after successful surgery and optical rehabilitation, achieving good visual acuity requires prolonged patching of the normal eye, with compliance being a major limiting factor.<br><br>Bilateral lamellar (C), sutural (B), anterior polar (D), and coronary (E) cataracts are partial opacities that allow some visual stimulation, resulting in significantly better prognosis than a dense unilateral cataract.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Rubella cataract has which classic characteristic that distinguishes it from other congenital cataracts?",o:["Oil droplet appearance on retroillumination","Live virus persists within the lens for years","Associated with anterior lenticonus","Bilateral sutural pattern of opacity","Spontaneous resolution after"],a:1,e:"Rubella cataract is unique because the rubella virus remains viable within the lens substance for up to three years after birth; this has critical surgical implications as lens extraction can release live virus into the anterior chamber causing severe endophthalmitis.<br><br>Surgeons operating on rubella cataracts must be aware of this risk; early surgery before one to two years of age carries higher risk of viral release, and appropriate precautions must be taken perioperatively. The pearly nuclear rubella cataract distinguishing it from other congenital types is a classic differentiator.<br><br>Oil droplet appearance (A) is pathognomonic of galactosaemia; anterior lenticonus (C) occurs in Alport syndrome; sutural pattern (D) is not specific to rubella; spontaneous resolution (E) does not occur in rubella cataract.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A patient on long-term chlorpromazine therapy develops which characteristic ocular finding in the lens?",o:["Posterior subcapsular stellate cataract","Anterior subcapsular pigmented stellate opacity","Nuclear brunescent cataract","Oil droplet opacity","Christmas tree cataract"],a:1,e:"Chlorpromazine, a phenothiazine antipsychotic, deposits pigment granules in the anterior subcapsular zone and anterior lens capsule, producing a characteristic stellate or star-shaped brown pigmented opacity visible on slit-lamp examination.<br><br>The deposits are dose and duration dependent; patients on high cumulative doses also develop brown corneal and conjunctival pigmentation; regular slit-lamp monitoring is recommended for patients on long-term phenothiazine therapy.<br><br>Posterior subcapsular cataract (A) is steroid or radiation-induced; nuclear brunescent (C) is age-related; oil droplet (D) is galactosaemia; Christmas tree opacity (E) is the hallmark of myotonic dystrophy.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which formula is most accurate for calculating IOL power in a patient with a very short axial length?",o:["SRK II formula","SRK/T formula","Holladay 1 formula","Hoffer Q formula","Barrett Universal II formula"],a:3,e:"Hoffer Q formula is most accurate for short eyes with axial length less than 22 mm; it incorporates anterior chamber depth as a variable and has been validated to produce the least hyperopic surprise in nanophthalmic and short eyes.<br><br>Standard third-generation formulas like SRK/T tend to produce hyperopic outcomes in short eyes; for eyes shorter than 22 mm, Hoffer Q or modern AI-based formulas such as Barrett or Kane formula are preferred to minimise refractive error.<br><br>SRK II (A) is an outdated regression formula; SRK/T (B) is best for long eyes; Holladay 1 (C) performs well for average eyes; Barrett Universal II (E) is excellent overall but Hoffer Q remains classic for short eyes specifically.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A patient with cataract also has corneal astigmatism of 2.5 dioptres. Which IOL would best address both conditions simultaneously?",o:["Toric IOL","Monofocal IOL","Multifocal IOL","Accommodating IOL","Extended depth of focus IOL"],a:0,e:"Toric IOL has cylinder correction built into the lens optic; it corrects pre-existing corneal astigmatism at the time of cataract surgery, reducing or eliminating spectacle dependence for distance vision in patients with significant regular astigmatism.<br><br>Accurate preoperative corneal topography and precise rotational alignment during surgery are essential; even 10 degrees of rotational misalignment reduces the toric effect by approximately 33%, making correct axis placement critical for optimal outcomes.<br><br>Multifocal IOL (C) corrects presbyopia, not astigmatism; monofocal IOL (B) does not address astigmatism; accommodating IOL (D) mimics accommodation; extended depth of focus (E) extends range of vision but does not correct cylinder.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Electric shock cataract characteristically produces opacity in which location?",o:["Nuclear zone","Posterior subcapsular zone","Anterior and posterior subcapsular zone","Cortical spoke pattern","Lamellar zone"],a:2,e:"Electric shock and lightning strike cataracts characteristically affect both the anterior and posterior subcapsular zones simultaneously; the opacity may develop days to weeks after the electrical injury and can progress to total cataract.<br><br>The mechanism involves electrical disruption of lens epithelial cell membranes and ion pump failure causing abnormal hydration; the anterior subcapsular epithelium and the posterior bow cells are most vulnerable to electrical injury.<br><br>Nuclear zone opacity (A) is age-related; purely posterior subcapsular (B) is steroid or radiation-induced; cortical spoke pattern (D) is age-related cortical cataract; lamellar zone (E) is associated with metabolic causes in infancy.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Infrared radiation exposure, classically seen in glassblowers, produces which type of cataract?",o:["Posterior subcapsular exfoliation cataract","Anterior subcapsular cataract","Nuclear brunescent cataract","Cortical cataract","Lamellar cataract"],a:0,e:"Glassblower's cataract results from chronic infrared radiation exposure; it produces exfoliation of the anterior lens capsule with curling of the outermost lamella, alongside posterior subcapsular opacity, constituting a distinct occupational cataract pattern.<br><br>Infrared radiation penetrates to the lens causing thermal damage; the exfoliated capsular scrolls floating in the anterior chamber are pathognomonic; true exfoliation must be distinguished from pseudoexfoliation syndrome caused by abnormal fibrillar material deposition.<br><br>Nuclear brunescent (C) is age-related; anterior subcapsular (B) is seen in atopic disease or trauma; cortical cataract (D) is age-related; lamellar cataract (E) is metabolic and congenital in aetiology.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following is the most common complication of phacoemulsification cataract surgery intraoperatively?",o:["Posterior capsule rupture","Suprachoroidal haemorrhage","Nucleus drop into vitreous","Corneal endothelial decompensation","Zonular"],a:0,e:"Posterior capsule rupture is the most common serious intraoperative complication of phacoemulsification; it occurs most frequently during nuclear emulsification or cortical aspiration and significantly alters the surgical plan and IOL placement strategy.<br><br>Risk factors include a shallow anterior chamber, small pupil, hard brunescent nucleus, and posterior polar cataract; posterior polar cataract carries particularly high risk due to a pre-existing focal weakness or defect in the posterior capsule.<br><br>Suprachoroidal haemorrhage (B) is rare but catastrophic; nucleus drop (C) is a consequence of capsule rupture; corneal decompensation (D) is a postoperative complication; zonular dialysis (E) occurs but is less frequent than capsule rupture.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Posterior polar cataract is a high-risk situation during phacoemulsification because:",o:["It is associated with persistent pupillary membrane","There is a pre-existing defect or weakness in the posterior capsule","The nucleus is always brunescent and hard","Zonular fibres are invariably weak in this condition","It is always associated with posterior lenticonus"],a:1,e:"Posterior polar cataract carries inherent risk of posterior capsule rupture during surgery because the central posterior capsule is congenitally thin, deficient, or adherent to the opacity, making hydrodissection particularly dangerous in this condition.<br><br>Surgeons managing posterior polar cataract avoid aggressive hydrodissection; hydrodelineation of the epinucleus is preferred, and a slow-motion technique with careful cortical management reduces the risk of extending the pre-existing capsular defect.<br><br>Persistent pupillary membrane (A) is a separate congenital anomaly; hard nucleus (C) is not a feature of posterior polar cataract; zonular weakness (D) is not invariably present; posterior lenticonus (E) is a distinct entity.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A patient develops severe pain, corneal oedema, and markedly raised IOP two weeks after uneventful cataract surgery. Slit-lamp shows retained lens cortical material. What is the mechanism of glaucoma?",o:["Trabecular meshwork obstruction by lens particles and macrophages","Pupil block by retained cortex","Peripheral anterior synechiae formation","Steroid-induced trabecular dysfunction","Cyclodialysis"],a:0,e:"Lens particle glaucoma occurs when retained cortical fragments after cataract surgery trigger macrophage infiltration; these macrophages engulf lens material and, along with free lens particles, physically obstruct the trabecular meshwork causing open-angle elevation of IOP.<br><br>Management involves aggressive topical anti-inflammatory and IOP-lowering therapy; surgical washout of the anterior chamber to remove retained lens material is indicated when medical therapy fails to control the pressure adequately.<br><br>Pupil block (B) causes angle-closure; peripheral anterior synechiae (C) cause chronic angle closure; steroid-induced glaucoma (D) follows prolonged topical steroid use; cyclodialysis cleft closure (E) causes hypotony followed by pressure spike.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following is the best method to detect a posterior capsule defect intraoperatively during phacoemulsification?",o:["B-scan ultrasonography","Loss of red reflex and sudden deepening of the anterior chamber","Rise in intraocular pressure","Appearance of Descemet folds","Vitreous traction on the retina"],a:1,e:"Intraoperative posterior capsule rupture is recognised by sudden deepening of the anterior chamber, loss of the red reflex, and upward movement of nuclear fragments; vitreous may be seen prolapsing into the anterior chamber if the rent is large.<br><br>Immediate recognition is critical; the phaco tip should be withdrawn carefully, and an anterior vitrectomy performed if vitreous is present; the IOL placement strategy is then modified based on the extent of the capsular and zonular damage. Detecting an occult posterior capsule defect intraoperatively is a recurring surgical-safety point.<br><br>B-scan (A) is not used intraoperatively for this purpose; IOP rise (C) does not occur at capsule rupture; Descemet folds (D) indicate corneal stress; retinal vitreous traction (E) is a delayed postoperative consequence.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Cataract associated with hypoglycaemia in a neonate classically produces which morphological type?",o:["Nuclear opacity","Lamellar or zonular cataract","Posterior subcapsular cataract","Total white cataract","Anterior polar cataract"],a:1,e:"Neonatal hypoglycaemia, like hypocalcaemia, disrupts lens fibre metabolism during active lens growth; this produces a lamellar or zonular cataract, an opacity confined to a discrete shell of lens corresponding to the period of metabolic insult.<br><br>The clear zones on either side of the opacity reflect normal lens growth before and after the metabolic episode; the density and visual significance of lamellar cataract varies, and many cases are managed with optical correction and amblyopia therapy.<br><br>Nuclear opacity (A) is hereditary or rubella-related; posterior subcapsular (C) is steroid or radiation-induced; total white cataract (D) indicates complete opacification; anterior polar (E) is congenital and non-progressive.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with cataract is found to have pseudoexfoliation material on the anterior lens capsule. What is the most important surgical implication?",o:["Higher risk of posterior capsule rupture","Higher risk of corneal decompensation","Higher risk of zonular weakness and capsule rupture","Higher risk of postoperative uveitis","Higher risk of cystoid macular"],a:2,e:"Pseudoexfoliation syndrome is associated with progressive zonular weakness due to abnormal fibrillar material depositing around and within zonular fibres; this significantly increases the risk of zonular dialysis and capsular bag instability during phacoemulsification.<br><br>Surgeons managing pseudoexfoliation cataract use capsular tension rings to stabilise the capsular bag, avoid excessive rotational manoeuvres, and maintain a low-flow technique; the risk of nucleus drop is substantially higher than in routine cataract surgery. Pseudoexfoliation material with zonular weakness raising surgical risk is a heavily emphasised pitfall.<br><br>Posterior capsule rupture (A) is secondary to zonular failure, not a primary isolated risk; corneal decompensation (B) relates to endothelial cell loss; postoperative uveitis (D) is not the primary concern; CMO (E) is not specifically elevated.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following systemic drugs is most commonly implicated in causing anterior subcapsular cataract?",o:["Amiodarone","Tamoxifen","Busulfan","Allopurinol","Hydroxychloroquine"],a:2,e:"Busulfan, an alkylating chemotherapy agent used in leukaemia treatment, is the most well-established cause of anterior subcapsular cataract among systemic drugs; long-term use leads to progressive anterior subcapsular opacity through direct lens epithelial toxicity.<br><br>Other chemotherapy agents including cyclophosphamide have also been implicated; regular slit-lamp surveillance is recommended in patients on prolonged busulfan therapy to detect early lens changes before they become visually significant.<br><br>Amiodarone (A) causes anterior subcapsular golden-brown deposits and corneal verticillata; tamoxifen (B) causes retinal crystalline deposits; allopurinol (D) has weak cataract association; hydroxychloroquine (E) primarily causes maculopathy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Soemmering ring cataract is characterised by:",o:["Residual lens epithelial proliferation forming a doughnut-shaped mass at the capsular equator","A ring-shaped nuclear opacity at the lens equator","Circular deposits of calcium on the posterior capsule","Ring-shaped opacity from blunt trauma","Circular fibrin ring following"],a:0,e:"Soemmering ring is a form of after-cataract seen after extracapsular surgery or traumatic lens absorption; residual equatorial lens epithelial cells proliferate between the anterior and posterior capsule, forming a doughnut or ring-shaped white mass at the periphery.<br><br>The central visual axis remains clear in Soemmering ring, distinguishing it from Elschnig pearls which affect the central posterior capsule; Soemmering ring is more commonly seen after congenital cataract surgery in infants due to their highly regenerative lens epithelium.<br><br>Nuclear opacity at equator (B) is not a recognised entity; calcium deposits (C) cause capsular calcification; trauma ring opacity (D) is rosette cataract; fibrin ring (E) is an early postoperative inflammatory finding.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following is the most common cause of paediatric cataract requiring surgery in Pakistan and similar developing countries?",o:["Trauma","Idiopathic and hereditary","Rubella","Galactosaemia","Steroid-induced"],a:0,e:"In developing countries including Pakistan, trauma is the most common cause of unilateral paediatric cataract requiring surgical intervention; penetrating injuries from sharp objects, sticks, and metallic foreign bodies account for the majority of traumatic cataracts in children.<br><br>Traumatic cataract in children carries a guarded visual prognosis due to associated injuries, risk of amblyopia, and delayed presentation; early surgery combined with aggressive amblyopia treatment and optical rehabilitation is essential for optimising visual outcomes.<br><br>Rubella (C) is now less common due to vaccination; idiopathic and hereditary (B) is the most common cause of bilateral cataract globally; galactosaemia (D) is metabolic and rare; steroid-induced (E) is uncommon in the paediatric age group.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A patient with mature cataract presents with severe eye pain, corneal oedema, and angle closure. Which mechanism is responsible?",o:["Phacomorphic glaucoma","Phacoanaphylactic uveitis","Phacolytic glaucoma","Lens particle glaucoma","Neovascular glaucoma"],a:0,e:"Phacomorphic glaucoma occurs when a swollen intumescent or mature lens pushes the iris-lens diaphragm anteriorly, causing angle closure; the shallow anterior chamber, corneal oedema, and acute pain reflect the rapid rise in intraocular pressure from trabecular obstruction.<br><br>Emergency management includes topical IOP-lowering agents, systemic acetazolamide, and osmotic agents; definitive treatment is lens extraction, which relieves the mechanical pupil block and restores the anterior chamber depth and angle anatomy.<br><br>Phacolytic glaucoma (C) is open-angle from hypermature cataract; phacoanaphylactic uveitis (B) is granulomatous inflammation from lens protein; lens particle glaucoma (D) follows surgery; neovascular glaucoma (E) follows retinal ischaemia.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following is a recognised ocular feature of Down syndrome related to the lens?",o:["Ectopia lentis","Anterior lenticonus","Sutural cataract","Brushfield spots with early cortical cataract","Oil droplet cataract"],a:3,e:"Down syndrome is associated with Brushfield spots, which are white or grey spots on the peripheral iris, along with early-onset cortical and sutural cataracts; the lens changes tend to occur at a younger age than in the general population.<br><br>Keratoconus is also a well-recognised association; the combination of Brushfield spots and early lens opacities on slit-lamp examination in a patient with trisomy 21 features is a classic exam presentation in ophthalmology MCQs. The recognised lens features of Down syndrome are a recurring association question.<br><br>Ectopia lentis (A) is seen in Marfan and homocystinuria; anterior lenticonus (B) is pathognomonic of Alport syndrome; oil droplet cataract (E) is pathognomonic of galactosaemia; pure sutural cataract (C) is not the defining association.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Radiation cataract following ionising radiation exposure characteristically affects which zone of the lens first?",o:["Anterior subcapsular zone","Nuclear zone","Posterior subcapsular zone","Equatorial cortex","Anterior cortex"],a:2,e:"Ionising radiation preferentially damages the germinative lens epithelial cells in the equatorial region; the abnormal cells migrate posteriorly and accumulate beneath the posterior capsule, producing a posterior subcapsular opacity as the earliest and most characteristic finding.<br><br>The latency period between radiation exposure and cataract formation ranges from months to years depending on the dose; higher doses produce denser opacities with shorter latency, and the posterior subcapsular location causes disproportionate visual impairment relative to opacity size.<br><br>Anterior subcapsular zone (A) is affected by trauma and atopic disease; nuclear zone (B) is affected by age-related sclerosis; equatorial cortex (D) and anterior cortex (E) are not the primary zones affected by ionising radiation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient develops severe pain, photophobia, and hypopyon five days after uneventful phacoemulsification. Which organism is most commonly responsible for acute postoperative endophthalmitis following cataract surgery?",o:["Staphylococcus aureus","Streptococcus pneumoniae","Pseudomonas aeruginosa","Coagulase-negative staphylococci","Propionibacterium acnes"],a:3,e:"Acute postoperative endophthalmitis following cataract surgery is most commonly caused by coagulase-negative staphylococci, particularly Staphylococcus epidermidis, derived from the patient's own conjunctival and lid flora introduced at the time of surgery.<br><br>Gram-positive organisms account for approximately 90% of post-cataract endophthalmitis cases; the organisms gain entry most commonly through the wound, especially with clear corneal incisions, which carry higher contamination risk than scleral tunnel incisions.<br><br>Staphylococcus aureus (A) causes more virulent acute infection; Streptococcus pneumoniae (B) is less common; Pseudomonas (C) causes aggressive gram-negative endophthalmitis; Propionibacterium acnes (E) causes delayed chronic low-grade endophthalmitis appearing months after surgery.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient presents with chronic low-grade uveitis, white intracapsular plaque, and progressive visual deterioration two years after cataract surgery. Which organism is most likely responsible?",o:["Coagulase-negative staphylococci","Candida albicans","Propionibacterium acnes","Streptococcus viridans","Haemophilus"],a:2,e:"Propionibacterium acnes is a slow-growing gram-positive anaerobic rod that causes delayed chronic postoperative endophthalmitis; it sequestrates within the capsular bag behind the IOL, producing the characteristic white intracapsular plaque visible on slit-lamp examination.<br><br>The condition presents insidiously months to years after surgery with recurrent low-grade uveitis resistant to steroids; diagnosis requires capsular biopsy and anaerobic cultures; treatment involves partial or complete capsulectomy with IOL exchange and intravitreal vancomycin.<br><br>Coagulase-negative staphylococci (A) cause acute postoperative infection; Candida (B) causes fungal endophthalmitis in immunocompromised patients; Streptococcus viridans (D) and Haemophilus (E) cause acute bacterial endophthalmitis, not delayed chronic presentations.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"The Endophthalmitis Vitrectomy Study established which key principle regarding management of postoperative endophthalmitis?",o:["Immediate vitrectomy is superior in all cases regardless of visual acuity","Systemic intravenous antibiotics improve visual outcomes in all patients","Intravitreal vancomycin alone is sufficient treatment","Pars plana vitrectomy is superior to vitreous tap in patients presenting with light perception only vision","Topical antibiotics are the"],a:3,e:"The Endophthalmitis Vitrectomy Study demonstrated that immediate pars plana vitrectomy produced significantly better visual outcomes compared to vitreous tap and inject in patients presenting with light perception only vision following cataract surgery.<br><br>In patients with hand movements or better vision, vitrectomy and tap-and-inject produced equivalent outcomes; importantly, the study found no benefit from systemic intravenous antibiotics in any group, removing them from standard management protocol.<br><br>Immediate vitrectomy for all cases (A) is not supported; systemic antibiotics benefit (B) was disproved by the EVS; intravitreal vancomycin alone (C) is insufficient; topical antibiotics (E) have no role in established endophthalmitis management.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"In Lowe oculocerebrorenal syndrome, which of the following best describes the lens finding?",o:["Bilateral dense nuclear cataract present at birth","Bilateral posterior lenticonus","Oil droplet cataract","Bilateral ectopia lentis","Sunflower cataract"],a:0,e:"Lowe syndrome is an X-linked recessive disorder caused by mutations in the OCRL1 gene affecting phosphatidylinositol metabolism; bilateral dense nuclear cataracts present at birth are the hallmark ocular finding, often accompanied by glaucoma and hypotonia.<br><br>The syndrome also involves renal tubular acidosis, intellectual disability, and hypotonia constituting the oculocerebrorenal triad; lens extraction must be performed early to prevent amblyopia, though surgical outcomes are complicated by associated glaucoma and small globe size.<br><br>Posterior lenticonus (B) is associated with Alport syndrome; oil droplet cataract (C) is galactosaemia; ectopia lentis (D) is Marfan or homocystinuria; sunflower cataract (E) is pathognomonic of Wilson's disease.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following is the most appropriate first-line prophylactic measure to reduce postoperative endophthalmitis following cataract surgery?",o:["Subconjunctival cefuroxime injection at end of surgery","Topical fourth-generation fluoroquinolone drops preoperatively","Intracameral cefuroxime injection at end of surgery","Systemic oral ciprofloxacin perioperatively","Povidone-iodine irrigation of the conjunctival sac"],a:2,e:"Intracameral cefuroxime injected into the anterior chamber at the end of cataract surgery is the most evidence-based prophylactic measure; the ESCRS multicentre study demonstrated a fivefold reduction in postoperative endophthalmitis rates with this intervention.<br><br>The drug achieves high local concentrations directly at the site of potential contamination; it targets gram-positive organisms, which account for the majority of post-cataract endophthalmitis; it has now become standard of care in most major ophthalmology centres globally.<br><br>Subconjunctival cefuroxime (A) is less effective than intracameral; topical fluoroquinolones (B) reduce surface flora but are not sufficient alone; systemic antibiotics (D) are not indicated prophylactically; povidone-iodine (E) is essential but is preoperative preparation, not the primary prophylactic intervention.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with homocystinuria develops lens dislocation. In which direction does the lens typically displace in homocystinuria?",o:["Superiorly and temporally","Inferiorly and nasally","Superiorly and nasally","Inferiorly and temporally","Centrally with iridodonesis only"],a:1,e:"In homocystinuria, deficiency of cystathionine beta-synthase leads to accumulation of homocysteine, which damages zonular fibres through oxidative mechanisms causing complete zonular rupture; the lens dislocates inferiorly and nasally due to the pattern of zonular failure.<br><br>Unlike Marfan syndrome where zonules are stretched but intact, homocystinuria causes complete zonular rupture allowing the lens to dislocate freely into the anterior chamber or vitreous, making these patients high surgical risk due to thromboembolic complications under anaesthesia.<br><br>Superior temporal dislocation (A) is characteristic of Marfan syndrome; superior nasal (C) and inferior temporal (D) are not classic patterns; iridodonesis alone (E) indicates early zonular weakness without frank dislocation.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Capsular tension ring is most specifically indicated in cataract surgery when:",o:["The nucleus is brunescent and hard","Posterior capsule rupture has occurred","The patient has a shallow anterior chamber","Zonular weakness or dialysis is present","The corneal endothelial count is low"],a:3,e:"Capsular tension ring is a PMMA ring inserted into the capsular bag to distribute tension evenly around the equator when zonular weakness or partial dialysis is present; it prevents capsular bag collapse, maintains its circular contour, and enables safe phacoemulsification and in-the-bag IOL placement.<br><br>It is indicated in pseudoexfoliation syndrome, Marfan syndrome, trauma with zonular dehiscence, and post-vitrectomy eyes with compromised zonules; for more severe zonulopathy, a modified Cionni ring with scleral fixation sutures provides additional support.<br><br>Hard nucleus (A) requires modified phaco technique, not a CTR; posterior capsule rupture (B) is managed with anterior vitrectomy and sulcus IOL; shallow anterior chamber (C) requires viscoelastic management; low endothelial count (E) mandates careful phaco energy minimisation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following correctly describes the SRK/T formula for IOL power calculation?",o:["A theoretical formula best suited for long myopic eyes","A regression formula best suited for short eyes","An empirical formula requiring no keratometry","A formula designed exclusively for toric IOL calculation","A formula requiring vitreous cavity volume measurement"],a:0,e:"SRK/T is a third-generation theoretical formula combining the regression-based SRK approach with a theoretical optical model; it performs best in long eyes with axial length greater than 26 mm and is the preferred formula for high myopes undergoing cataract surgery.<br><br>The formula incorporates axial length, keratometry, and a surgeon-specific A-constant; it tends to produce myopic errors in short eyes; for very long eyes beyond 28 mm, modern AI-based formulas such as Kane or Barrett may be superior to SRK/T.<br><br>SRK II (B) is a regression formula for short eyes; keratometry is required for all standard formulas, excluding option C; toric IOL calculation uses separate online calculators, not SRK/T; vitreous volume measurement (E) is not a parameter in any standard IOL formula.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A patient presents with TASS (Toxic Anterior Segment Syndrome) following phacoemulsification. Which feature best distinguishes TASS from infectious endophthalmitis?",o:["Presence of hypopyon","Severe pain and periorbital oedema","Positive vitreous cultures","Onset within 12 to 48 hours with limbus-to-limbus corneal oedema and minimal pain","Failure to respond to topical"],a:3,e:"TASS is a sterile acute anterior segment inflammation caused by non-infectious toxic substances entering the anterior chamber during surgery; it characteristically presents within 12 to 48 hours with diffuse limbus-to-limbus corneal oedema, fibrinous anterior chamber reaction, and minimal pain compared to infectious endophthalmitis.<br><br>The absence of vitreous involvement, negative cultures, rapid onset, and striking response to intensive topical corticosteroids help distinguish TASS from bacterial endophthalmitis; causes include impurities on surgical instruments, irrigating solutions, or OVD remnants.<br><br>Hypopyon (A) occurs in both conditions; severe pain (B) is more characteristic of infectious endophthalmitis; positive vitreous cultures (C) confirm infection; failure to respond to steroids (E) suggests infection rather than TASS.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following congenital cataracts is most likely to be bilateral, visually insignificant, and require no surgical intervention?",o:["Dense nuclear cataract","Anterior polar cataract","Total cataract","Posterior subcapsular cataract","Lamellar cataract involving the"],a:1,e:"Anterior polar cataract is a small, stationary opacity at the anterior pole of the lens; it is bilateral in the majority of cases, does not progress, and rarely affects vision significantly enough to require surgical intervention in most patients.<br><br>Regular monitoring is recommended as a minority of cases are associated with anisometropia and mild amblyopia; optical correction and amblyopia treatment suffice in such cases; surgery is reserved for the rare instance where the opacity is large enough to impair visual development significantly.<br><br>Dense nuclear cataract (A) requires urgent surgery; total cataract (C) is visually devastating; posterior subcapsular cataract (D) causes significant glare and near vision difficulty; lamellar cataract involving the visual axis (E) often requires surgery depending on density and amblyogenic risk.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which viscoelastic substance is most appropriate to protect the corneal endothelium during phacoemulsification of a hard brunescent nucleus in a patient with low endothelial cell count?",o:["Hydroxypropyl methylcellulose","Sodium hyaluronate (dispersive OVD)","Sodium hyaluronate (cohesive OVD)","Balanced salt solution","Air"],a:1,e:"Dispersive ophthalmic viscoelastic devices coat and adhere to the corneal endothelium, providing sustained protection during phacoemulsification; they are preferred over cohesive OVDs in patients with low endothelial counts or hard nuclei where prolonged phaco energy is required.<br><br>The soft shell technique combines a dispersive OVD on the endothelium with a cohesive OVD in the centre; this optimises both endothelial protection and working space simultaneously; dispersive OVDs are more difficult to remove but safer for the endothelium in high-risk cases.<br><br>HPMC (A) provides less endothelial protection than sodium hyaluronate; cohesive OVD (C) maintains space well but does not coat the endothelium as effectively; BSS (D) and air (E) provide no endothelial protection during phacoemulsification.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Anterior lenticonus is pathognomonic of which systemic condition?",o:["Marfan syndrome","Wilson's disease","Alport syndrome","Homocystinuria","Fabry disease"],a:2,e:"Anterior lenticonus, a forward conical protrusion of the central anterior lens surface, is pathognomonic of Alport syndrome; it results from localised thinning of the anterior lens capsule due to defective type IV collagen, which is the primary structural protein of all basement membranes in this condition.<br><br>Anterior lenticonus produces progressive myopia and irregular astigmatism in affected patients; it is best detected by retroillumination, which reveals the classic oil droplet reflex; phacoemulsification is technically challenging due to the thin abnormal anterior capsule at risk of rhexis runout. Anterior lenticonus pointing to Alport syndrome is a classic pathognomonic association.<br><br>Marfan syndrome (A) causes ectopia lentis; Wilson's disease (B) causes sunflower cataract; homocystinuria (D) causes inferior lens dislocation; Fabry disease (E) causes corneal verticillata and posterior spoke-like cataracts, not lenticonus.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A patient with Marfan syndrome undergoes cataract surgery. Which intraoperative adjunct is most important to prevent capsular bag collapse and IOL decentration in this patient?",o:["Iris hooks","Pupil expander ring","Capsular tension ring","Anterior vitrectomy cutter","Intracameral phenylephrine"],a:2,e:"In Marfan syndrome, zonular fibres are elongated and fragile due to fibrillin-1 gene mutations; a capsular tension ring distributes stress evenly around the capsular bag equator, preventing collapse during cortical aspiration and maintaining centration of the IOL postoperatively.<br><br>For more severe zonulopathy in Marfan patients, a Cionni modified capsular tension ring with scleral fixation sutures provides superior long-term stability; these patients require lifelong monitoring for late IOL-capsular bag complex dislocation even after successful surgery. Capsular tension ring use for zonular weakness in Marfan is an emphasised intraoperative manoeuvre.<br><br>Iris hooks (A) and pupil expander rings (B) manage small pupils; anterior vitrectomy cutter (D) manages vitreous prolapse after capsule rupture; intracameral phenylephrine (E) dilates the pupil intraoperatively but does not address zonular instability.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Nuclear hardness grading using the Lens Opacities Classification System is important preoperatively because it directly determines:",o:["The type of IOL material to be implanted","The phacoemulsification energy required and surgical risk","The need for general versus local anaesthesia","The postoperative refraction target","The type of"],a:1,e:"Preoperative grading of nuclear hardness using LOCS III or the Emery-Little classification guides the surgeon in anticipating the cumulative dissipated energy required for emulsification; harder Grade IV and V nuclei demand more ultrasound energy, increasing the risk of corneal endothelial damage and posterior capsule rupture.<br><br>Surgeons may modify their technique for hard nuclei, choosing phaco-chop over divide-and-conquer, reducing irrigation turbulence, using dispersive viscoelastics, and counselling patients about higher surgical risk including the possibility of conversion to manual ECCE. LOCS nuclear grading guiding phaco energy is a frequently tested practical correlate.<br><br>IOL material selection (A) is independent of nuclear hardness; anaesthesia choice (C) depends on patient cooperation and systemic factors; refraction target (D) is determined by biometry; capsulorhexis technique (E) is not primarily dictated by nuclear grade.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following best describes the concept of refractive lens exchange performed in a high myope for refractive purposes?",o:["Clear lens extraction with IOL implantation to correct high myopia","Removal of the cornea and replacement with donor tissue","Laser ablation of the lens nucleus","Implantation of a phakic IOL anterior to the crystalline lens","Corneal collagen crosslinking combined with IOL"],a:0,e:"Refractive lens exchange involves removal of the optically clear crystalline lens and implantation of an appropriately powered IOL to correct high myopia beyond the safe range of laser refractive surgery; it permanently eliminates the risk of future cataract formation in the same eye.<br><br>The procedure carries the same risks as cataract surgery including retinal detachment, which is significantly higher in high myopes due to peripheral retinal degeneration; careful preoperative peripheral retinal examination and treatment of lattice degeneration are essential before proceeding.<br><br>Corneal replacement (B) describes keratoplasty; laser lens ablation (C) is not a clinical procedure; phakic IOL implantation (D) is an alternative that preserves the crystalline lens and accommodation in younger patients; corneal crosslinking (E) treats keratoconus.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 16-year-old tall boy with arm span exceeding height, high arched palate, and pectus excavatum presents with blurred vision. Slit-lamp shows superotemporal lens displacement with intact visible zonules. What is the most likely diagnosis?",o:["Homocystinuria","Weill-Marchesani syndrome","Marfan syndrome","Sulphite oxidase deficiency","Hyperlysinaemia"],a:2,e:"Marfan syndrome is an autosomal dominant fibrillin-1 gene mutation on chromosome 15; ectopia lentis occurs in 50 to 80% of cases, characteristically displaced superiorly and temporally with zonules remaining intact and visible on slit-lamp examination.<br><br>The skeletal features of arachnodactyly, tall stature with arm span exceeding height, pectus excavatum, and high arched palate form the classic systemic picture; cardiovascular complications including aortic root dilatation represent the life-threatening aspect requiring multidisciplinary management.<br><br>Homocystinuria (A) causes inferior nasal dislocation with ruptured zonules; Weill-Marchesani (B) causes microspherophakia with inferior dislocation; sulphite oxidase deficiency (D) and hyperlysinaemia (E) are rare metabolic causes of ectopia lentis without the Marfan skeletal phenotype.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"In which direction does the lens dislocate in Weill-Marchesani syndrome?",o:["Superiorly and temporally","Superiorly and nasally","Nasally without vertical component","Inferiorly","Anteriorly into the anterior"],a:3,e:"Weill-Marchesani syndrome is an autosomal recessive connective tissue disorder characterised by microspherophakia, short stature, brachydactyly, and joint stiffness; the small spherical lens dislocates inferiorly due to generalised zonular weakness and its abnormal spherical configuration.<br><br>The microspherophakic lens is particularly prone to pupil block glaucoma; when the small spherical lens moves anteriorly through the pupil, it causes acute angle closure refractory to conventional treatment and requiring lens extraction as the definitive intervention.<br><br>Superotemporal dislocation (A) is Marfan syndrome; superonasal (B) is not a classic pattern for any named condition; nasal displacement alone (C) is not described; anterior chamber dislocation (E) is a complication of inferior dislocation, not the primary direction.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 14-year-old presents with downward lens dislocation, intellectual disability, thromboembolism, and a positive urine nitroprusside test. What is the enzyme deficiency responsible?",o:["Aldose reductase","Galactokinase","Cystathionine beta-synthase","Sulphite oxidase","Lysyl oxidase"],a:2,e:"Homocystinuria results from deficiency of cystathionine beta-synthase, causing accumulation of homocysteine; the urine nitroprusside test is positive, confirming excess homocysteine in urine; the lens dislocates inferonasally due to complete oxidative disruption of zonular fibres.<br><br>The condition is autosomal recessive; systemic features include intellectual disability, Marfanoid habitus, osteoporosis, and life-threatening thromboembolic events affecting both arterial and venous systems; pyridoxine-responsive cases are managed with high-dose vitamin B6 supplementation. Downward lens dislocation with developmental delay pointing to homocystinuria is a classic discriminator from Marfan.<br><br>Aldose reductase deficiency (A) relates to diabetic cataract via the polyol pathway; galactokinase (B) causes oil droplet cataract; sulphite oxidase deficiency (D) causes ectopia lentis but without thromboembolism; lysyl oxidase (E) is relevant in Menkes disease, not homocystinuria.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following best differentiates ectopia lentis in Marfan syndrome from that in homocystinuria on slit-lamp examination?",o:["Degree of visual impairment","Presence or absence of cataract","Zonules visible and intact versus broken and absent","Presence of iridodonesis","Degree of lens tilt"],a:2,e:"In Marfan syndrome, the zonular fibres are elongated and weakened but remain structurally intact and visible on slit-lamp retroillumination as fine fibrils around the lens equator; in homocystinuria, oxidative zonular damage causes complete rupture making zonules invisible or absent.<br><br>This distinction has critical surgical implications; intact zonules in Marfan syndrome allow capsular bag surgery with a capsular tension ring, whereas absent zonules in homocystinuria often necessitate lensectomy via pars plana approach with scleral-fixated IOL implantation.<br><br>Visual impairment (A) depends on degree of dislocation in both conditions; cataract (B) may occur in both; iridodonesis (D) occurs in both with zonular weakness; lens tilt (E) is not a reliable differentiating feature between the two conditions.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Ectopia lentis et pupillae is characterised by which classic finding?",o:["Lens and pupil displaced in the same direction","Lens displaced superiorly with pupil displaced inferiorly","Lens dislocation with absence of iris","Lens and pupil displaced in opposite directions","Bilateral cataract with corectopia"],a:3,e:"Ectopia lentis et pupillae is a rare autosomal recessive condition in which the lens and pupil are displaced in opposite directions; typically the lens dislocates temporally while the pupil is displaced nasally, a pattern that is pathognomonic of this specific entity.<br><br>Additional features include poor pupil dilation due to iris stromal hypoplasia, persistent pupillary membrane, and often an associated cataract; the condition is bilateral but asymmetric; the visual prognosis depends on degree of dislocation and associated refractive error and amblyopia.<br><br>Same direction displacement (A) occurs in simple ectopia lentis; superior lens with inferior pupil (B) is not a recognised named pattern; lens dislocation with iris absence (C) describes aniridia with ectopia lentis; bilateral cataract with corectopia alone (E) does not define this condition.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A patient with ectopia lentis develops acute angle closure glaucoma. Which mechanism is most likely responsible?",o:["Trabecular meshwork blockage by lens proteins","Neovascularisation of the angle","Peripheral anterior synechiae from chronic uveitis","Anterior dislocation of the lens causing pupil block","Steroid-induced"],a:3,e:"Anterior dislocation of the subluxated lens into the anterior chamber or against the posterior iris surface creates pupil block, preventing aqueous flow from posterior to anterior chamber; this raises posterior chamber pressure, bowing the peripheral iris forward and closing the drainage angle acutely.<br><br>Emergency management requires urgent IOP lowering with topical and systemic agents, cycloplegia to retract the lens posteriorly, and supine positioning; definitive treatment is lens extraction; miotic drops are contraindicated as they tighten the pupil around the dislocated lens, worsening the block.<br><br>Trabecular blockage by lens proteins (A) is phacolytic glaucoma from hypermature cataract; neovascularisation (B) causes neovascular glaucoma from ischaemia; peripheral anterior synechiae (C) cause chronic angle closure; steroid-induced glaucoma (E) is open-angle mechanism.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which chromosomal locus is affected in Marfan syndrome causing ectopia lentis?",o:["Chromosome 21q","Chromosome 15q, fibrillin-1 gene","Chromosome 10q, fibrillin-2 gene","Chromosome 18p, collagen IV gene","Chromosome 7q,"],a:1,e:"Marfan syndrome is caused by mutations in the FBN1 gene encoding fibrillin-1, located on chromosome 15q21; fibrillin-1 is a major structural component of the extracellular microfibrils that form the scaffolding of zonular fibres, explaining why zonular integrity is compromised in this condition.<br><br>The mutation is autosomal dominant with high penetrance but variable expressivity; fibrillin-1 also regulates TGF-beta signalling, contributing to the cardiovascular and pulmonary manifestations beyond the mechanical effects of deficient microfibril structure in connective tissues.<br><br>Chromosome 21 (A) is trisomy 21 Down syndrome; fibrillin-2 on chromosome 10 (C) causes congenital contractural arachnodactyly; collagen IV on chromosome 18 (D) is not the Marfan locus; elastin gene on chromosome 7 (E) is associated with supravalvular aortic stenosis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Microspherophakia is most classically associated with which of the following conditions?",o:["Marfan syndrome","Homocystinuria","Weill-Marchesani syndrome","Alport syndrome","Ehlers-Danlos syndrome"],a:2,e:"Microspherophakia, an abnormally small and spherical lens with increased curvature and refractive power, is the hallmark lens finding of Weill-Marchesani syndrome; the spherical configuration results from defective zonular guidance of lens growth during development.<br><br>The high lenticular myopia caused by increased lens curvature is often the presenting complaint in childhood; the risk of acute pupil block glaucoma is significant when the spherical lens migrates anteriorly; cycloplegia is used acutely to posteriorly reposition the lens, opposite to angle closure management in phakic eyes.<br><br>Marfan syndrome (A) causes a normal-sized lens with superotemporal dislocation; homocystinuria (B) causes inferonasal dislocation with normal lens size; Alport syndrome (D) causes anterior lenticonus; Ehlers-Danlos syndrome (E) may cause ectopia lentis but not microspherophakia specifically.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"In the management of subluxated lens in homocystinuria, which perioperative precaution is most critical?",o:["Avoiding general anaesthesia due to malignant hyperthermia risk","Avoiding mydriatics due to angle closure risk","Preoperative pilocarpine to constrict the pupil","Anticoagulation and hydration to prevent thromboembolic complications","Preoperative oral acetazolamide to lower"],a:3,e:"Homocystinuria carries a high risk of arterial and venous thromboembolism, which is significantly exacerbated by dehydration, hypotension, and the hypercoagulable state induced by general anaesthesia; perioperative hydration, anticoagulation, and minimising anaesthetic time are mandatory precautions.<br><br>The thromboembolic risk in homocystinuria is due to homocysteine-mediated endothelial damage, platelet aggregation, and impaired fibrinolysis; stroke, pulmonary embolism, and myocardial infarction can occur intraoperatively, making anaesthetic and haematological liaison essential before any ocular surgery.<br><br>Malignant hyperthermia risk (A) is associated with succinylcholine and volatile anaesthetic agents, not specifically with homocystinuria; pilocarpine (C) worsens pupil block when the lens is anteriorly displaced; avoiding mydriatics (B) is relevant in microspherophakia; acetazolamide (E) is not the primary perioperative concern.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following is the most appropriate surgical approach for lens removal in a patient with complete zonular rupture and posteriorly dislocated lens in homocystinuria?",o:["Standard phacoemulsification through a corneal incision","Extracapsular cataract extraction with capsular tension ring","Pars plana lensectomy with vitrectomy","Intracapsular cataract extraction","Manual small incision cataract surgery"],a:2,e:"When the lens has completely dislocated posteriorly into the vitreous cavity due to total zonular rupture, pars plana lensectomy combined with vitrectomy is the safest approach; it avoids the risks of anterior segment manipulation and allows controlled removal of the dislocated lens under direct vitreoretinal visualisation.<br><br>IOL placement in such cases typically involves scleral fixation of a posterior chamber IOL or implantation of an anterior chamber IOL depending on the surgeon's expertise and available lens design; the vitreoretinal surgeon manages any associated retinal complications simultaneously.<br><br>Standard phacoemulsification (A) is impossible without zonular support in the anterior segment; ECCE with CTR (B) requires at least partial zonular integrity; intracapsular extraction (D) is obsolete and causes vitreous loss; MSICS (E) requires anterior segment zonular support not present here.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Simple ectopia lentis without systemic associations is inherited in which pattern?",o:["Autosomal recessive only","X-linked recessive","Mitochondrial inheritance","Autosomal dominant or autosomal recessive","Sporadic only"],a:3,e:"Simple ectopia lentis is an isolated bilateral condition without systemic features; it can be inherited as either autosomal dominant or autosomal recessive; the autosomal dominant form is often caused by FBN1 mutations identical to those in Marfan syndrome but without the full systemic phenotype.<br><br>The lens displacement in simple ectopia lentis is typically bilateral and symmetric, most often in the superotemporal direction; management includes optical correction of induced irregular astigmatism and myopia, with surgical intervention reserved for cases where vision cannot be rehabilitated optically.<br><br>Autosomal recessive only (A) is incorrect as dominant forms exist; X-linked recessive (B) is not a recognised inheritance pattern for simple ectopia lentis; mitochondrial inheritance (C) is not relevant here; sporadic-only (E) is incorrect as familial forms are well established.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A patient with ectopia lentis has the lens partially displaced so that the equator of the lens bisects the pupil. Which optical phenomenon does the patient experience?",o:["Monocular diplopia","Metamorphopsia","Photopsia","Oscillopsia","Micropsia"],a:0,e:"When the lens equator bisects the pupil, light entering the eye passes simultaneously through both the phakic and aphakic portions of the pupillary aperture; this creates two separate images on the retina, producing monocular diplopia that persists even when the fellow eye is covered.<br><br>This is a classic and frequently tested clinical consequence of subluxation; patients may also experience significant irregular astigmatism, high myopia from the displaced lens, and fluctuating vision with changes in pupil size affecting the proportion of phakic versus aphakic aperture.<br><br>Metamorphopsia (B) implies macular distortion; photopsia (C) suggests retinal or vitreal traction; oscillopsia (D) indicates nystagmus or vestibular pathology; micropsia (E) occurs in macular oedema or posterior segment disease, not ectopia lentis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Iridodonesis on slit-lamp examination indicates:",o:["Inflammation of the iris stroma","Loss of iris pigment epithelium","Zonular weakness causing the iris-lens diaphragm to tremble with eye movement","Posterior synechiae pulling the iris","Rubeosis iridis from"],a:2,e:"Iridodonesis is the tremulousness of the iris observed on slit-lamp examination with rapid eye movements; it occurs when the normal support provided by the zonules and lens to the posterior iris surface is lost, allowing the iris to oscillate freely with ocular movement.<br><br>It is a sensitive clinical sign of zonular weakness or lens subluxation; phacodonesis, the tremulousness of the lens itself, accompanies iridodonesis in more significant zonular compromise; both signs should prompt careful assessment for an underlying systemic cause of ectopia lentis.<br><br>Iris stromal inflammation (A) causes ciliary injection and keratic precipitates; loss of pigment epithelium (B) causes transillumination defects; posterior synechiae (D) cause irregular pupil shape; rubeosis iridis (E) causes neovascularisation visible at the pupil margin and angle.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following metabolic conditions causes ectopia lentis through deficiency of sulphite oxidase, resulting in accumulation of sulphite and S-sulphocysteine?",o:["Homocystinuria","Hyperlysinaemia","Sulphite oxidase deficiency","Molybdenum cofactor deficiency","Both C and D"],a:4,e:"Sulphite oxidase deficiency and molybdenum cofactor deficiency both cause accumulation of toxic sulphite and S-sulphocysteine; molybdenum is the essential cofactor for sulphite oxidase, so deficiency of either the enzyme or its cofactor produces identical biochemical and clinical consequences including ectopia lentis and severe neurological impairment.<br><br>Both conditions are autosomal recessive and extremely rare; the lens dislocation is typically inferior and the neurological features including intractable seizures, intellectual disability, and hypotonia dominate the clinical picture, often leading to early death in severe cases.<br><br>Homocystinuria (A) involves cystathionine beta-synthase deficiency producing elevated homocysteine; hyperlysinaemia (B) is another rare metabolic cause but through a different pathway; options C and D alone are individually correct but the question specifically identifies that both share the same mechanism.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with ectopia lentis is being assessed for optical management without surgery. Which approach is most appropriate when the lens is subluxated but the visual axis remains optically useful?",o:["Full cycloplegic refraction and correction of induced myopia and astigmatism","Immediate surgical referral regardless of visual acuity","Patching of the affected eye only","Pinhole correction for distance vision","Bilateral occlusion therapy"],a:0,e:"When a subluxated lens still occupies a useful position in the visual axis, optical rehabilitation with spectacle correction of the induced myopia and irregular astigmatism is the first-line approach; cycloplegic refraction is essential to accurately measure the refractive error caused by lens tilt and displacement.<br><br>If amblyopia coexists in a child, appropriate occlusion therapy of the fellow eye is added; surgery is deferred as long as useful vision can be rehabilitated optically, reserving lens extraction for cases of progressive dislocation, uncontrolled glaucoma, or optically uncorrectable vision loss.<br><br>Immediate surgical referral (B) is not indicated when optical correction is feasible; patching alone (C) without optical correction is insufficient; pinhole (D) is a diagnostic tool, not a management strategy; bilateral occlusion (E) has no role in unilateral ectopia lentis management.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Pyridoxine supplementation is a specific treatment in which cause of ectopia lentis?",o:["Marfan syndrome","Weill-Marchesani syndrome","Sulphite oxidase deficiency","Homocystinuria","Simple ectopia lentis"],a:3,e:"Approximately 50% of homocystinuria cases are pyridoxine-responsive; high-dose vitamin B6 acts as a cofactor for cystathionine beta-synthase, partially restoring enzymatic activity and reducing homocysteine levels, thereby decreasing the risk of lens dislocation progression and thromboembolic complications.<br><br>Pyridoxine-non-responsive cases are managed with dietary methionine restriction, betaine supplementation to remethylate homocysteine, and folate; early diagnosis through newborn screening and prompt treatment can prevent or significantly delay the development of ectopia lentis and neurological complications.<br><br>Marfan syndrome (A) has no specific metabolic treatment; Weill-Marchesani (B) has no pyridoxine response; sulphite oxidase deficiency (C) does not respond to pyridoxine; simple ectopia lentis (E) is structural and has no metabolic treatment.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"In Ehlers-Danlos syndrome, ectopia lentis occurs due to:",o:["Fibrillin-1 gene mutation causing zonular weakness","Homocysteine accumulation causing zonular oxidative damage","Defective copper metabolism causing zonular deposition","Defective collagen synthesis causing connective tissue fragility including zonular fibres","Aldose"],a:3,e:"Ehlers-Danlos syndrome encompasses a group of inherited connective tissue disorders caused by mutations affecting collagen synthesis, processing, or cross-linking; the generalised connective tissue fragility extends to the zonular fibres, predisposing to ectopia lentis, though this is less common and less severe than in Marfan or homocystinuria.<br><br>Other ocular features include blue sclerae, keratoconus, angioid streaks, and retinal detachment; the skin hyperextensibility, joint hypermobility, and fragile blood vessels causing easy bruising constitute the systemic hallmarks used to clinically identify this connective tissue disorder.<br><br>Fibrillin-1 mutation (A) causes Marfan syndrome; homocysteine oxidative damage (B) causes homocystinuria; copper metabolism defect (C) causes Wilson's or Menkes disease; aldose reductase overactivity (E) relates to diabetic cataract formation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which of the following is a recognised ocular complication specific to a completely anteriorly dislocated lens into the anterior chamber?",o:["Vitreous haemorrhage","Cystoid macular oedema","Acute corneal decompensation and secondary glaucoma","Proliferative vitreoretinopathy","Central retinal artery occlusion"],a:2,e:"A lens completely dislocated into the anterior chamber causes direct mechanical contact with the corneal endothelium, leading to rapid and severe corneal decompensation; simultaneously, the dislocated lens obstructs the trabecular meshwork and creates pupil block, causing secondary acute angle closure glaucoma.<br><br>This constitutes an ocular emergency requiring urgent lens removal; delay results in irreversible corneal endothelial failure requiring subsequent penetrating keratoplasty; the combination of acute glaucoma and corneal decompensation makes anterior chamber lens dislocation one of the most vision-threatening complications of ectopia lentis.<br><br>Vitreous haemorrhage (A) and PVR (D) occur with posterior dislocation and retinal complications; cystoid macular oedema (B) is a postoperative complication; central retinal artery occlusion (E) is not a direct consequence of anterior lens dislocation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Slit-lamp examination in a patient with Marfan syndrome shows the lens equator and zonular fibres in the pupillary aperture. Which refractive error does this most likely produce?",o:["High hypermetropia","Anisohypermetropia","Pure regular astigmatism","Irregular myopic astigmatism","No refractive error as zonules"],a:3,e:"Superotemporal subluxation of the lens tilts the optical axis of the lens relative to the visual axis; this induces irregular astigmatism because different meridians of the decentred lens contribute varying refractive powers, compounded by the partial aphakic sector within the pupillary aperture producing additional myopic shift.<br><br>The irregular component of the astigmatism cannot be corrected by standard spherocylindrical spectacle lenses; rigid gas permeable contact lenses can mask the irregular astigmatism by creating a new regular refracting surface, offering better optical rehabilitation than spectacles in significant cases.<br><br>High hypermetropia (A) would occur with posterior dislocation reducing effective lens power; pure regular astigmatism (C) is correctable with spectacles; anisohypermetropia (B) is not the primary refractive consequence; the claim that no refractive error results (E) is incorrect as subluxation invariably affects refraction.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which sign on slit-lamp examination, seen as a crescent of reflected light at the lens equator, confirms the presence of lens subluxation?",o:["Krukenberg spindle","Vossius ring","Shafer sign","Oil droplet reflex","Aphakic crescent"],a:4,e:"The aphakic crescent is a dark crescent-shaped shadow visible at the pupil margin on retroillumination or direct focal slit-lamp examination; it represents the area of pupil not covered by the subluxated lens, through which light passes without the refracting effect of the lens, confirming lens displacement.<br><br>This sign directly indicates the degree and direction of lens subluxation; a large aphakic crescent corresponds to significant subluxation where a substantial aphakic zone contributes to monocular diplopia and visual disturbance in addition to the phakic zone of the displaced lens. The oil-droplet retroillumination sign of nuclear cataract is a classic slit-lamp clue.<br><br>Krukenberg spindle (A) is a vertical pigment deposit on the corneal endothelium in pigment dispersion syndrome; Vossius ring (B) is a pigment ring on the anterior lens capsule after blunt trauma; Shafer sign (C) is tobacco dust in the vitreous indicating retinal tear; oil droplet reflex (D) is seen in galactosaemia and keratoconus.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following systemic features most strongly suggests homocystinuria over Marfan syndrome in a patient presenting with ectopia lentis?",o:["Tall stature with arachnodactyly","High arched palate","Pectus excavatum","Intellectual disability with history of deep vein thrombosis","Mitral valve prolapse"],a:3,e:"Intellectual disability and thromboembolic events including deep vein thrombosis, pulmonary embolism, and stroke are hallmarks of homocystinuria not seen in Marfan syndrome; the combination of these features with inferior lens dislocation in a Marfanoid-appearing patient should immediately raise suspicion for homocystinuria.<br><br>The thromboembolic risk in homocystinuria is present from childhood; homocysteine promotes platelet aggregation, endothelial injury, and a procoagulant state; this distinguishes it critically from Marfan syndrome where the primary concern is cardiovascular, specifically aortic root dilatation and dissection.<br><br>Tall stature with arachnodactyly (A), high arched palate (B), pectus excavatum (C), and mitral valve prolapse (E) all occur in Marfan syndrome and can also appear in homocystinuria, making them unreliable discriminating features without the metabolic and neurological context.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"In the postoperative management of aphakia following lensectomy for ectopia lentis in a child, which is the most important intervention to optimise visual outcome?",o:["Systemic steroid therapy to reduce inflammation","Early optical correction with contact lens or spectacle and amblyopia treatment","Immediate secondary IOL implantation within one week","Patching of the operated eye to stimulate the fellow eye","Topical beta-blocker to"],a:1,e:"Following lensectomy for ectopia lentis in a child, the resulting aphakia must be corrected immediately to prevent stimulus deprivation amblyopia; contact lenses are preferred for optical rehabilitation of unilateral aphakia as they avoid aniseikonia and prismatic effects associated with high-power aphakic spectacles.<br><br>Amblyopia therapy through patching of the fellow eye must begin promptly alongside optical correction; the duration and intensity of patching depends on the degree of amblyopia, the child's age, and the critical period window; regular orthoptic follow-up is essential throughout visual development.<br><br>Systemic steroids (A) are not routinely indicated; immediate secondary IOL (C) may be planned but not necessarily within one week and depends on capsular support availability; patching the operated eye (D) would worsen amblyopia; topical beta-blocker (E) is used for IOP control if needed but is not the primary determinant of visual outcome.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following is most accurate regarding the inheritance and gene involved in Weill-Marchesani syndrome?",o:["Autosomal dominant only; fibrillin-1 gene","Autosomal recessive; ADAMTS10 gene, or autosomal dominant; fibrillin-1 gene","X-linked recessive; OCRL1 gene","Autosomal recessive only; cystathionine beta-synthase gene","Mitochondrial; COL4A gene"],a:1,e:"Weill-Marchesani syndrome has genetic heterogeneity; the autosomal recessive form is caused by mutations in the ADAMTS10 gene encoding a metalloprotease involved in fibrillin microfibril assembly, while an autosomal dominant form caused by FBN1 mutations produces a phenotype overlapping with Marfan syndrome.<br><br>This genetic overlap explains why both conditions share connective tissue abnormalities yet produce opposite skeletal phenotypes; Marfan causes tall stature with long digits while Weill-Marchesani causes short stature with brachydactyly, reflecting different downstream effects of disrupted fibrillin-mediated signalling.<br><br>Autosomal dominant fibrillin-1 only (A) is incomplete; OCRL1 (C) is Lowe syndrome; cystathionine beta-synthase (D) is homocystinuria; COL4A mitochondrial inheritance (E) is incorrect on both the gene and inheritance pattern.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A child presents with lens subluxation, fine hair, pale skin, seizures, and Menkes kinky hair syndrome is suspected. Which metabolic abnormality underlies the ocular finding?",o:["Excess copper deposition in zonular fibres","Sorbitol deposition within zonular fibres","Homocysteine accumulation oxidising zonular fibres","Copper deficiency impairing lysyl oxidase activity and collagen cross-linking","Sulphite accumulation disrupting"],a:3,e:"Menkes disease is an X-linked recessive disorder of copper transport causing systemic copper deficiency; lysyl oxidase, a copper-dependent enzyme essential for collagen and elastin cross-linking, is impaired; defective connective tissue cross-linking weakens zonular fibres, leading to lens subluxation.<br><br>The condition also causes neurodegeneration, hypopigmentation due to deficient tyrosinase activity, arterial tortuosity, and the characteristic sparse kinky steely hair; serum copper and caeruloplasmin levels are low; copper replacement therapy has limited benefit due to impaired cellular uptake.<br><br>Excess copper deposition (A) causes Wilson's disease with sunflower cataract; homocysteine accumulation (C) causes homocystinuria; sorbitol deposition (B) causes diabetic cataract; sulphite accumulation (E) causes sulphite oxidase deficiency with ectopia lentis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which of the following best describes the management of microspherophakia with acute pupil block glaucoma in Weill-Marchesani syndrome?",o:["Pilocarpine drops to constrict the pupil and pull the lens back","Cycloplegia and supine positioning followed by lens extraction if needed","Nd:YAG laser peripheral iridotomy as sole definitive treatment","Topical beta-blockers alone sufficient for long-term control","Bilateral prophylactic trabeculectomy"],a:1,e:"In microspherophakia with pupil block, cycloplegia relaxes the ciliary muscle, tightening the zonules and pulling the small spherical lens posteriorly away from the pupil; supine positioning allows gravity to assist posterior repositioning; this is the critical initial medical step distinct from management of other forms of angle closure.<br><br>Pilocarpine is specifically contraindicated as it relaxes zonules by contracting the ciliary muscle, worsening anterior lens migration and intensifying pupil block; if cycloplegia fails to break the attack or attacks recur, lens extraction is the definitive treatment to eliminate the anatomical cause permanently.<br><br>Pilocarpine (A) worsens this specific form of pupil block; Nd:YAG iridotomy (C) may relieve pupil block temporarily but does not address the underlying microspherophakia; beta-blockers alone (D) reduce IOP but do not relieve mechanical block; prophylactic trabeculectomy (E) is not indicated bilaterally in this condition.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following is the most common ocular complication of ectopia lentis requiring urgent intervention?",o:["Cystoid macular oedema","Optic atrophy","Corneal dystrophy","Secondary glaucoma","Choroidal detachment"],a:3,e:"Secondary glaucoma is the most common urgent complication of ectopia lentis; it arises through pupil block by an anteriorly displaced lens, angle closure from iris-lens diaphragm shift, or trabecular obstruction by lens material.<br><br>The mechanism varies by degree and direction of dislocation; anterior dislocation causes acute angle closure whereas posterior dislocation may cause open-angle elevation through vitreous prolapse obstructing trabecular outflow.<br><br>Cystoid macular oedema (A) is postoperative; corneal dystrophy (C) is unrelated to ectopia lentis; optic atrophy (B) is a late sequela of uncontrolled glaucoma; choroidal detachment (E) follows hypotony rather than lens dislocation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with ectopia lentis undergoes refraction. Best corrected vision is better through the aphakic zone than the phakic zone. What does this indicate?",o:["The lens has dislocated into the vitreous","Amblyopia has developed in the phakic zone","The cornea has decompensated centrally","Significant lenticular myopia or irregular astigmatism makes the phakic zone optically inferior","The optic nerve is damaged from chronic glaucoma"],a:3,e:"When vision through the aphakic zone exceeds that through the phakic portion, the subluxated lens is inducing sufficient irregular astigmatism or lenticular myopia to degrade image quality beyond what simple aphakic correction can achieve through the clear zone.<br><br>This finding guides management; if the aphakic zone provides better corrected vision, optical rehabilitation focuses on correcting the aphakic portion, and surgical lens removal becomes more justifiable to eliminate the optically degrading phakic contribution entirely.<br><br>Posterior dislocation into vitreous (A) would eliminate the phakic zone entirely; central corneal decompensation (C) would reduce vision through all zones; amblyopia (B) affects the entire visual pathway not a specific optical zone; optic nerve damage (E) causes field loss unrelated to zone comparison.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Traumatic subluxation of the lens most commonly occurs following blunt trauma due to rupture of zonular fibres at which location?",o:["Anterior zonular insertion on the lens capsule","Posterior zonular insertion near the pars plana","The weakest point at the zonular midportion","The entire circumference simultaneously","Only at the"],a:0,e:"Blunt trauma transmits a compressive force that momentarily expands the globe equatorially; the resulting stretch force is maximal at the zonular insertion onto the anterior lens capsule, which is the weakest attachment point and most vulnerable to traumatic rupture.<br><br>The degree of zonular rupture determines whether subluxation or complete dislocation occurs; less than 180 degrees of zonular rupture causes subluxation while more extensive rupture results in complete dislocation either anteriorly into the anterior chamber or posteriorly into the vitreous cavity.<br><br>Posterior zonular insertion (B) is more robust; midportion rupture (C) is not the primary site of failure; simultaneous circumferential rupture (D) would cause immediate complete dislocation; rupture only at the impact site (E) is incorrect as the force is transmitted circumferentially.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A Vossius ring on the anterior lens capsule following blunt trauma indicates:",o:["Rupture of the posterior lens capsule","Imprint of the iris pigment epithelium transferred to the lens during trauma","Deposits of calcium on the lens surface","Subluxation of the lens with zonular rupture","Anterior subcapsular cataract from direct trauma"],a:1,e:"Vossius ring is a circular pigmented ring deposited on the anterior lens capsule following blunt ocular trauma; it results from forceful contact between the posterior iris surface and the anterior lens, transferring iris pigment epithelium onto the capsule in a ring corresponding to the pupillary margin.<br><br>The ring itself does not significantly impair vision but is an important marker of significant blunt ocular trauma; its presence should prompt thorough examination for associated injuries including angle recession, iridodialysis, zonular damage, vitreous haemorrhage, and retinal tears or detachment. The Vossius ring of iris pigment on the anterior capsule is a frequently tested traumatic eponym.<br><br>Posterior capsule rupture (A) causes vitreous prolapse and is not associated with a pigment ring; calcium deposits (C) cause anterior capsular plaques; lens subluxation (D) causes iridodonesis and aphakic crescent; anterior subcapsular cataract (E) presents as a stellate or rosette opacity.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following investigations is most useful in confirming a diagnosis of homocystinuria in a child with suspected ectopia lentis?",o:["Slit-lamp examination of the lens position","Urine nitroprusside test and plasma homocysteine level","Serum copper and caeruloplasmin","Echocardiography for aortic root measurement","Skin biopsy for collagen"],a:1,e:"The urine nitroprusside test detects excess urinary homocysteine, turning red-purple in positive cases; plasma total homocysteine measurement provides quantitative confirmation and guides treatment response monitoring; together they establish the biochemical diagnosis of homocystinuria.<br><br>Newborn screening using tandem mass spectrometry can detect elevated methionine, enabling presymptomatic diagnosis before lens dislocation develops; early treatment with pyridoxine, dietary restriction, and betaine can prevent or delay the ocular, neurological, and thromboembolic complications.<br><br>Slit-lamp examination (A) identifies the lens position but not the aetiology; serum copper (C) diagnoses Wilson's or Menkes disease; echocardiography (D) assesses Marfan cardiovascular features; skin biopsy (E) is used for Ehlers-Danlos collagen analysis.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"In a patient with suspected Marfan syndrome presenting with ectopia lentis, which cardiovascular investigation is most essential before any surgical planning?",o:["Electrocardiography for arrhythmia detection","Echocardiography to assess aortic root diameter","Coronary angiography","Carotid Doppler ultrasound","Chest X-ray for cardiomegaly"],a:1,e:"Aortic root dilatation is the most life-threatening cardiovascular manifestation of Marfan syndrome; echocardiography to measure aortic root diameter is mandatory before any surgical intervention as anaesthesia-related haemodynamic changes can precipitate aortic dissection in patients with significant dilatation.<br><br>Beta-blocker therapy to reduce aortic wall stress is initiated when dilatation is identified; elective aortic root repair is recommended when diameter exceeds 5 cm; multidisciplinary cardiology input is essential for perioperative risk stratification before any ophthalmic surgical procedure.<br><br>ECG (A) detects arrhythmias but not the primary Marfan cardiovascular risk; coronary angiography (C) is invasive and not indicated; carotid Doppler (D) assesses cerebrovascular disease; chest X-ray (E) is insufficiently sensitive for aortic root measurement.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which of the following correctly pairs the condition with its specific lens finding?",o:["Marfan syndrome: oil droplet cataract","Homocystinuria: sunflower cataract","Wilson's disease: anterior lenticonus","Alport syndrome: anterior lenticonus","Weill-Marchesani: superotemporal ectopia lentis"],a:3,e:"Anterior lenticonus is pathognomonic of Alport syndrome; the forward conical protrusion of the central anterior lens surface results from localised deficiency of type IV collagen in the anterior lens capsule, a direct consequence of the COL4A gene mutations underlying this condition.<br><br>Each condition has a distinct lens signature; Marfan causes superotemporal ectopia lentis with intact zonules; homocystinuria causes inferonasally dislocated lens with ruptured zonules; Wilson's disease causes sunflower cataract; Weill-Marchesani causes microspherophakia with inferior subluxation.<br><br>Oil droplet cataract (A) is galactosaemia; sunflower cataract (B) is Wilson's disease; anterior lenticonus (C) is Alport not Wilson's; superotemporal ectopia lentis (E) is Marfan syndrome not Weill-Marchesani which causes inferior displacement.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Phacodonesis differs from iridodonesis in that:",o:["Phacodonesis indicates corneal pathology","Phacodonesis is tremulousness of the lens while iridodonesis is tremulousness of the iris","Iridodonesis occurs only after cataract surgery","Phacodonesis is seen only in Marfan syndrome","Both terms describe the same clinical"],a:1,e:"Phacodonesis refers specifically to the wobbling or tremulous movement of the crystalline lens observed on slit-lamp with rapid eye movements; it indicates zonular weakness insufficient to fully support the lens; iridodonesis is the similar oscillation of the iris due to loss of posterior lens support.<br><br>Both signs often coexist with increasing severity of zonular compromise; phacodonesis may be seen before frank iridodonesis develops; together they serve as reliable clinical indicators of zonular instability requiring careful surgical planning and use of adjuncts like capsular tension rings.<br><br>Corneal pathology (A) does not cause phacodonesis; iridodonesis is not exclusively postoperative (C); phacodonesis occurs in all causes of zonular weakness not just Marfan (D); they are distinct signs affecting different structures (E).<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following is the most appropriate refractive correction for a child with unilateral aphakia following lensectomy for traumatic ectopia lentis?",o:["High-plus aphakic spectacle lens","Extended wear silicone contact lens","Piggyback IOL system","Epikeratophakia","Corneal tattooing"],a:1,e:"Extended wear silicone contact lenses are the preferred optical rehabilitation for unilateral paediatric aphakia following lensectomy; they avoid the severe aniseikonia and optical distortions of high-plus spectacle lenses, allow full field correction, and are well tolerated in infants when fitted and managed by experienced practitioners.<br><br>Compliance with lens insertion and removal is managed by parents or carers; regular follow-up ensures appropriate lens power adjustments as the eye grows; patching of the fellow eye must accompany contact lens wear to treat the amblyopia that invariably accompanies unilateral aphakia in children. Refractive correction strategy in unilateral paediatric aphakia is a recurring management discussion.<br><br>High-plus aphakic spectacles (A) cause significant aniseikonia in unilateral cases; piggyback IOL (C) is used for secondary IOL power adjustment; epikeratophakia (D) is rarely performed today; corneal tattooing (E) is entirely unrelated to aphakic correction.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"In which of the following conditions is ectopia lentis associated with tall stature, arachnodactyly, and inferior lens dislocation with ruptured zonules?",o:["Marfan syndrome","Stickler syndrome","Homocystinuria","Weill-Marchesani syndrome","Ehlers-Danlos syndrome"],a:2,e:"Homocystinuria produces a Marfanoid phenotype with tall stature and arachnodactyly; however, the lens dislocates inferonasally with completely ruptured invisible zonules, distinguishing it from Marfan syndrome where the lens displaces superotemporally with intact visible zonules.<br><br>The metabolic nature of homocystinuria means that the systemic complications of thromboembolism and intellectual disability accompany the skeletal and ocular features; this combination of Marfanoid appearance with inferior dislocation and neurological or thromboembolic history is a classic high-yield distinguishing scenario.<br><br>Marfan syndrome (A) causes superotemporal dislocation with intact zonules; Stickler syndrome (B) causes myopia and retinal detachment without classic ectopia lentis; Weill-Marchesani (D) causes inferior dislocation but with short stature and brachydactyly; Ehlers-Danlos (E) causes ectopia lentis without the Marfanoid habitus.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Retinal detachment is a recognised complication of posteriorly dislocated lens. Which factor most increases this risk?",o:["Elevated intraocular pressure from secondary glaucoma","Anterior chamber shallowing compressing the retina","Corneal oedema reducing visual acuity","Direct vitreous traction on the retina from lens displacement and vitreous disruption","Inflammatory mediators from lens"],a:3,e:"Posterior lens dislocation into the vitreous cavity disrupts the normal vitreous architecture; the dislocated lens creates vitreous traction and syneresis, predisposing to peripheral retinal tears and subsequent rhegmatogenous retinal detachment, particularly in high myopes with pre-existing peripheral degeneration.<br><br>The risk is compounded by the high myopia commonly associated with conditions causing ectopia lentis; preoperative peripheral retinal examination and prophylactic treatment of lattice degeneration before lens surgery are essential to reduce the significant retinal detachment risk in these patients.<br><br>Elevated IOP (A) causes optic nerve damage rather than retinal detachment; corneal oedema (C) affects vision but not retinal attachment; anterior chamber shallowing (B) does not compress the retina; inflammatory mediators (E) cause uveitis not retinal detachment.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following best describes the lens position in posterior dislocation into the vitreous?",o:["Lens rests against the posterior iris surface","Lens floats freely in the vitreous or settles on the retinal surface","Lens becomes adherent to the ciliary body","Lens migrates into the suprachoroidal space","Lens dissolves within the vitreous over time"],a:1,e:"When the lens dislocates completely posteriorly through a ruptured zonule and vitreous face, it may float freely within the liquid vitreous or, in older patients with syneretic vitreous, settle inferiorly onto the retinal surface; a settled lens on the retina causes chronic retinal toxicity and tractional changes.<br><br>A freely floating dislocated lens may be tolerated temporarily without immediate surgery if it is clear and IOP is controlled; however, a lens resting on the retina, causing inflammation, or associated with uncontrolled glaucoma requires prompt pars plana lensectomy and vitrectomy.<br><br>Adherence to the posterior iris (A) describes incomplete anterior dislocation; ciliary body adherence (C) does not occur with complete dislocation; suprachoroidal migration (D) is not anatomically possible for the intact lens; lens dissolution (E) occurs only with cataractous lenses over very long periods.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"An eight-year-old child with bilateral ectopia lentis, tall stature, and learning difficulties has a normal urine nitroprusside test. Which condition should be considered next?",o:["Marfan syndrome","Hyperlysinaemia","Weill-Marchesani syndrome","Sulphite oxidase deficiency","Stickler syndrome"],a:3,e:"A negative urine nitroprusside test excludes homocystinuria; sulphite oxidase deficiency also causes bilateral ectopia lentis with intellectual disability and neurological features in a child; it is diagnosed by elevated urinary sulphite and S-sulphocysteine, not by the nitroprusside test which is specific for homocysteine.<br><br>The neurological features of sulphite oxidase deficiency including intractable seizures and severe intellectual disability often dominate the clinical picture; early recognition is important as molybdenum cofactor deficiency causing the same phenotype may benefit from specific cofactor supplementation in some subtypes.<br><br>Marfan syndrome (A) does not cause intellectual disability; hyperlysinaemia (B) is a very rare cause with milder features; Weill-Marchesani (C) causes short stature not tall stature; Stickler syndrome (E) does not typically cause ectopia lentis or intellectual disability.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which of the following describes the role of fibrillin-1 in the zonular fibres and explains why its deficiency causes ectopia lentis?",o:["Fibrillin-1 forms the collagen backbone of zonular fibres","Fibrillin-1 provides the elastic recoil of zonular fibres during accommodation","Fibrillin-1 regulates aqueous humour production maintaining zonular tension","Fibrillin-1 is the primary structural component of extracellular microfibrils that form zonular fibre scaffolding","Fibrillin-1 anchors zonular fibres to the lens"],a:3,e:"Fibrillin-1 polymerises into microfibrils that form the structural scaffold of zonular fibres; deficiency or dysfunction due to FBN1 mutations in Marfan syndrome compromises microfibril integrity, progressively weakening zonular support and leading to lens subluxation or dislocation over time.<br><br>Fibrillin-1 also regulates TGF-beta bioavailability; dysregulated TGF-beta signalling contributes to cardiovascular and pulmonary manifestations beyond the mechanical zonular defect, explaining why Marfan syndrome is a systemic connective tissue disorder rather than purely a mechanical structural problem.<br><br>Collagen backbone (A) is incorrect; fibrillin is not collagen; aqueous humour regulation (C) is not a fibrillin function; elastic recoil (B) is a property of elastin not fibrillin; direct epithelial anchorage (E) is not the mechanism of zonular-lens attachment.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which of the following surgical techniques is preferred for IOL fixation when no capsular support exists following lensectomy for complete ectopia lentis?",o:["In-the-bag IOL implantation","Sulcus fixation of a standard three-piece IOL","Anterior chamber angle-supported IOL","Scleral-fixated IOL using sutures or glue technique","Iris-claw IOL fixated to the"],a:3,e:"When no capsular or sulcus support exists following complete lensectomy, scleral fixation of a posterior chamber IOL provides the most anatomically appropriate and stable long-term solution; the haptics are fixated to the sclera either by sutures passed through the ciliary sulcus or by fibrin glue-assisted tucking of haptics into scleral flaps.<br><br>Scleral fixation places the IOL in the posterior chamber behind the iris, avoiding the corneal endothelial contact risks of anterior chamber IOLs; modern sutureless glued IOL techniques have simplified the procedure and reduced suture-related complications such as erosion and late IOL dislocation.<br><br>In-the-bag implantation (A) requires an intact capsular bag; standard sulcus fixation (B) requires at least partial sulcus support; angle-supported AC IOL (C) risks corneal endothelial loss and UGH syndrome; iris-claw IOL on anterior iris (E) has higher endothelial risk than posterior iris fixation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"In aniridia with associated ectopia lentis, the lens dislocation is most likely caused by:",o:["Secondary glaucoma damaging zonular fibres","Corneal pannus growing over and disrupting the zonules","Elevated IOP mechanically stretching zonular attachments","Developmental abnormality of the zonular fibres associated with PAX6 mutation","Chronic uveitis from"],a:3,e:"Aniridia is caused by PAX6 gene mutations affecting ocular development broadly; zonular dysgenesis resulting in ectopia lentis is a recognised developmental association, reflecting the role of PAX6 in coordinating multiple anterior segment structures including the iris, zonules, cornea, and trabecular meshwork.<br><br>The ectopia lentis in aniridia is typically bilateral and present from birth or early childhood; it compounds the already poor visual prognosis from foveal hypoplasia and nystagmus; surgical management is complicated by the small poorly dilating pupil and associated developmental glaucoma.<br><br>Secondary glaucoma (A) damages the optic nerve not the zonules directly; IOP mechanically stretching zonules (C) does not occur at clinically encountered pressures; corneal pannus (B) does not reach the zonules; uveitis-mediated zonular dissolution (E) is not the mechanism in aniridia.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A patient with Marfan syndrome develops acute myopic shift. What is the most likely mechanism?",o:["Corneal steepening from elevated IOP","Anterior lens dislocation increasing effective lens power","Vitreous liquefaction changing refractive index","Choroidal thickening from vascular changes","Nuclear sclerosis developing in the subluxated lens"],a:1,e:"Anterior displacement of a subluxated lens moves it closer to the nodal point of the eye and the cornea, effectively increasing its contribution to total ocular refractive power and producing a significant myopic shift; this can occur acutely if the lens suddenly moves forward through a weakened zonule.<br><br>The induced myopia from anterior lens displacement is often irregular and not fully correctable with standard spherocylindrical lenses; if the lens migrates into the anterior chamber, acute angle closure glaucoma accompanies the dramatic myopic shift, representing a surgical emergency.<br><br>Corneal steepening from IOP (A) does not cause acute myopia; vitreous liquefaction (C) does not significantly alter refraction; choroidal thickening (D) has negligible refractive impact; nuclear sclerosis (E) causes gradual index myopia not acute shift.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following statements about the capsular tension ring in ectopia lentis surgery is most accurate?",o:["It can be used even with complete 360-degree zonular loss","It is contraindicated in pseudoexfoliation syndrome","It must be placed before capsulorhexis is performed","It expands the capsular bag equator and distributes stress to intact zonular sectors","It replaces"],a:3,e:"The capsular tension ring works by distributing the zonular tension load evenly around the entire capsular bag equator; in cases of partial zonular loss, this transfers stress from the weak or absent sectors to the intact zonular quadrants, preventing capsular bag collapse and enabling safe phacoemulsification.<br><br>Standard CTR is suitable for zonular loss up to approximately 120 degrees; for greater loss the Cionni modified CTR with an eyelet for scleral suture fixation provides additional active support; beyond 180 degrees of zonular loss, pars plana lensectomy with vitrectomy is generally preferred.<br><br>Complete 360-degree zonular loss (A) precludes standard CTR use; CTR is placed after capsulorhexis not before (C); it is specifically indicated in pseudoexfoliation (B) which is a common indication; CTR does not replace anterior vitrectomy when vitreous has prolapsed (E).<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Following traumatic dislocation of the lens into the vitreous, which of the following is an indication for prompt surgical removal rather than observation?",o:["Patient age over 50 years","Uncontrolled secondary glaucoma or retinal detachment","Nuclear sclerosis of the dislocated lens","Patient preference for surgery","Presence of vitreous floaters"],a:1,e:"A dislocated lens in the vitreous may be observed if IOP is controlled and the retina is attached; surgical intervention is mandated when the dislocated lens causes uncontrolled secondary glaucoma refractory to medical therapy, lens-induced uveitis, or rhegmatogenous retinal detachment requiring concurrent vitreoretinal surgery.<br><br>Pars plana vitrectomy with lensectomy or fragmatome-assisted lens removal is the surgical approach; timing is critical as a lens resting on the retina causes progressive retinal toxicity and tractional changes increasing the complexity and worsening the prognosis of delayed surgery.<br><br>Patient age (A) alone does not determine surgical urgency; nuclear sclerosis of the dislocated lens (C) is not itself an indication for surgery; patient preference (D) is considered but not the primary indication; vitreous floaters alone (E) do not warrant surgical intervention.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following best describes the optical consequence of complete posterior dislocation of the lens into the vitreous?",o:["High myopia from increased axial length","Monocular diplopia from bifocal aperture","Irregular astigmatism from corneal warping","Absolute aphakia with high hypermetropia","No refractive change as vitreous"],a:3,e:"Complete posterior dislocation of the crystalline lens into the vitreous renders the eye functionally aphakic; the loss of approximately 15 to 20 dioptres of lenticular power causes marked high hypermetropia requiring full aphakic correction to restore functional vision.<br><br>The sudden onset of high hypermetropia is often the presenting symptom of complete posterior dislocation in a patient with previously known subluxation; spectacle aphakic correction in the interim while awaiting surgery provides functional vision though with the limitations of high-plus lenses including significant magnification.<br><br>High myopia (A) results from anterior dislocation increasing lens power; irregular astigmatism (C) occurs with partial subluxation not complete dislocation; monocular diplopia (B) requires the lens equator to bisect the pupil not complete dislocation; vitreous compensation (E) does not exist optically.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Scleral transillumination defects are associated with which condition that also causes ectopia lentis?",o:["Marfan syndrome","Homocystinuria","Ocular albinism with ectopia lentis","Ehlers-Danlos syndrome","Aniridia"],a:4,e:"Aniridia causes marked iris hypoplasia or virtual absence of iris tissue; the resulting transillumination of the sclera in the iris region is visible on examination; ectopia lentis is a recognised developmental association of aniridia through PAX6-mediated zonular dysgenesis affecting multiple anterior segment structures simultaneously.<br><br>Additional features of aniridia include foveal hypoplasia causing nystagmus and poor vision from birth, corneal pannus, cataract, and developmental glaucoma; the combination of these findings with ectopia lentis in a patient with no visible iris should immediately suggest aniridia and prompt genetic testing for PAX6 mutations.<br><br>Marfan syndrome (A) and homocystinuria (B) cause ectopia lentis without scleral transillumination defects; Ehlers-Danlos (D) causes ectopia lentis without iris abnormality; ocular albinism (C) causes iris transillumination but is not a primary cause of ectopia lentis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A newborn is found to have bilateral lens subluxation with nystagmus, poor visual fixation, and a family history of similar findings. No systemic features are present. What is the most likely diagnosis?",o:["Marfan syndrome","Homocystinuria","Simple familial ectopia lentis","Weill-Marchesani syndrome","Aniridia"],a:2,e:"Simple familial ectopia lentis is an isolated bilateral condition without systemic features; it presents in childhood with lens subluxation causing significant refractive error, nystagmus from early visual deprivation, and a positive family history following autosomal dominant or recessive inheritance.<br><br>Management centres on optical correction of the refractive error and amblyopia treatment; nystagmus in this setting reflects early visual deprivation during the critical period rather than a neurological disorder; genetic counselling is important given the heritable nature of the condition.<br><br>Marfan syndrome (A) has systemic cardiovascular and skeletal features; homocystinuria (B) causes intellectual disability and thromboembolism; Weill-Marchesani (D) has short stature and brachydactyly; aniridia (E) causes iris absence and foveal hypoplasia not isolated ectopia lentis.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following is most accurate regarding the use of mydriatics versus miotics in the acute management of lens subluxation with pupil block?",o:["Miotics are always first-line to constrict and stabilise the lens","Mydriatics and cycloplegics are preferred to pull the lens posteriorly by tightening zonules","Both are equally effective and interchangeable","Miotics are used for anterior dislocation; mydriatics for posterior dislocation","Neither has any effect on the position of a subluxated"],a:1,e:"Cycloplegia relaxes the ciliary muscle, which tightens the zonular fibres and exerts a posteriorly directed force on the lens, helping reposition an anteriorly displaced lens away from the pupil and relieve pupil block; mydriasis also widens the pupil, potentially allowing the lens to slip back posteriorly.<br><br>Miotics are specifically contraindicated in pupil block from lens subluxation as ciliary muscle contraction relaxes the zonules, worsening anterior lens displacement and intensifying pupil block; this is the opposite of their beneficial role in pupillary block from iris bombe where the iris, not the lens, is the obstructing element.<br><br>Miotics as first-line (A) is incorrect and harmful in this setting; equal interchangeability (C) is incorrect; the division by dislocation direction (D) is not the correct clinical principle; both drugs do affect lens position through their zonular effects (E).<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which feature of the dislocated lens on B-scan ultrasonography confirms complete posterior dislocation versus subluxation?",o:["Hyperreflective membrane at the posterior pole","Calcified plaque at the lens equator","Low-reflectivity shadow in the anterior vitreous","High-reflectivity mobile echo posterior to the iris plane with no lens in normal position","Thickening of the posterior hyaloid membrane"],a:3,e:"B-scan ultrasonography demonstrates the dislocated lens as a high-reflectivity echo within the vitreous cavity, posterior to the iris plane, with no identifiable lens structure in its normal retrolental position; the lens echo moves freely with eye movement, confirming complete dislocation rather than partial subluxation.<br><br>B-scan is particularly valuable when the view is obscured by corneal oedema, a dense cataract, or pupillary miosis; it also allows assessment of associated posterior segment pathology including vitreous haemorrhage, retinal detachment, and choroidal abnormalities requiring concurrent surgical management.<br><br>Hyperreflective membrane at posterior pole (A) suggests epiretinal membrane; low-reflectivity shadow in anterior vitreous (C) is not the appearance of a dislocated lens; calcified plaque at equator (B) suggests phthisis; posterior hyaloid thickening (E) indicates proliferative vitreoretinopathy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which of the following is the most important long-term ocular complication to monitor in a patient with Marfan syndrome after successful IOL implantation for ectopia lentis?",o:["Corneal graft rejection","Late IOL-capsular bag complex dislocation","Progressive keratoconus","Development of macular hole","Optic nerve"],a:1,e:"In Marfan syndrome, progressive zonular weakness does not cease after cataract surgery; the entire IOL-capsular bag complex can spontaneously dislocate months to years postoperatively as the residual zonular fibres continue to deteriorate, requiring IOL repositioning or scleral fixation of the dislocated complex.<br><br>Regular long-term slit-lamp surveillance is essential to detect early decentration of the IOL-capsular bag complex before complete dislocation occurs; prophylactic use of a capsular tension ring at the time of initial surgery reduces but does not eliminate the risk of this delayed complication. The long-term retinal detachment risk after paediatric lensectomy is an emphasised counselling point.<br><br>Corneal graft rejection (A) is irrelevant without keratoplasty; progressive keratoconus (C) is not a Marfan association; macular hole (D) is not specifically linked to Marfan syndrome; optic nerve cupping (E) requires concurrent glaucoma and is not the primary post-surgical concern.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following is the most recognised ocular association of Stickler syndrome relevant to the lens?",o:["Microspherophakia with inferior subluxation","Anterior lenticonus with capsular thinning","Sunflower cataract with zonular calcification","Presenile cataract with optically empty vitreous","Oil droplet"],a:3,e:"Stickler syndrome is an autosomal dominant collagen disorder caused by COL2A1 or COL11A1 mutations; the classic ocular triad includes high myopia, optically empty vitreous with avascular vitreous remnant, and presenile cataract developing in the third to fourth decade.<br><br>The lens opacity in Stickler syndrome is cortical and wedge-shaped, developing earlier than age-related cataract; the associated high myopia and vitreous abnormality significantly increase the risk of retinal detachment, which is the most vision-threatening complication in this condition.<br><br>Microspherophakia (A) is Weill-Marchesani; anterior lenticonus (B) is Alport syndrome; sunflower cataract (C) is Wilson's disease; oil droplet opacity (E) is galactosaemia; none of these are associated with optically empty vitreous.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with known ectopia lentis is found on gonioscopy to have angle recession in the same eye. What is the most likely aetiology of the lens subluxation?",o:["Marfan syndrome","Homocystinuria","Blunt ocular trauma","Weill-Marchesani syndrome","Simple familial ectopia lentis"],a:2,e:"Angle recession, representing a tear between the longitudinal and circular layers of the ciliary muscle, is pathognomonic of blunt ocular trauma; its presence in an eye with lens subluxation confirms that the zonular rupture resulted from the same traumatic episode rather than a hereditary or metabolic cause.<br><br>The combination of angle recession and traumatic lens subluxation carries a long-term risk of angle recession glaucoma, which can develop years after the original injury; annual IOP monitoring and gonioscopy of the fellow eye for bilateral angle recession are important long-term surveillance measures.<br><br>Marfan syndrome (A), homocystinuria (B), Weill-Marchesani (D), and simple familial ectopia lentis (E) are all hereditary causes that do not produce angle recession; angle recession is exclusively a traumatic finding.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following correctly describes the zonular findings in pseudoexfoliation syndrome leading to surgical risk during cataract surgery?",o:["Zonules are hypertrophied and excessively taut","Zonules are calcified and brittle due to calcium deposition","Zonules rupture acutely due to elevated IOP","Zonules are progressively weakened by pseudoexfoliative fibrillar material deposition","Zonules are absent"],a:3,e:"In pseudoexfoliation syndrome, abnormal fibrillar extracellular material produced by ageing lens epithelial cells deposits along and within the zonular fibres; this progressive accumulation mechanically weakens the zonules over time, reducing their tensile strength and increasing the risk of zonular dialysis during phacoemulsification.<br><br>The weakness is often clinically inapparent before surgery; intraoperative signs include poor pupil dilation, phacodonesis, and premature zonular dialysis; a capsular tension ring is routinely recommended for pseudoexfoliation cases to redistribute stress across remaining intact zonular sectors.<br><br>Hypertrophied taut zonules (A) do not occur; IOP-related acute rupture (C) is not the mechanism; calcium deposition (B) is not the pathological process; congenital zonular absence (E) does not describe pseudoexfoliation syndrome.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with ectopia lentis secondary to Marfan syndrome is being counselled about the risk of retinal detachment. Which factor most significantly elevates this risk?",o:["Superotemporal direction of lens displacement","Concurrent high axial myopia","Use of cycloplegic drops for management","Presence of nuclear sclerosis in the subluxated lens","Age of onset of ectopia"],a:1,e:"High axial myopia in Marfan syndrome produces peripheral retinal thinning, lattice degeneration, and vitreous syneresis; these predisposing changes dramatically increase the risk of rhegmatogenous retinal detachment, which is compounded further by vitreous disruption from zonular instability and surgical manipulation.<br><br>Preoperative peripheral retinal examination with scleral indentation and prophylactic treatment of lattice degeneration or retinal breaks before lens surgery is essential; patients must be counselled that the lifetime risk of retinal detachment in Marfan syndrome with high myopia is substantially elevated regardless of lens surgery.<br><br>Superotemporal lens displacement (A) is a direction finding not a retinal risk factor; cycloplegic drops (C) do not increase retinal detachment risk; nuclear sclerosis (D) does not predispose to detachment; age of onset (E) influences amblyopia risk not retinal detachment risk.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following systemic features is shared by both Marfan syndrome and homocystinuria, making clinical differentiation difficult on phenotype alone?",o:["Intellectual disability","Thromboembolic events","Aortic root dilatation","Tall stature with arachnodactyly and high arched palate","Sensorineural deafness"],a:3,e:"Both Marfan syndrome and homocystinuria produce a Marfanoid phenotype with tall stature, long limbs, arachnodactyly, high arched palate, and pectus deformities; this skeletal similarity makes it impossible to distinguish the two conditions on phenotype alone, necessitating biochemical testing.<br><br>The urine nitroprusside test and plasma homocysteine measurement differentiate homocystinuria from Marfan syndrome; echocardiography identifies aortic root dilatation in Marfan; the distinction is clinically critical because the perioperative thromboembolic risk and anaesthetic implications differ dramatically between the two conditions.<br><br>Intellectual disability (A) and thromboembolism (B) occur only in homocystinuria; aortic root dilatation (C) is specific to Marfan syndrome; sensorineural deafness (E) is specific to Alport syndrome.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"When performing capsulorhexis in a patient with Marfan syndrome and significant zonular weakness, which modification reduces the risk of rhexis runout?",o:["Making the rhexis as large as possible to decompress the bag","Using a smaller rhexis with a slow controlled tearing technique and maintaining anterior chamber depth with viscoelastic","Performing a posterior rhexis instead of anterior","Using scissors rather than a cystotome or forceps","Performing rhexis under air rather than"],a:1,e:"In zonular weakness, the capsular bag lacks normal posterior counter-traction; the anterior capsule tends to stretch and the rhexis can run peripherally toward the equator if tension is not carefully controlled; a smaller rhexis with gentle controlled tearing under good viscoelastic support minimises this risk.<br><br>Maintaining anterior chamber depth throughout with a dispersive viscoelastic prevents surge-induced chamber shallowing that destabilises the bag; iris hooks or pupil expansion rings provide additional stabilisation; placement of the CTR after rhexis completion further stabilises the bag for subsequent steps.<br><br>A large rhexis (A) increases runout risk in a floppy bag; posterior rhexis (C) is performed only in specific paediatric cases; scissors (D) provide less control than continuous curvilinear tearing; rhexis under air (E) provides poor visualisation and no capsular support.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following best explains why miotics worsen pupil block in microspherophakia but are beneficial in pupil block from iris bombe?",o:["Miotics increase aqueous production in microspherophakia","Miotics are ineffective in all forms of pupil block","Miotics cause corneal oedema selectively in microspherophakia","In microspherophakia miotics relax zonules allowing anterior lens migration; in iris bombe they constrict the pupil reducing iris contact with the lens","Miotics increase vitreous pressure in microspherophakia only"],a:3,e:"In microspherophakia, ciliary muscle contraction induced by miotics relaxes the zonular fibres, allowing the small spherical lens to move anteriorly and worsen pupil block; in iris bombe from posterior synechiae, the pupil block is iris-mediated and miotics help by pulling the iris away from the lens surface at the pupillary margin.<br><br>This fundamental pharmacological distinction is a high-yield examination concept; confusion between the two mechanisms can lead to incorrect treatment causing acute irreversible angle closure in microspherophakia; the rule is cycloplegia for lens-mediated pupil block and miotics for iris-mediated pupil block.<br><br>Increased aqueous production (A) is not a miotic effect; corneal oedema selectivity (C) does not exist; miotics are effective in specific pupil block types (B) making this incorrect; miotics do not alter vitreous pressure (E).<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following investigations would best differentiate simple ectopia lentis from Marfan syndrome in a tall adolescent with bilateral superotemporal lens subluxation?",o:["Urine nitroprusside test","Serum copper and caeruloplasmin levels","Echocardiography and FBN1 genetic testing","Electroretinography","Skin"],a:2,e:"Simple ectopia lentis can result from FBN1 mutations identical to Marfan syndrome but without the systemic phenotype; echocardiography assessing aortic root diameter and formal FBN1 genetic testing are required to determine whether the full Marfan diagnosis applies or the patient has isolated familial ectopia lentis.<br><br>The Ghent nosology criteria for Marfan syndrome require systemic scoring alongside genetic confirmation; a tall adolescent with superotemporal subluxation but no aortic involvement or skeletal score meeting threshold may have simple ectopia lentis; distinguishing these has major implications for cardiovascular surveillance and life insurance.<br><br>Urine nitroprusside (A) excludes homocystinuria not Marfan; serum copper (B) evaluates Wilson's or Menkes disease; electroretinography (D) assesses retinal function unrelated to this question; skin biopsy (E) evaluates collagen disorders not fibrillin.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which of the following correctly identifies the gene and chromosome involved in the autosomal recessive form of Weill-Marchesani syndrome?",o:["FBN1 on chromosome 15q","ADAMTS10 on chromosome 19p","CBS on chromosome 21q","OCRL1 on chromosome Xq26","PAX6 on chromosome 11p"],a:1,e:"The autosomal recessive form of Weill-Marchesani syndrome is caused by mutations in ADAMTS10 on chromosome 19p13; ADAMTS10 encodes a metalloprotease involved in extracellular matrix remodelling and fibrillin microfibril assembly, explaining the shared features with Marfan syndrome which involves fibrillin-1 directly.<br><br>Loss of ADAMTS10 function disrupts normal fibrillin microfibril organisation, producing the characteristic short stature, brachydactyly, joint stiffness, and microspherophakia; the autosomal dominant form caused by FBN1 mutations produces an overlapping phenotype, reflecting the functional connection between fibrillin and ADAMTS10 in the same biological pathway.<br><br>FBN1 chromosome 15q (A) is autosomal dominant Weill-Marchesani or Marfan; CBS chromosome 21q (C) is homocystinuria; OCRL1 Xq26 (D) is Lowe syndrome; PAX6 chromosome 11p (E) is aniridia.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient is found to have lens subluxation, fair skin, seizures, and elevated urinary sulphite on metabolic screening. Which of the following is the most likely diagnosis?",o:["Homocystinuria","Hyperlysinaemia","Marfan syndrome","Molybdenum cofactor deficiency","Galactosaemia"],a:3,e:"Molybdenum cofactor deficiency causes functional sulphite oxidase deficiency; elevated urinary sulphite combined with ectopia lentis, seizures, intellectual disability, and fair skin in a child is the characteristic presentation; the fair skin results from impaired melanin synthesis due to sulphite accumulation affecting tyrosinase activity.<br><br>The condition is autosomal recessive and usually fatal in infancy or early childhood in severe forms; a cyclic pyranopterin monophosphate substitute has shown benefit in a specific subtype; the urinary sulphite dipstick test is a rapid bedside screening tool that turns positive in affected patients. Lens subluxation with fair skin, seizures and raised homocysteine is a classic homocystinuria stem.<br><br>Homocystinuria (A) is detected by nitroprusside test not sulphite dipstick; hyperlysinaemia (B) involves lysine accumulation not sulphite; Marfan syndrome (C) has no metabolic abnormality on urine testing; galactosaemia (E) presents with oil droplet cataract and reducing substances in urine.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following best describes the term subluxation as distinct from luxation of the lens?",o:["Subluxation means the lens is in the anterior chamber; luxation means it is in the vitreous","Subluxation is congenital; luxation is always acquired","Subluxation refers to horizontal displacement; luxation refers to vertical displacement","Subluxation is partial displacement with residual zonular attachment; luxation is complete dislocation with no zonular support","Subluxation causes hypermetropia;"],a:3,e:"Subluxation implies partial zonular rupture with the lens remaining in the posterior chamber but decentred; some zonular fibres remain intact, providing residual support and explaining why the lens does not fall freely into the anterior chamber or vitreous despite visible displacement.<br><br>Luxation or complete dislocation implies total zonular rupture with no residual support; the lens is free to migrate anteriorly into the anterior chamber or posteriorly into the vitreous cavity; this distinction determines surgical approach as subluxation may allow anterior segment surgery while complete luxation usually requires pars plana vitrectomy.<br><br>Anterior chamber location (A) describes one form of complete dislocation not subluxation; directional definitions (C) are incorrect; congenital versus acquired distinction (B) does not define these terms; the refractive consequences (E) depend on direction of displacement not subluxation versus luxation per se.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following findings on anterior segment examination is most specific for pseudoexfoliation syndrome in a patient with early lens subluxation?",o:["Krukenberg spindle on the corneal endothelium","Posterior embryotoxon at the limbus","Brown iris transillumination defects","Pseudoexfoliative material on the anterior lens capsule with a clear central disc and peripheral ring","Corneal guttata in the central endothelium"],a:3,e:"The classic slit-lamp finding of pseudoexfoliation syndrome on the anterior lens capsule is a central disc of grey-white material, a clear intermediate zone scraped by the iris, and a peripheral granular ring; this three-zone pattern is pathognomonic and visible on undilated examination, confirmed with dilation exposing the peripheral zone.<br><br>The intermediate clear zone results from mechanical rubbing of the posterior iris surface against the anterior capsule as the pupil moves; the material is also deposited on the pupil margin, zonular fibres, ciliary processes, trabecular meshwork, and corneal endothelium, explaining the associated glaucoma risk.<br><br>Krukenberg spindle (A) is seen in pigment dispersion syndrome not pseudoexfoliation; brown iris transillumination defects (C) are characteristic of pigment dispersion at the mid-peripheral iris; posterior embryotoxon (B) is associated with Axenfeld-Rieger syndrome; corneal guttata (E) indicate Fuchs endothelial dystrophy.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"In a patient with homocystinuria, which dietary modification forms the cornerstone of long-term medical management to reduce lens dislocation progression?",o:["Low fat diet with omega-3 supplementation","Low methionine diet with cysteine supplementation","High protein diet to support connective tissue synthesis","Low carbohydrate diet to reduce oxidative stress","High calcium diet to strengthen zonular fibres"],a:1,e:"In homocystinuria, the enzymatic block at cystathionine beta-synthase prevents conversion of methionine to cysteine via homocysteine; dietary restriction of methionine reduces substrate availability for homocysteine production, while cysteine supplementation compensates for the deficiency caused by the blocked synthetic pathway.<br><br>Betaine supplementation further reduces homocysteine by promoting its remethylation back to methionine; this combined dietary and pharmacological approach reduces plasma homocysteine, slows zonular damage progression, and decreases the thromboembolic risk that represents the most life-threatening systemic complication.<br><br>Low fat diet (A) has no specific role in homocystinuria; high protein intake (C) would worsen methionine load; low carbohydrate diet (D) does not address the specific metabolic defect; calcium supplementation (E) has no evidence base in zonular strengthening in this condition.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following complications is most specific to intracapsular cataract extraction compared to extracapsular techniques when performed for a dislocated lens?",o:["Posterior capsule opacification","Elschnig pearl formation","Soemmering ring formation","Vitreous loss with subsequent complications including retinal detachment and cystoid macular oedema","IOL"],a:3,e:"Intracapsular cataract extraction removes the entire lens including its capsule, invariably disrupting the anterior vitreous face; vitreous loss into the anterior segment increases the risk of vitreous-related complications including vitreous traction on the retina, rhegmatogenous retinal detachment, chronic cystoid macular oedema, and vitreous touch to the corneal endothelium.<br><br>These vitreous-related complications are significantly less common with extracapsular techniques where the preserved posterior capsule maintains the barrier between anterior and posterior segments; the superior safety profile of extracapsular approaches is the primary reason intracapsular extraction has been largely abandoned for routine and complex cataract surgery.<br><br>Posterior capsule opacification (A), Elschnig pearl formation (B), and Soemmering ring (C) all require a residual capsule and are thus exclusive to extracapsular techniques; IOL decentration within the bag (E) requires a capsular bag absent in intracapsular surgery.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following best describes the management of a child with bilateral ectopia lentis where the lens is subluxated but still partially within the visual axis and vision is 6/18 in each eye?",o:["Immediate bilateral simultaneous lensectomy","Oral carbonic anhydrase","Nd:YAG laser to the zonular remnants to complete dislocation","Bilateral patching without optical correction","Optical correction of refractive error with amblyopia treatment and regular monitoring"],a:4,e:"When a subluxated lens retains a position providing correctable vision of 6/18 or better, conservative optical management is the appropriate first-line approach; cycloplegic refraction guides spectacle or contact lens prescription to correct the induced myopia and astigmatism, and amblyopia treatment is initiated if anisometropic or deprivation amblyopia is present.<br><br>Regular monitoring every three to six months assesses for progressive subluxation, worsening vision, or development of secondary glaucoma that would trigger surgical intervention; deferring surgery avoids anaesthetic risks and surgical complications in young children while preserving the option for lens removal if optical rehabilitation fails.<br><br>Immediate bilateral simultaneous lensectomy (A) is not justified when vision is correctable; Nd:YAG to zonular remnants (C) is not a recognised treatment; patching without correction (D) would worsen vision; carbonic anhydrase inhibitors (B) are not prophylactically indicated without raised IOP.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with Marfan syndrome undergoes pars plana vitrectomy and lensectomy. Which IOL fixation method provides the most anatomically stable long-term result when no capsular support is available?",o:["Anterior chamber angle-fixated IOL","Iris-sutured posterior chamber IOL","Scleral-sutured or sutureless scleral-fixated posterior chamber IOL","In-the-bag IOL with capsular tension ring","Piggyback IOL system"],a:2,e:"Scleral fixation of a posterior chamber IOL places the optic and haptics behind the iris in the anatomically correct position; this avoids the chronic corneal endothelial contact and angle damage risks of anterior chamber IOLs while providing stable long-term centration even without capsular support through direct scleral anchorage.<br><br>Sutureless techniques including glued IOL and flanged haptic intrascleral fixation have reduced the risk of suture erosion and late IOL dislocation seen with traditional sutured methods; these modern approaches offer excellent long-term outcomes in complex cases without capsular support following lensectomy. Pars plana lensectomy with vitrectomy for Marfan ectopia lentis is an emphasised surgical approach.<br><br>Angle-fixated AC IOL (A) carries chronic endothelial loss and UGH syndrome risk; iris-sutured IOL (B) is an option but less stable long-term; in-the-bag implantation (D) requires a capsular bag absent after lensectomy; piggyback in the anterior chamber (E) is not a standard fixation technique.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Ectopia lentis is associated with which of the following skeletal dysplasias characterised by short stature, short fingers, and joint stiffness as opposed to the Marfanoid tall habitus?",o:["Achondroplasia","Weill-Marchesani syndrome","Osteogenesis imperfecta","Kniest dysplasia","Spondyloepiphyseal dysplasia"],a:1,e:"Weill-Marchesani syndrome produces an anti-Marfan phenotype; while Marfan causes tall stature and long digits, Weill-Marchesani causes proportionate short stature, brachydactyly with short stubby fingers, limited joint mobility, and microspherophakia with inferior lens subluxation; recognising this contrasting skeletal phenotype is a key examination discriminator.<br><br>The condition results from mutations in ADAMTS10 or FBN1; despite the opposite skeletal effects, both Marfan and Weill-Marchesani involve disruption of fibrillin microfibril biology, reflecting how the same molecular pathway can produce diametrically opposite phenotypic outcomes depending on the specific mutation and downstream signalling effects.<br><br>Achondroplasia (A) causes short stature from FGFR3 mutation without ectopia lentis; osteogenesis imperfecta (C) causes bone fragility and blue sclerae; Kniest dysplasia (D) causes short trunk dwarfism without lens subluxation; spondyloepiphyseal dysplasia (E) is a different skeletal dysplasia without classic ectopia lentis.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following is the most appropriate initial pharmacological management for a patient with Marfan syndrome to reduce the rate of aortic root dilatation and thereby reduce perioperative surgical risk?",o:["Calcium channel blockers","ACE inhibitors alone","Diuretics to reduce systemic fluid load","Beta-blockers such as atenolol or propranolol","Antiplatelet agents to prevent aortic thrombosis"],a:3,e:"Beta-blockers reduce aortic wall stress by lowering heart rate and blood pressure, thereby decreasing the pulsatile mechanical strain on the already structurally weak aortic root; long-term beta-blocker therapy slows the rate of aortic root dilatation and reduces the risk of aortic dissection in Marfan syndrome.<br><br>Angiotensin receptor blockers such as losartan have also shown benefit by blocking TGF-beta-mediated aortic remodelling, which is dysregulated in Marfan syndrome due to fibrillin-1 deficiency; combined beta-blocker and ARB therapy is increasingly used in clinical practice.<br><br>Calcium channel blockers (A) are not first-line for aortic protection in Marfan; ACE inhibitors alone (B) have less evidence than ARBs in this context; diuretics (C) are not indicated for aortic protection; antiplatelet agents (E) target thrombosis not aortic structural deterioration.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with bilateral ectopia lentis, learning difficulties, and a positive urine cyanide nitroprusside test is found to be pyridoxine non-responsive. Which is the next most appropriate treatment addition?",o:["High-dose vitamin C supplementation","Riboflavin supplementation","Copper supplementation","Zinc acetate therapy","Betaine and dietary methionine restriction"],a:4,e:"In pyridoxine non-responsive homocystinuria, betaine acts as a methyl donor to remethylate homocysteine back to methionine via betaine homocysteine methyltransferase, thereby reducing plasma homocysteine levels; combined with dietary methionine restriction to reduce substrate load, this forms the cornerstone of treatment in non-responsive cases.<br><br>Cysteine supplementation replaces the deficient downstream product of the blocked pathway; regular monitoring of plasma homocysteine, methionine, and cysteine levels guides dose adjustments; folate and vitamin B12 supplementation support the remethylation pathway alongside betaine therapy.<br><br>Vitamin C (A) has antioxidant properties but no specific role in homocystinuria management; copper supplementation (C) treats Menkes disease; zinc acetate (D) treats Wilson's disease; riboflavin (B) is a cofactor in other metabolic pathways unrelated to homocystinuria.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"In the management of posteriorly dislocated lens in a vitrectomised eye, which specific risk is significantly higher compared to a non-vitrectomised eye?",o:["Risk of corneal decompensation","Risk of IOL","Risk of angle closure glaucoma","Risk of anterior capsule fibrosis","Risk of rapid posterior migration of nuclear fragments during phacoemulsification"],a:4,e:"In a vitrectomised eye, the normal cushioning effect of formed vitreous gel is absent; if posterior capsule rupture occurs during phacoemulsification, nuclear fragments drop rapidly into the posterior segment without resistance, making retrieval significantly more difficult than in a non-vitrectomised eye with intact vitreous.<br><br>This risk mandates that cataract surgery in vitrectomised eyes be performed with increased caution; lower aspiration flow rates, careful hydrodissection avoidance, and low phaco energy reduce the risk; the vitreoretinal surgeon should be available for concurrent management if nuclear drop occurs.<br><br>Corneal decompensation (A) is not specifically elevated by prior vitrectomy; angle closure glaucoma (C) is less likely without vitreous pushing the iris forward; anterior capsule fibrosis (D) is not specifically elevated; IOL calcification (B) is related to IOL material not vitrectomy status.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following conditions causes ectopia lentis through defective copper metabolism rather than a structural protein defect?",o:["Marfan syndrome","Ehlers-Danlos syndrome","Menkes disease","Homocystinuria","Weill-Marchesani syndrome"],a:2,e:"Menkes kinky hair disease is caused by mutations in ATP7A encoding a copper-transporting ATPase; the resulting systemic copper deficiency impairs lysyl oxidase, a copper-dependent enzyme essential for collagen and elastin cross-linking; defective connective tissue cross-linking weakens zonular fibres, causing ectopia lentis as one of its ocular manifestations.<br><br>Unlike the structural protein defects of Marfan and homocystinuria, Menkes disease operates through a metabolic enzymatic mechanism; the condition is X-linked recessive, affects males predominantly, and presents with progressive neurodegeneration, hypopigmentation, kinky brittle hair, and arterial tortuosity alongside the ocular features.<br><br>Marfan syndrome (A) involves fibrillin-1 structural defect; Ehlers-Danlos (B) involves defective collagen synthesis not copper; homocystinuria (D) involves cystathionine beta-synthase deficiency; Weill-Marchesani (E) involves ADAMTS10 or fibrillin-1 mutations.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with ectopia lentis has their lens successfully removed via pars plana lensectomy. Six months later they present with raised IOP, anterior chamber flare, and small white particles in the anterior chamber. What is the most likely diagnosis?",o:["Toxic anterior segment syndrome","Infectious endophthalmitis","Lens particle glaucoma from residual cortical material","Pseudophakic bullous keratopathy","Sympathetic ophthalmia"],a:2,e:"Retained cortical lens material following lensectomy can cause a delayed inflammatory response months after surgery; residual lens proteins and cortical particles trigger macrophage infiltration and direct trabecular meshwork obstruction, causing open-angle elevation of IOP and chronic low-grade anterior chamber inflammation.<br><br>Management involves topical anti-inflammatory agents to reduce the macrophage-mediated inflammation and IOP-lowering treatment; if particles are visible and IOP remains uncontrolled, surgical washout of the anterior chamber removes the residual material and resolves both the inflammation and glaucoma. Pars plana lensectomy for ectopia lentis is an emphasised surgical-approach decision.<br><br>TASS (A) presents acutely within 48 hours not six months postoperatively; infectious endophthalmitis (B) typically presents acutely with pain and hypopyon; pseudophakic bullous keratopathy (D) requires a pseudophakic eye with endothelial failure; sympathetic ophthalmia (E) involves the fellow eye in a bilateral granulomatous uveitis.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following best explains why cycloplegic refraction rather than manifest refraction is essential in assessing a child with ectopia lentis?",o:["Cycloplegia prevents pupil constriction that would obscure the subluxated lens","Accommodation artificially changes the position of the subluxated lens making refraction unreliable without cycloplegia","Cycloplegia dilates the pupil allowing better visualisation of lens position","Children cannot cooperate with manifest refraction","Cycloplegia reduces IOP enabling more accurate refraction"],a:1,e:"In ectopia lentis, accommodation causes ciliary muscle contraction that dynamically alters zonular tension; in a subluxated lens, this changing zonular tension produces fluctuating lens position and lenticular power during the refraction, making manifest refraction measurements inconsistent and unreliable for prescribing purposes.<br><br>Cycloplegia eliminates the accommodative component, stabilises lens position by maintaining uniform zonular tension, and allows measurement of the true underlying refractive error; it also reveals the full hypermetropic component masked by accommodative effort that would otherwise be undetected with non-cycloplegic techniques.<br><br>Pupil constriction obscuring the lens (A) is not the primary reason for cycloplegia in this context; dilation for visualisation (C) is a secondary benefit; inability to cooperate (D) is not universally true for children; IOP reduction from cycloplegia (E) is not a recognised effect.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following is the most appropriate long-term follow-up schedule for a child with known bilateral lens subluxation managed conservatively with spectacles?",o:["Annual review only when symptomatic","Monthly","Single review at age 18 when adult ophthalmology can take over","Biennial review alternating between optometrist and ophthalmologist","Every three to six months with assessment of vision, refraction, IOP, and lens position"],a:4,e:"Conservative management of paediatric ectopia lentis requires frequent structured review every three to six months; each visit should include best corrected visual acuity, cycloplegic refraction to detect refractive changes from progressive subluxation, IOP measurement to detect secondary glaucoma, and slit-lamp assessment of lens position and zonular integrity.<br><br>Progressive subluxation requiring surgical intervention, development of amblyopia requiring intensified treatment, and secondary glaucoma requiring medical or surgical management are the key outcomes being monitored; the frequency reflects the rapid changes possible during visual development and the serious consequences of missed complications.<br><br>Annual symptomatic-only review (A) risks missing progressive subluxation and amblyopia development; single review at 18 (C) is wholly inappropriate in a visually developing child; biennial review (D) is too infrequent; monthly review then discharge (B) is not evidence-based and risks missing late complications.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"In which of the following conditions does ectopia lentis occur with skeletal features resembling Marfan syndrome, caused by a defect in perlecan, a heparan sulphate proteoglycan?",o:["Stickler syndrome with vitreous anomaly and retinal detachment risk","Weill-Marchesani syndrome with brachydactyly and microspherophakia","Homocystinuria with cystathionine beta-synthase deficiency and","Ehlers-Danlos syndrome type VI with lysyl hydroxylase deficiency","Schwartz-Jampel syndrome with myotonic myopathy and skeletal dysplasia"],a:4,e:"Schwartz-Jampel syndrome is caused by HSPG2 mutations encoding perlecan, a heparan sulphate proteoglycan essential for extracellular matrix organisation; disrupted matrix scaffolding weakens zonular fibres, producing lens subluxation and microspherophakia alongside myotonic myopathy and skeletal dysplasia.<br><br>The condition is distinguished from Marfan and Weill-Marchesani by prominent myotonic features including persistent muscle stiffness, difficulty relaxing grip, and a characteristic facial appearance with blepharophimosis; the ectopia lentis results from abnormal zonular matrix rather than fibrillin or collagen defects.<br><br>Stickler syndrome (A) causes presenile cataract and optically empty vitreous; Weill-Marchesani (B) involves ADAMTS10 or FBN1 mutations; Ehlers-Danlos type VI (D) involves lysyl hydroxylase deficiency; homocystinuria (C) involves cystathionine beta-synthase deficiency without myotonic features.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which chromosome and gene mutation is responsible for classic homocystinuria causing ectopia lentis?",o:["Chromosome 21q22; cystathionine beta-synthase gene mutation","Chromosome 15q21; fibrillin-1 gene causing Marfan syndrome","Chromosome 19p13; ADAMTS10 causing Weill-Marchesani syndrome","Chromosome Xq26; OCRL1 gene causing Lowe syndrome","Chromosome 11p13; PAX6 gene causing"],a:0,e:"Classic homocystinuria results from mutations in the CBS gene on chromosome 21q22, encoding cystathionine beta-synthase; deficiency blocks conversion of homocysteine to cystathionine, causing homocysteine accumulation that oxidatively destroys zonular fibres producing inferonasally dislocated lens.<br><br>The autosomal recessive condition presents with ectopia lentis, intellectual disability, Marfanoid habitus, osteoporosis, and life-threatening arterial and venous thromboembolic events; approximately 50% of patients respond to high-dose pyridoxine which acts as an enzymatic cofactor enhancing residual CBS activity.<br><br>Chromosome 15q21 FBN1 (B) is Marfan syndrome; chromosome 19p13 ADAMTS10 (C) is Weill-Marchesani recessive form; OCRL1 Xq26 (D) is Lowe syndrome; PAX6 chromosome 11p13 (E) causes aniridia with associated ectopia lentis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Superotemporal ectopia lentis with intact visible zonules in a tall patient with pectus carinatum indicates which diagnosis?",o:["Homocystinuria with inferonasal dislocation and ruptured zonules","Marfan syndrome from FBN1 mutation on chromosome 15q21","Weill-Marchesani syndrome with microspherophakia and short stature","Sulphite oxidase deficiency with seizures and neurological impairment","Hyperlysinaemia with lysine accumulation and connective tissue weakness"],a:1,e:"Marfan syndrome causes superotemporal lens dislocation with elongated but structurally intact zonular fibres visible on slit-lamp retroillumination; the pectus deformity, tall stature, arachnodactyly, and arm span exceeding height complete the classic systemic phenotype caused by FBN1 mutations on chromosome 15q21.<br><br>The intact zonules in Marfan syndrome allow anterior segment surgical approach with capsular tension ring support, contrasting with homocystinuria where complete zonular rupture mandates pars plana lensectomy; this surgical distinction makes clinical differentiation between these two Marfanoid conditions critically important.<br><br>Homocystinuria (A) causes inferonasally dislocated lens with ruptured invisible zonules; Weill-Marchesani (C) causes inferior dislocation with microspherophakia and short stature; sulphite oxidase deficiency (D) and hyperlysinaemia (E) are rare metabolic causes without the classic Marfan skeletal phenotype.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A patient with ectopia lentis has the lens equator bisecting the pupil. Which single optical device best corrects the resulting irregular astigmatism?",o:["High-plus aphakic spectacle lenses for full field correction","Bifocal spectacle correction addressing both distance and near vision","Rigid gas permeable contact lens vaulting the irregular surface","Soft toric contact lens conforming to the ocular surface","Multifocal"],a:2,e:"Rigid gas permeable contact lenses vault over the irregular lenticular surface, creating a new regular refracting interface filled with tear fluid; this liquid lens neutralises the irregular astigmatism induced by lens tilt and decentration, providing superior optical correction over any spectacle lens in ectopia lentis.<br><br>Soft contact lenses conform to the ocular surface and cannot mask irregular astigmatism; spectacles can only correct regular astigmatism with cylindrical lenses; RGP lenses are therefore the optical device of choice when the subluxated lens remains in the visual axis producing irregular astigmatism uncorrectable by standard spectacles.<br><br>High-plus aphakic spectacles (A) correct aphakia not irregular astigmatism from subluxation; bifocal spectacles (B) address presbyopia not irregular astigmatism; soft toric lenses (D) correct only regular astigmatism; multifocal spectacles (E) address presbyopia without correcting irregular astigmatism.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following correctly describes the Ghent nosology criteria used to diagnose Marfan syndrome in a patient presenting with ectopia lentis?",o:["Ectopia lentis alone sufficient if confirmed FBN1 mutation is present on testing","Aortic root dilatation combined with ectopia lentis sufficient without genetic testing","Skeletal systemic score exceeding seven points alone confirms the diagnosis","Ectopia lentis with aortic root dilatation or FBN1 mutation causing aortic disease fulfils criteria","Positive family history combined with ectopia lentis sufficient for"],a:3,e:"The revised Ghent nosology defines Marfan syndrome through specific combinations; in the absence of family history, aortic root dilatation combined with ectopia lentis, or ectopia lentis with a pathogenic FBN1 mutation known to cause aortic disease, independently fulfils the diagnostic threshold for Marfan syndrome.<br><br>This nosology prevents misdiagnosis of conditions sharing features without meeting full criteria; the systemic score incorporating skeletal, skin, pulmonary, and dural features provides additional weighting when individual major criteria are present alone without fulfilling independent thresholds.<br><br>Ectopia lentis with FBN1 mutation alone (A) diagnoses ectopia lentis syndrome not full Marfan; aortic dilatation plus ectopia lentis without genetics (B) is sufficient but option D is more precise; skeletal score alone (C) requires additional criteria; family history plus ectopia lentis (E) requires further cardiovascular confirmation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Phacoanaphylactic endophthalmitis following lens dislocation is mediated by which immunological mechanism?",o:["Type I IgE-mediated hypersensitivity to released lens crystallin proteins","Type II antibody-mediated cytotoxicity targeting lens epithelial cell antigens","Type III immune complex deposition within the trabecular meshwork tissue","Non-granulomatous Type IV delayed hypersensitivity to lens proteins","Granulomatous Type IV"],a:4,e:"Phacoanaphylactic endophthalmitis is a granulomatous uveitis caused by Type IV delayed hypersensitivity to lens proteins; crystallins sequestered behind the blood-aqueous barrier are perceived as foreign antigens when released through capsular rupture, triggering a T-cell mediated granulomatous inflammatory response.<br><br>The condition presents with severe granulomatous uveitis, keratic precipitates, posterior synechiae, and raised IOP days to weeks after lens disruption; treatment requires removal of all lens material combined with intensive anti-inflammatory therapy; the fellow eye must be monitored for sympathetic lens-induced inflammation. Phacoanaphylactic endophthalmitis as a type III lens-induced reaction is a recurring immunology correlate.<br><br>Type I IgE-mediated hypersensitivity (A) causes immediate allergic reactions not granulomatous uveitis; Type II cytotoxicity (B) and Type III immune complex (C) are not the mechanisms of phacoanaphylaxis; non-granulomatous Type IV (D) is an incomplete description as the granulomatous nature is the defining pathological feature.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following is the most common direction of traumatic lens dislocation following blunt equatorial expansion of the globe?",o:["Inferiorly as gravity assists displacement in the commonest direction of failure","Superiorly and temporally following the path of least zonular resistance","Anteriorly into the anterior chamber through the weakened pupillary aperture","Posteriorly into the vitreous through the disrupted anterior vitreous face","Nasally due to structurally weaker"],a:0,e:"Following blunt trauma, the compressive force causes transient equatorial globe expansion stretching zonular fibres; the inferiorly positioned zonules are subjected to the greatest mechanical disadvantage combined with gravitational effects, making inferior displacement the most common direction of traumatic lens dislocation clinically.<br><br>The degree of inferior displacement depends on the extent of zonular rupture; subluxation with a visible inferior aphakic crescent is the most common presentation; complete inferior dislocation with the lens resting on the inferior retinal surface requires prompt pars plana vitrectomy and lensectomy.<br><br>Superotemporal dislocation (B) is the direction of Marfan ectopia lentis not traumatic dislocation; anterior chamber dislocation (C) occurs but is less common than inferior subluxation; pure posterior dislocation (D) requires extensive circumferential zonular rupture; nasal dislocation (E) is not the predominant traumatic direction.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following is the most feared immediate complication of complete anterior dislocation of the lens into the anterior chamber?",o:["Lens-induced uveitis from protein leakage through the intact capsule","Choroidal","Posterior synechiae formation around the anteriorly dislocated lens periphery","Vitreous haemorrhage from traction on peripheral retinal vessels at ora serrata","Acute secondary angle closure with corneal decompensation from endothelial contact"],a:4,e:"Complete anterior dislocation simultaneously obstructs the trabecular meshwork and creates pupil block; the resulting acute angle closure causes rapid severe IOP elevation with corneal endothelial decompensation from both direct lens-endothelial contact and pressure-related ischaemic damage to the corneal endothelium.<br><br>This constitutes a true ocular emergency; every hour of delay worsens irreversible endothelial cell loss; emergency IOP reduction with systemic acetazolamide and osmotic agents precedes prompt surgical lens extraction; prolonged anterior chamber dislocation may necessitate subsequent penetrating keratoplasty for corneal decompensation.<br><br>Lens-induced uveitis (A) is a delayed complication of hypermature cataract not acute dislocation; posterior synechiae (C) are chronic inflammatory complications; vitreous haemorrhage (D) follows retinal traction not anterior dislocation; choroidal detachment (B) results from hypotony not the elevated pressure of anterior dislocation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which clinical sign specifically indicates zonular instability that develops before frank iridodonesis becomes visible on slit-lamp examination?",o:["Shafer sign visible as tobacco dust cells in the anterior vitreous","Krukenberg spindle seen on the corneal endothelium inferiorly","Vossius ring seen as pigment imprint on the anterior lens capsule","Pigment deposited on the trabecular meshwork visible on gonioscopy","Phacodonesis observed as lens tremulousness on rapid eye movements"],a:4,e:"Phacodonesis, the visible tremulous oscillation of the crystalline lens with rapid eye movements observed on slit-lamp, is the earliest clinical indicator of zonular instability; it precedes iridodonesis because the lens directly reflects zonular weakness before the posterior iris surface loses adequate support.<br><br>Identifying phacodonesis before surgery is critical; it signals the need for modified surgical technique including lower fluidics, gentle hydrodissection, and prophylactic capsular tension ring placement; intraoperative phacodonesis not previously assessed can lead to catastrophic capsular bag collapse if unrecognised early.<br><br>Shafer sign (A) indicates retinal tear with tobacco dust cells in the vitreous; Krukenberg spindle (B) indicates pigment dispersion from zonular-lens friction; pigment on trabecular meshwork (D) suggests pigmentary glaucoma; Vossius ring (C) is a traumatic pigment imprint on the anterior lens capsule.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"In which of the following conditions is ectopia lentis associated with cutis laxa, joint hypermobility, and defective elastin rather than collagen or fibrillin?",o:["Marfan syndrome caused by fibrillin-1 microfibril structural defect","Stickler syndrome caused by type II collagen gene COL2A1 mutation","Homocystinuria caused by cystathionine beta-synthase enzyme deficiency","Cutis laxa syndrome with ocular involvement from elastin deficiency","Weill-Marchesani syndrome caused by ADAMTS10 or FBN1 mutations"],a:3,e:"Cutis laxa is a heterogeneous group of connective tissue disorders characterised by defective elastin production or assembly causing loose redundant skin, pulmonary emphysema, cardiovascular defects, and joint hypermobility; ocular involvement including ectopia lentis occurs in some subtypes through defective elastin-based zonular architecture.<br><br>The condition differs fundamentally from Marfan syndrome where fibrillin-1 not elastin itself is defective, and from Ehlers-Danlos where collagen is primarily affected; elastin deficiency in cutis laxa disrupts the elastic extracellular matrix component contributing to zonular fibre weakness and lens subluxation.<br><br>Marfan syndrome (A) involves fibrillin-1 not elastin deficiency; Stickler syndrome (B) involves type II collagen without elastin defects; homocystinuria (C) involves enzymatic not structural protein defects; Weill-Marchesani (E) involves ADAMTS10 or fibrillin-1 mutations without elastin deficiency.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which of the following correctly describes the natural history of untreated ectopia lentis in a child with Marfan syndrome?",o:["Spontaneous improvement as zonules gradually strengthen with skeletal maturity","Static lens position with no progressive subluxation occurring after puberty","Progressive subluxation with worsening refractive error and eventual complete dislocation","Regression of subluxation occurring with long-term beta-blocker therapy use","Stabilisation of lens position following successful aortic root repair"],a:2,e:"The natural history of untreated ectopia lentis in Marfan syndrome is progressive worsening with advancing age as zonular fibres continue to degenerate due to ongoing fibrillin-1 dysfunction, leading to increasing subluxation, worsening myopia and irregular astigmatism, and eventual complete dislocation.<br><br>Progressive subluxation worsens induced myopia and irregular astigmatism; in children during the critical period this causes deprivation or anisometropic amblyopia; regular optical correction, monitoring, and timely surgical intervention when optical rehabilitation fails prevent permanent visual loss.<br><br>Spontaneous improvement (A) does not occur in Marfan syndrome; static position after puberty (B) is incorrect as progression continues into adulthood; regression with beta-blockers (D) applies to aortic dilatation not lens position; aortic repair stabilising lens position (E) has no biological basis.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is most useful for quantifying lens subluxation and planning surgical approach when fundal view is obscured?",o:["B-scan ultrasonography assessing lens position and posterior segment anatomy","Corneal topography mapping induced irregular astigmatism from lens tilt","Electroretinography quantifying residual retinal function before surgery","Anterior segment OCT measuring anterior chamber depth and lens vault","Fluorescein angiography assessing macular perfusion"],a:0,e:"B-scan ultrasonography precisely localises the lens within the posterior chamber or vitreous cavity, assesses vitreous face integrity, detects associated retinal detachment or vitreous haemorrhage, and guides the choice between anterior segment surgery and pars plana vitrectomy when optical media are too opaque for direct visualisation.<br><br>High-resolution B-scan can also assess the degree of zonular rupture by identifying the position and mobility of the lens echo; a freely mobile high-reflectivity echo posterior to the iris plane with absent normal lens position confirms complete dislocation requiring vitreoretinal surgical approach.<br><br>Corneal topography (B) assesses corneal shape not lens position; electroretinography (C) assesses retinal electrical function not anatomy; anterior segment OCT (D) cannot penetrate sufficiently to assess the vitreous cavity; fluorescein angiography (E) requires adequate optical media clarity.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which mechanism explains why pseudoexfoliation syndrome causes both lens subluxation and elevated intraocular pressure?",o:["Pseudoexfoliative material blocks the pupil causing pupil block glaucoma","Pseudoexfoliative fibrillar material weakens zonules and clogs the trabecular meshwork simultaneously","Chronic uveitis from lens protein release damages both zonules and trabecular meshwork","Pseudoexfoliative material stimulates abnormal aqueous production by the ciliary body","Steroid treatment of associated inflammation causes both"],a:1,e:"Pseudoexfoliative material produced by ageing lens epithelial cells deposits diffusely throughout the anterior segment; deposition within zonular fibres causes mechanical weakening, while deposition within the trabecular meshwork physically impedes aqueous outflow producing open-angle glaucoma concurrently.<br><br>This dual deposition explains why pseudoexfoliation is simultaneously the most common identifiable cause of open-angle glaucoma worldwide and a significant risk factor for intraoperative zonular complications during cataract surgery; both consequences arise from the same pathological material affecting different structures.<br><br>Pupil block glaucoma (A) is the mechanism in microspherophakia not pseudoexfoliation; chronic uveitis (C) is not the mechanism in pseudoexfoliation; abnormal aqueous production (D) does not occur in this condition; steroid use (E) is not the aetiology of pseudoexfoliation syndrome.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which is the most appropriate management of a completely dislocated crystalline lens resting on the retina with controlled IOP and attached retina?",o:["Immediate urgent surgery within 24 hours regardless of current IOP status","Indefinite observation with aphakic correction if vision remains satisfactory","Intravitreal","Laser photocoagulation around the dislocated lens to fix it to the retina","Prompt pars plana vitrectomy and lensectomy within weeks to prevent retinal toxicity"],a:4,e:"A crystalline lens resting on the retinal surface causes progressive mechanical retinal toxicity, disrupts the photoreceptor layer, and creates vitreous traction; prompt surgical removal via pars plana vitrectomy within weeks prevents irreversible retinal damage even when IOP is controlled and the retina remains attached.<br><br>Delay beyond several weeks increases surgical complexity as inflammatory membranes form around the lens and retinal adhesion develops; early intervention while the lens remains mobile and the retina is attached provides the best surgical conditions and visual prognosis compared to delayed surgery.<br><br>Immediate surgery within 24 hours (A) is not necessary if IOP is controlled; indefinite observation (B) risks permanent retinal toxicity from lens contact; laser photocoagulation to fix the lens (D) is not a recognised procedure; intravitreal steroid (C) does not remove the mechanical source of damage.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which aortic root diameter threshold triggers recommendation for prophylactic surgical intervention in Marfan syndrome?",o:["Surgery recommended when diameter exceeds 4.0 cm in all patients universally","Surgery recommended when diameter exceeds 4.5 cm in patients with rapid growth only","Surgery recommended when diameter exceeds 6.0 cm regardless of the growth rate","Surgery recommended when exceeding 5.0 cm, or 4.5 cm with rapid growth or dissection history","Surgery recommended only after documented aortic dissection has already"],a:3,e:"Current guidelines recommend prophylactic aortic root repair in Marfan syndrome when the diameter exceeds 5.0 cm; earlier intervention at 4.5 cm is recommended when growth exceeds 0.5 cm per year, when there is a family history of aortic dissection, or when planned pregnancy adds surgical urgency.<br><br>This threshold knowledge is relevant to ophthalmologists managing Marfan patients for ectopia lentis; preoperative echocardiographic assessment and cardiology clearance are mandatory before any elective ophthalmic surgery, as anaesthesia-related haemodynamic changes can precipitate dissection in patients with significant aortic dilatation. The aortic root threshold for prophylactic repair in Marfan is a classic systemic-correlate fact.<br><br>4.0 cm threshold (A) is too conservative leading to premature surgery; 4.5 cm for rapid growth only (B) is an incomplete recommendation; 6.0 cm threshold (C) is dangerously late intervention; surgery only after dissection (E) represents failed prophylactic management strategy.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which of the following accurately explains why the lens assumes a more spherical shape when zonular tension is released during accommodation?",o:["Ciliary muscle contraction directly moulds the lens substance into a sphere","Aqueous pressure pushes the lens posteriorly moulding it into a spherical form","Vitreous pressure anteriorly compresses and rounds the lens during near focus","The lens nucleus expands osmotically when zonular tension is suddenly released","The elastic lens capsule moulds"],a:4,e:"The lens capsule is highly elastic and under constant tension from zonular fibres; when ciliary muscle contraction releases zonular tension during accommodation, the elastic recoil of the capsule compresses the lens substance into a rounder more spherical configuration, increasing its refractive power for near vision.<br><br>This capsular elasticity is greatest in youth when the lens nucleus is soft and easily moulded; with ageing the nucleus hardens progressively, resisting capsular moulding despite intact capsular elasticity; this age-related nuclear hardening is the predominant mechanism of presbyopia according to the Helmholtz theory.<br><br>Ciliary muscle directly moulding the lens (A) is incorrect as the muscle acts through zonule-mediated tension change; aqueous pressure (B) does not direct lens shape change during accommodation; vitreous pressure (C) provides posterior support not a shaping force; osmotic nuclear expansion (D) is not a recognised accommodation mechanism.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following is the most important preoperative assessment specific to planning lens surgery in a patient with homocystinuria?",o:["Measurement of axial length and keratometry for accurate IOL power calculation","Corneal endothelial cell count to assess decompensation risk from phacoemulsification","Haematological assessment and liaison for perioperative thromboembolism prevention","Gonioscopy to assess angle anatomy and risk of postoperative glaucoma","Electroretinography"],a:2,e:"The most critical preoperative consideration specific to homocystinuria is assessment and management of the thromboembolic risk; homocysteine-mediated endothelial damage and platelet hyperaggregability create a profoundly prothrombotic state exacerbated by anaesthesia, dehydration, and surgical stress, potentially causing fatal stroke or pulmonary embolism.<br><br>Haematological consultation to plan anticoagulation, optimise plasma homocysteine levels with betaine and pyridoxine before surgery, ensure adequate perioperative hydration, and minimise anaesthetic duration are the specific preparatory measures unique to this condition beyond standard ophthalmic assessment.<br><br>Axial length measurement (A) and corneal endothelial count (B) are standard assessments applicable to all cataract surgery without specific homocystinuria relevance; gonioscopy (D) and electroretinography (E) are not the most important specific preoperative steps in homocystinuria.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which slit-lamp finding helps distinguish traumatic lens subluxation from hereditary ectopia lentis when history is unavailable?",o:["Direction of lens displacement indicating the likely underlying aetiology","Presence of iridodonesis confirming the degree of zonular weakness present","Presence","Degree of nuclear sclerosis visible within the subluxated lens on examination","Angle recession on gonioscopy, Vossius ring, or traumatic sphincter tears indicating prior trauma"],a:4,e:"When history is unavailable, signs of prior blunt trauma provide objective evidence of traumatic aetiology; angle recession on gonioscopy is pathognomonic of blunt injury; Vossius ring on the anterior capsule confirms iris-lens contact at impact; traumatic sphincter tears cause permanent irregular mydriasis.<br><br>These trauma markers combined with absence of systemic features of hereditary conditions and unilateral presentation point strongly toward traumatic aetiology; hereditary causes are typically bilateral and lack these trauma-specific signs; any two trauma markers together make hereditary aetiology highly unlikely.<br><br>Direction of lens displacement (A) overlaps between conditions; iridodonesis (B) occurs in all forms of zonular weakness regardless of aetiology; nuclear sclerosis (D) reflects age not aetiology; phacodonesis (C) indicates zonular weakness but not its underlying cause.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following best describes the role of betaine in the management of homocystinuria?",o:["Betaine inhibits aldose reductase thereby reducing total homocysteine production","Betaine directly replaces the deficient cystathionine beta-synthase enzyme activity","Betaine remethylates homocysteine to methionine via betaine-homocysteine methyltransferase","Betaine chelates excess homocysteine preventing zonular oxidative damage directly","Betaine reduces intestinal methionine absorption reducing"],a:2,e:"Betaine donates a methyl group to homocysteine via betaine-homocysteine methyltransferase, converting it back to methionine through an alternative remethylation pathway that bypasses the blocked CBS step; this reduces plasma homocysteine levels, decreasing oxidative zonular damage and thromboembolic risk.<br><br>Betaine is effective in both pyridoxine-responsive and non-responsive patients; combined with dietary methionine restriction it reduces substrate input from both ends of the pathway; regular plasma homocysteine monitoring guides dose titration aiming for levels below 100 micromoles per litre.<br><br>Aldose reductase inhibition (A) relates to diabetic cataract management not homocystinuria; enzyme replacement (B) is not available for CBS deficiency; chelation of homocysteine (D) is not betaine's mechanism of action; reducing gastrointestinal methionine absorption (E) is achieved by dietary restriction not betaine supplementation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which is the most appropriate optical correction for bilateral aphakia in an infant following lensectomy for dense bilateral congenital ectopia lentis?",o:["Rigid gas permeable contact lenses fitted bilaterally for irregular astigmatism correction","High-plus spectacle aphakic correction addressing unilateral aniseikonia concerns","Immediate bilateral secondary IOL implantation performed concurrently with lensectomy","Bilateral aphakic spectacles combined with early patching of the dominant eye","Epikeratophakia performed bilaterally to restore"],a:3,e:"In bilateral infantile aphakia, high-plus aphakic spectacles provide the most practical immediate optical rehabilitation; unlike unilateral aphakia where aniseikonia limits spectacle use, bilateral correction avoids this problem; early patching of the dominant eye encourages equal visual development and prevents amblyopia.<br><br>Contact lenses are preferred for unilateral aphakia; for bilateral cases spectacles are often first-line in infants due to ease of management by parents; IOL implantation in infants under two years carries high rates of posterior capsule opacification and inflammatory complications making spectacle correction the safer initial approach. Aphakic correction in infants and the amblyopia risk is a classic paediatric management theme.<br><br>RGP lenses bilaterally (A) are technically difficult to manage in very young infants; high-plus spectacles for bilateral cases (B) are appropriate but option D includes the essential amblyopia management component; immediate bilateral IOL implantation (C) is generally deferred in infants below two years; epikeratophakia (E) is rarely performed in modern practice.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A patient with Marfan syndrome and known ectopia lentis reports sudden floaters and a peripheral visual field curtain. What is the most likely diagnosis?",o:["Vitreous haemorrhage from rupture of peripheral zonular vessels","Acute angle closure from anterior displacement of the subluxated lens","Central retinal artery occlusion from aortic emboli reaching the ophthalmic artery","Cystoid macular oedema from chronic low-grade lens-induced inflammation","Rhegmatogenous retinal detachment from"],a:4,e:"Floaters combined with a visual field curtain are the classic presenting symptoms of rhegmatogenous retinal detachment; in Marfan syndrome, high axial myopia causes peripheral retinal thinning and lattice degeneration while zonular instability disrupts vitreous architecture, creating traction on the peripheral retina predisposing to tears and detachment.<br><br>This is a surgical emergency requiring urgent vitreoretinal assessment and repair; the risk is substantially elevated in Marfan syndrome compared to the general population and further increased if the patient has undergone prior lens surgery; prophylactic retinal treatment reduces but does not eliminate this risk.<br><br>Vitreous haemorrhage (A) presents with sudden floaters without a peripheral field curtain; acute angle closure (B) presents with pain and haloes not field loss; central retinal artery occlusion (C) causes sudden complete painless visual loss not a curtain; cystoid macular oedema (D) causes central blur not peripheral field curtain.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which is the most common systemic cause of bilateral lens subluxation in a child presenting without intellectual disability or thromboembolic history?",o:["Marfan syndrome from FBN1 mutation causing superotemporal dislocation","Homocystinuria causing inferonasal dislocation with intellectual disability","Weill-Marchesani syndrome causing inferior dislocation with short stature","Sulphite oxidase deficiency causing ectopia lentis with severe seizures","Simple familial ectopia lentis inherited as"],a:0,e:"Marfan syndrome is the most common systemic cause of bilateral ectopia lentis in children; it characteristically presents without intellectual disability or thromboembolic events, distinguishing it from homocystinuria despite the similar Marfanoid phenotype; the superotemporal lens dislocation with intact zonules and cardiovascular features confirm the diagnosis.<br><br>The absence of neurological and thromboembolic features in a child with bilateral superotemporal ectopia lentis and tall Marfanoid habitus makes Marfan syndrome the first and most important diagnosis to confirm; echocardiography and FBN1 genetic testing complete the diagnostic workup and guide multidisciplinary management.<br><br>Homocystinuria (B) causes intellectual disability and thromboembolism; Weill-Marchesani (C) causes short stature and brachydactyly; sulphite oxidase deficiency (D) causes severe seizures and neurological impairment; simple familial ectopia lentis (E) has no systemic features but is less common than Marfan syndrome.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which surgical risk is most specific to phacoemulsification in an eye with angle recession and traumatic lens subluxation?",o:["Higher risk of corneal graft rejection from prior traumatic endothelial damage","Higher risk of postoperative cystoid macular oedema from","Higher risk of postoperative endophthalmitis from traumatised conjunctival tissue","Higher risk of IOL calcification from altered aqueous humour composition post-trauma","Higher risk of intraoperative suprachoroidal haemorrhage from abnormal choroidal vasculature"],a:4,e:"Angle recession indicates prior significant blunt trauma; the ciliary muscle tear and associated disruption of uveal vasculature create abnormal choroidal vessel fragility; intraoperative IOP fluctuations during phacoemulsification in such an eye carry higher risk of expulsive suprachoroidal haemorrhage compared to non-traumatised eyes.<br><br>Additional surgical challenges in angle recession eyes include compromised zonular support from traumatic damage, abnormal anterior segment anatomy from the original injury, and coexisting risk of post-phacoemulsification IOP elevation in an eye already predisposed to angle recession glaucoma.<br><br>Corneal graft rejection (A) is irrelevant without keratoplasty; postoperative endophthalmitis (C) relates to wound integrity not conjunctival trauma history; IOL calcification (D) is material-related not trauma-related; cystoid macular oedema (B) is a genuine risk but not the most specific risk unique to angle recession eyes.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which of the following best describes the appearance of ectopia lentis on retroillumination during slit-lamp examination?",o:["A white dense central opacity with radiating spoke-like cortical opacities","An oil droplet reflex visible centrally within the displaced lens substance","A multicoloured","A golden-brown stellate anterior subcapsular opacity beneath the lens capsule","A dark aphakic crescent at the pupil margin with lens edge and zonules visible"],a:4,e:"Retroillumination using the red reflex reveals a dark aphakic crescent at the pupil margin corresponding to the zone of the pupil not covered by the subluxated lens; the lens equator appears as a curved edge within the pupillary aperture, and in Marfan syndrome intact zonular fibres are visible as fine lines extending from the equator.<br><br>This retroillumination appearance directly quantifies the degree and direction of subluxation; a small aphakic crescent indicates mild subluxation while a large crescent crossing the visual axis indicates significant displacement; visible zonular fibres in the crescent specifically favour Marfan syndrome over homocystinuria where zonules are ruptured and absent.<br><br>White central opacity with spokes (A) describes mature cortical cataract; oil droplet reflex (B) is pathognomonic of galactosaemia and Alport anterior lenticonus; golden-brown anterior subcapsular opacity (D) describes chlorpromazine deposits; multicoloured iridescent reflex (C) describes Christmas tree cataract of myotonic dystrophy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following is the most important reason for using a limbal approach when removing a lens dislocated into the anterior chamber?",o:["The limbal approach provides superior visualisation of the posterior segment structures","The limbal approach avoids vitreous traction on the retina from pars plana entry","The limbal approach directly accesses the anterior chamber where the lens resides","The pars plana approach carries higher endophthalmitis risk in ocular trauma cases","The limbal approach better preserves the anterior hyaloid face during"],a:2,e:"The limbal approach provides direct anterior access to a lens dislocated into the anterior chamber, allowing controlled removal without unnecessarily entering the posterior segment and disrupting the vitreous in an eye where the posterior segment may be uninvolved and intact.<br><br>A pars plana approach to an anteriorly dislocated lens would require negotiating through the entire vitreous cavity to reach an anteriorly positioned lens, introducing unnecessary posterior segment risks; the limbal approach is the anatomically logical and surgically safest route for anteriorly dislocated lenses specifically.<br><br>Better posterior segment visualisation (A) is not an advantage of the limbal approach for anterior lens dislocation; retinal traction from pars plana entry (B) is a secondary consideration not the primary reason; endophthalmitis risk difference (D) is not the rationale for approach selection; preserving the anterior hyaloid face (E) is a secondary benefit not the primary reason.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which of the following best summarises the key differences between ectopia lentis in Marfan syndrome and homocystinuria across direction, zonular status, inheritance, systemic risk, and surgical approach?",o:["Both cause superotemporal dislocation; Marfan is recessive; homocystinuria is dominant; both need pars plana lensectomy","Marfan causes inferotemporal dislocation with intact zonules and is autosomal recessive in inheritance","Both conditions cause inferonasal dislocation with ruptured","Marfan causes inferonasal dislocation with ruptured zonules; homocystinuria causes superotemporal dislocation; both use same surgical approach","Marfan causes superotemporal dislocation with intact zonules, dominant, cardiovascular risk, anterior segment surgery feasible; homocystinuria causes inferonasal dislocation, ruptured zonules, recessive, thromboembolic risk, pars plana preferred"],a:4,e:"This comprehensive comparison encapsulates the most clinically important distinguishing features of the two most commonly examined causes of ectopia lentis; superotemporal intact-zonule dislocation in autosomal dominant Marfan syndrome with cardiovascular risk contrasts precisely with inferonasal ruptured-zonule dislocation in autosomal recessive homocystinuria with thromboembolic risk.<br><br>The surgical implications follow directly from the zonular status; intact zonules in Marfan allow capsular bag surgery with capsular tension ring support, while absent ruptured zonules in homocystinuria mandate pars plana lensectomy with vitrectomy and scleral-fixated IOL; perioperative thromboembolic prophylaxis is mandatory in homocystinuria but not in Marfan.<br><br>All other options (A, B, D, E) contain factual errors in at least one of the five comparison domains, making them definitively incorrect; this question tests integrated knowledge across the entire ectopia lentis topic requiring recall, understanding, and clinical application simultaneously.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 14-year-old tall boy presents with bilateral superotemporal lens subluxation, arachnodactyly, and high-arched palate. Which systemic disorder is most likely?",o:["Homocystinuria","Ehlers-Danlos syndrome","Wilson disease","Weill-Marchesani syndrome","Marfan syndrome"],a:4,e:"Marfan syndrome classically produces bilateral superotemporal ectopia lentis due to fibrillin-related zonular weakness.<br><br>Homocystinuria (A) more commonly causes inferonasal lens subluxation rather than superotemporal displacement.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which type of cataract is most strongly associated with prolonged corticosteroid therapy?",o:["Nuclear cataract","Cortical cataract","Rosette cataract","Lamellar cataract","Posterior subcapsular cataract"],a:4,e:"Posterior subcapsular cataract commonly develops after long-term corticosteroid exposure and may significantly impair vision early.<br><br>Of associations with steroids, diabetes, and uveitis.<br><br>Rosette cataract (C) is classically traumatic in origin.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A child presents with inferonasal lens dislocation, intellectual disability, and thromboembolic tendency. Which condition is most likely?",o:["Marfan syndrome","Homocystinuria","Wilson disease","Stickler syndrome","Alport syndrome"],a:1,e:"Homocystinuria classically produces inferonasal ectopia lentis along with developmental delay and increased thromboembolic risk.<br><br>Marfan syndrome (A) usually causes superotemporal lens subluxation rather than inferonasal displacement.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract morphology is classically associated with blunt trauma?",o:["Coronary cataract","Cerulean cataract","Rosette cataract","Sutural cataract","Blue-dot cataract"],a:2,e:"Blunt trauma produces characteristic stellate or rosette-shaped posterior cortical opacities due to lens fiber disruption.<br><br>Cerulean cataract (B) is congenital and unrelated to trauma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which metabolic disorder is classically associated with sunflower cataract?",o:["Galactosemia","Diabetes mellitus","Hyperparathyroidism","Homocystinuria","Wilson disease"],a:4,e:"Copper deposition within the lens in Wilson disease may produce sunflower cataract and Kayser-Fleischer rings.<br><br>Galactosemia (A) is associated with oil-droplet cataract rather than sunflower cataract.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with ectopia lentis develops sudden painful rise in intraocular pressure due to pupillary block. What is the likely mechanism?",o:["Corneal endothelial failure","Retinal ischemia","Forward lens displacement","Vitreous hemorrhage","Choroidal detachment"],a:2,e:"Anteriorly displaced subluxated lens may obstruct aqueous flow through the pupil, precipitating pupillary block glaucoma.<br><br>Retinal ischemia (B) does not directly produce pupillary block glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which cataract surgery technique is currently considered the standard worldwide procedure?",o:["Couching","Intracapsular extraction","Discission","Phacoemulsification","Linear extraction"],a:3,e:"Phacoemulsification uses ultrasonic fragmentation of the lens nucleus through a small incision with rapid visual rehabilitation.<br><br>It is currently the preferred cataract extraction technique globally.<br><br>Intracapsular extraction (B) is now rarely performed except in selected complicated cases.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disorder is associated with microspherophakia and inferior lens dislocation?",o:["Marfan syndrome","Retinitis pigmentosa","Neurofibromatosis","Sturge-Weber syndrome","Weill-Marchesani syndrome"],a:4,e:"Weill-Marchesani syndrome is characterized by microspherophakia, short stature, brachydactyly, and ectopia lentis.<br><br>The spherical lens predisposes to pupillary block glaucoma.<br><br>Marfan syndrome (A) usually features tall stature and superotemporal lens subluxation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom is most characteristic of posterior subcapsular cataract?",o:["Peripheral field constriction","Severe glare and difficulty in bright light","Sudden painless blindness","Flashes and floaters","Diplopia only in darkness"],a:1,e:"Posterior subcapsular cataract scatters central light rays and therefore causes disproportionate glare and near-vision difficulty.<br><br>Peripheral field constriction (A) is more suggestive of glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which congenital cataract commonly causes severe visual deprivation requiring early surgery?",o:["Sutural cataract","Blue-dot cataract","Cerulean cataract","Coronary cataract","Total congenital cataract"],a:4,e:"Dense congenital cataracts obstruct visual maturation and may rapidly cause irreversible amblyopia if untreated.<br><br>Early diagnosis and prompt surgery are heavily emphasized in pediatric ophthalmology recalls.<br><br>Blue-dot cataracts (B) are usually visually insignificant incidental findings.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which lens abnormality is most likely in a patient with Marfan syndrome?",o:["Inferonasal ectopia lentis","Posterior lenticonus","Aphakia","Microspherophakia","Superotemporal ectopia lentis"],a:4,e:"Marfan syndrome classically produces bilateral superotemporal lens displacement due to zonular fibrillin defects.<br><br>Microspherophakia (D) is more typical of Weill-Marchesani syndrome.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which postoperative cataract complication presents with painless gradual visual deterioration months later?",o:["Endophthalmitis","Suprachoroidal hemorrhage","Posterior capsule opacification","Iris prolapse","Expulsive hemorrhage"],a:2,e:"Posterior capsule opacification occurs due to residual lens epithelial proliferation after cataract surgery.<br><br>Endophthalmitis (A) causes painful inflammatory visual loss rather than gradual painless decline. Posterior capsular opacification as the commonest late complication is a heavily emphasised fact.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which condition is classically associated with inferonasal ectopia lentis?",o:["Marfan syndrome","Retinitis pigmentosa","Pseudoexfoliation syndrome","Wilson disease","Homocystinuria"],a:4,e:"Homocystinuria produces inferonasal lens displacement due to abnormal zonular connective tissue.<br><br>Marfan syndrome (A) usually causes superotemporal displacement.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract is associated with infrared radiation exposure in glass workers?",o:["Lamellar cataract","Rosette cataract","Glassblower's cataract","Cerulean cataract","Coronary cataract"],a:2,e:"Chronic infrared radiation exposure damages the lens and produces posterior cortical lens opacities called glassblower's cataract.<br><br>Rosette cataract (B) is traumatic rather than occupational.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which complication is particularly associated with microspherophakia?",o:["Retinal detachment","Corneal ulceration","Endophthalmitis","Optic neuritis","Pupillary block glaucoma"],a:4,e:"Microspherophakia increases lens convexity and anterior displacement, predisposing to pupillary block glaucoma.<br><br>This association is classically tested with Weill-Marchesani syndrome.<br><br>Retinal detachment (A) is not the primary complication of microspherophakia.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which congenital infection is classically associated with cataract, deafness, and cardiac anomalies?",o:["Toxoplasmosis","Cytomegalovirus","Herpes simplex","Syphilis","Rubella"],a:4,e:"Congenital rubella syndrome classically presents with cataract, sensorineural deafness, and congenital heart disease.<br><br>Maternal first-trimester infection carries the highest fetal risk.<br><br>Toxoplasmosis (A) more commonly causes chorioretinitis rather than congenital cataract triad.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is most essential before cataract surgery for intraocular lens calculation?",o:["Gonioscopy","Biometry","Schirmer testing","Fluorescein angiography","Visual field analysis"],a:1,e:"Biometry measures axial length and corneal curvature to determine appropriate intraocular lens power.<br><br>Accurate IOL calculation is critical for postoperative refractive success.<br><br>Fluorescein angiography (D) evaluates retinal vasculature rather than lens implant power.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which type of cataract commonly causes \"second sight\"?",o:["Posterior subcapsular cataract","Nuclear sclerosis","Traumatic cataract","Lamellar cataract","Polar cataract"],a:1,e:"Nuclear sclerosis increases lens refractive index and induces myopic shift, temporarily improving near vision in elderly patients.<br><br>Posterior subcapsular cataract (A) more commonly causes glare and reading difficulty.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which treatment is standard for visually significant posterior capsule opacification?",o:["Repeat phacoemulsification","Trabeculectomy","Nd:YAG laser capsulotomy","Vitrectomy","Penetrating keratoplasty"],a:2,e:"Nd:YAG capsulotomy creates a central opening in the opacified posterior capsule and rapidly restores visual clarity.<br><br>Vitrectomy (D) is unnecessary because the opacity lies in the capsule rather than vitreous cavity.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which statement regarding ectopia lentis is most accurate?",o:["Marfan syndrome causes inferonasal lens displacement","Homocystinuria commonly causes superotemporal displacement","Ectopia lentis always requires surgery immediately","Marfan syndrome classically causes superotemporal lens subluxation","Microspherophakia is unrelated to glaucoma"],a:3,e:"Marfan syndrome produces superotemporal lens displacement due to fibrillin-related zonular weakness.<br><br>Homocystinuria (B) classically causes inferonasal displacement. Microspherophakia (E) strongly predisposes to pupillary block glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A young patient with ectopia lentis presents with mental retardation and recurrent thromboembolic episodes. Which diagnosis is most likely?",o:["Marfan syndrome","Alport syndrome","Weill-Marchesani syndrome","Stickler syndrome","Homocystinuria"],a:4,e:"Homocystinuria classically presents with inferonasal ectopia lentis, developmental delay, skeletal abnormalities, and thromboembolic tendency.<br><br>Marfan syndrome (A) causes superotemporal lens subluxation and usually normal intelligence.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract is classically associated with blunt trauma?",o:["Coronary cataract","Blue-dot cataract","Sutural cataract","Lamellar cataract","Rosette cataract"],a:4,e:"Blunt ocular trauma produces characteristic rosette-shaped posterior cortical lens opacities due to shock-wave injury to lens fibers.<br><br>Lamellar cataract (D) is congenital rather than traumatic.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which cataract type is most commonly associated with prolonged corticosteroid therapy?",o:["Posterior subcapsular cataract","Nuclear sclerosis","Traumatic cataract","Coronary cataract","Cerulean cataract"],a:0,e:"Posterior subcapsular cataract is strongly associated with long-term steroid use, diabetes mellitus, and chronic uveitis.<br><br>They produce severe glare symptoms early.<br><br>Cerulean cataracts (E) are congenital developmental opacities.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A tall thin patient with arachnodactyly and bilateral superotemporal lens subluxation most likely has:",o:["Homocystinuria","Marfan syndrome","Wilson disease","Weill-Marchesani syndrome","Retinitis pigmentosa"],a:1,e:"Marfan syndrome classically causes bilateral superotemporal ectopia lentis due to fibrillin-related zonular weakness.<br><br>Homocystinuria (A) usually causes inferonasal lens displacement rather than superotemporal subluxation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which congenital cataract commonly requires urgent surgery to prevent amblyopia?",o:["Blue-dot cataract","Coronary cataract","Sutural cataract","Dense bilateral congenital cataract","Cerulean cataract"],a:3,e:"Dense congenital cataracts prevent normal visual development and rapidly cause irreversible deprivation amblyopia if untreated.<br><br>Sutural cataracts (C) are often visually insignificant.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which lens abnormality is classically associated with Weill-Marchesani syndrome?",o:["Posterior lenticonus","Aphakia","Traumatic lens rupture","Posterior polar cataract","Microspherophakia"],a:4,e:"Weill-Marchesani syndrome is characterized by short stature, brachydactyly, microspherophakia, and ectopia lentis.<br><br>The spherical lens predisposes to pupillary block glaucoma.<br><br>Posterior lenticonus (A) is unrelated to Weill-Marchesani syndrome.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract is associated with infrared radiation exposure?",o:["Rosette cataract","Traumatic cataract","Lamellar cataract","PSC cataract","Glassblower's cataract"],a:4,e:"Chronic infrared exposure damages the lens and produces characteristic posterior cortical opacities known as glassblower's cataract.<br><br>Rosette cataract (A) is traumatic rather than occupational.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which symptom is most characteristic of posterior subcapsular cataract?",o:["Severe glare in bright light","Sudden complete blindness","Peripheral visual field loss","Floaters and flashes","Painful red eye"],a:0,e:"Posterior subcapsular cataracts scatter central light rays and therefore cause disproportionate glare and near-vision impairment.<br><br>Patients often report difficulty driving at night despite relatively preserved visual acuity initially.<br><br>Peripheral field loss (C) is characteristic of glaucoma rather than cataract.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which postoperative cataract complication is treated with Nd:YAG laser capsulotomy?",o:["Endophthalmitis","Posterior capsule opacification","Corneal ulcer","Suprachoroidal hemorrhage","Iris prolapse"],a:1,e:"Posterior capsule opacification develops due to proliferation of residual lens epithelial cells after cataract surgery.<br><br>Nd:YAG laser capsulotomy creates a central opening restoring visual clarity. Nd:YAG capsulotomy for posterior capsular opacification is a recurring management point.<br><br>Endophthalmitis (A) requires urgent antimicrobial therapy rather than laser treatment.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which direction of lens displacement is classically associated with homocystinuria?",o:["Superotemporal","Central displacement","Inferotemporal","Superior only","Inferonasal"],a:4,e:"Homocystinuria classically causes inferonasal lens subluxation because of defective zonular connective tissue.<br><br>Marfan syndrome typically produces superotemporal displacement rather than inferonasal displacement.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract surgery technique preserves the posterior capsule?",o:["Intracapsular cataract extraction","Couching","Extracapsular cataract extraction","Discission","Lens aspiration only without capsule preservation"],a:2,e:"Extracapsular extraction removes the lens nucleus and cortex while preserving the posterior capsule for IOL support.<br><br>Posterior capsule preservation reduces vitreous-related complications.<br><br>Intracapsular extraction (A) removes the entire capsule along with the lens.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which metabolic disorder is associated with sunflower cataract?",o:["Diabetes mellitus","Galactosemia","Hyperparathyroidism","Homocystinuria","Wilson disease"],a:4,e:"Copper deposition within the lens in Wilson disease may produce characteristic sunflower cataract and Kayser-Fleischer rings.<br><br>Galactosemia (B) produces oil-droplet cataracts rather than sunflower cataracts.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract type commonly produces \"second sight\"?",o:["Posterior subcapsular cataract","Nuclear sclerosis","Lamellar cataract","Traumatic cataract","Posterior polar cataract"],a:1,e:"Nuclear sclerosis increases refractive index of the lens nucleus causing acquired myopia and temporary improvement of near vision.<br><br>Posterior subcapsular cataracts (A) usually worsen near vision rather than improve it.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which complication is particularly associated with microspherophakia?",o:["Retinal detachment","Optic neuritis","Pupillary block glaucoma","Corneal ulceration","Endophthalmitis"],a:2,e:"Microspherophakia causes forward displacement of the spherical lens, predisposing to pupillary block and angle closure.<br><br>This association is classically tested alongside Weill-Marchesani syndrome.<br><br>Retinal detachment (A) is not the primary complication of microspherophakia.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which congenital infection classically causes cataract, deafness, and cardiac defects?",o:["Cytomegalovirus","Toxoplasmosis","Syphilis","Herpes simplex","Rubella"],a:4,e:"Congenital rubella syndrome produces cataract, congenital heart disease, and sensorineural deafness.<br><br>Maternal first-trimester infection is especially dangerous for fetal ocular development.<br><br>Toxoplasmosis (B) more commonly causes chorioretinitis rather than congenital cataract triad.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation is most essential before cataract surgery for IOL calculation?",o:["Gonioscopy","Fluorescein angiography","Hess charting","Visual field analysis","Biometry"],a:4,e:"Biometry measures axial length and corneal power to calculate intraocular lens power accurately.<br><br>Correct IOL calculation is critical for postoperative refractive success.<br><br>Visual field analysis (D) evaluates optic nerve function rather than lens implant power.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which lens-induced glaucoma occurs due to leakage of lens proteins from hypermature cataract?",o:["Pigmentary glaucoma","Neovascular glaucoma","Phacolytic glaucoma","Juvenile glaucoma","Congenital glaucoma"],a:2,e:"Leakage of high-molecular-weight lens proteins from hypermature cataract obstructs trabecular outflow causing phacolytic glaucoma.<br><br>Pigmentary glaucoma (A) results from pigment dispersion rather than lens protein leakage.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract is usually visually insignificant and often discovered incidentally?",o:["Total congenital cataract","Rosette cataract","Morgagnian cataract","PSC cataract","Blue-dot cataract"],a:4,e:"Blue-dot cataracts are small punctate congenital opacities that generally do not significantly impair vision.<br><br>Recognition of visually insignificant congenital lens opacities is important clinically.<br><br>Morgagnian cataracts (C) are advanced senile cataracts with significant visual impairment.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which modern cataract surgery technique uses ultrasonic emulsification of the nucleus?",o:["Couching","Intracapsular extraction","Linear extraction","Discission","Phacoemulsification"],a:4,e:"Phacoemulsification fragments the nucleus using ultrasound through a small incision with rapid visual recovery.<br><br>It is currently the standard cataract surgery technique worldwide.<br><br>Couching (A) is an obsolete historical technique.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which statement regarding ectopia lentis is most accurate?",o:["Marfan syndrome causes inferonasal displacement","Homocystinuria usually causes superotemporal displacement","Microspherophakia is unrelated to glaucoma","Marfan syndrome classically causes superotemporal lens subluxation","Ectopia lentis never affects vision significantly"],a:3,e:"Marfan syndrome produces superotemporal lens displacement due to fibrillin-related zonular weakness.<br><br>Homocystinuria (B) classically causes inferonasal displacement. Microspherophakia (C) strongly predisposes to pupillary block glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which of the following is the most common ocular complication of ectopia lentis requiring urgent intervention?",o:["Secondary glaucoma from pupil block or trabecular obstruction","Cystoid macular oedema from chronic lens-induced inflammation","Corneal dystrophy from anterior chamber lens contact","Optic atrophy from uncontrolled chronic glaucoma","Choroidal detachment following sudden"],a:0,e:"Secondary glaucoma is the most common urgent complication of ectopia lentis; it arises through pupil block by an anteriorly displaced lens, angle closure from iris-lens diaphragm shift, or trabecular obstruction by lens material.<br><br>The mechanism varies by degree and direction of dislocation; anterior dislocation causes acute angle closure while posterior dislocation may cause open-angle elevation through vitreous prolapse obstructing trabecular outflow.<br><br>Cystoid macular oedema (B) is postoperative; corneal dystrophy (C) is unrelated; optic atrophy (D) is a late sequela of uncontrolled glaucoma; choroidal detachment (E) follows hypotony rather than lens dislocation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with ectopia lentis achieves better corrected vision through the aphakic zone than the phakic zone. What does this indicate?",o:["The lens has dislocated completely into the vitreous cavity","The subluxated lens induces sufficient irregular astigmatism making the phakic zone optically inferior","Central corneal decompensation has occurred from lens contact","Amblyopia has selectively developed in the phakic optical zone","Optic nerve damage from chronic glaucoma has"],a:1,e:"When vision through the aphakic zone exceeds the phakic portion, the subluxated lens is inducing irregular astigmatism or lenticular myopia sufficient to degrade image quality beyond what aphakic correction achieves through the clear zone.<br><br>This finding guides management; if the aphakic zone provides better corrected vision, optical rehabilitation focuses on correcting the aphakic portion, making surgical lens removal more justifiable to eliminate the optically degrading phakic contribution.<br><br>Posterior dislocation into vitreous (A) would eliminate the phakic zone entirely; central corneal decompensation (C) would reduce vision through all zones equally; amblyopia (D) affects the entire visual pathway; optic nerve damage (E) causes field loss unrelated to zone comparison.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Traumatic lens subluxation most commonly occurs following blunt trauma due to rupture of zonular fibres at which location?",o:["Posterior zonular insertion near the pars plana region","The weakest midportion of the zonular fibre length","The anterior zonular insertion onto the lens capsule","Simultaneously around the entire circumference of the zonule","Only at the direct site of blunt impact on the globe"],a:2,e:"Blunt trauma transmits a compressive force that momentarily expands the globe equatorially; the resulting stretch force is maximal at the zonular insertion onto the anterior lens capsule, which is the weakest attachment point and most vulnerable to traumatic rupture.<br><br>The degree of zonular rupture determines whether subluxation or complete dislocation occurs; less than 180 degrees of rupture causes subluxation while more extensive rupture results in complete dislocation either anteriorly or posteriorly into the vitreous.<br><br>Posterior zonular insertion (A) is more robust; midportion rupture (B) is not the primary failure site; simultaneous circumferential rupture (D) would cause immediate complete dislocation; rupture only at the impact site (E) is incorrect as force transmits circumferentially.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A Vossius ring on the anterior lens capsule following blunt trauma indicates which finding?",o:["Rupture of the posterior lens capsule from concussive force","Calcium deposits accumulating on the anterior lens surface","Subluxation of the lens with associated zonular rupture","Iris pigment epithelium transferred to the lens at the pupillary margin","Anterior"],a:3,e:"Vossius ring is a circular pigmented ring deposited on the anterior lens capsule following blunt ocular trauma; it results from forceful iris-lens contact, transferring iris pigment epithelium onto the capsule in a ring corresponding to the pupillary margin.<br><br>The ring itself does not significantly impair vision but marks significant blunt trauma; its presence should prompt thorough examination for angle recession, iridodialysis, zonular damage, vitreous haemorrhage, and retinal tears. The Vossius ring as a pigment imprint from blunt trauma is a classic eponymous sign worth instant recognition.<br><br>Posterior capsule rupture (A) causes vitreous prolapse without a pigment ring; calcium deposits (B) cause anterior capsular plaques; lens subluxation (C) causes iridodonesis and aphakic crescent; anterior subcapsular cataract (E) presents as a stellate or rosette opacity.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which investigation best confirms a biochemical diagnosis of homocystinuria in a child with suspected ectopia lentis?",o:["Slit-lamp examination identifying the direction of lens displacement","Serum copper and caeruloplasmin levels excluding Wilson disease","Echocardiography measuring aortic root diameter for Marfan assessment","Electroretinography assessing baseline retinal function before surgery","Urine nitroprusside test and plasma homocysteine level measurement"],a:4,e:"The urine nitroprusside test detects excess urinary homocysteine, turning red-purple in positive cases; plasma total homocysteine measurement provides quantitative confirmation and guides treatment response monitoring; together they establish the biochemical diagnosis.<br><br>Newborn screening using tandem mass spectrometry detects elevated methionine enabling presymptomatic diagnosis; early treatment with pyridoxine, dietary restriction, and betaine prevents or delays the ocular, neurological, and thromboembolic complications.<br><br>Slit-lamp examination (A) identifies lens position not aetiology; serum copper (B) diagnoses Wilson or Menkes disease; echocardiography (C) assesses Marfan cardiovascular features; electroretinography (D) assesses retinal function unrelated to this diagnosis.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which cardiovascular investigation is most essential before any surgical planning in a patient with Marfan syndrome presenting with ectopia lentis?",o:["Echocardiography to assess aortic root diameter before anaesthesia","Electrocardiography to detect arrhythmias associated with Marfan syndrome","Coronary angiography to exclude ischaemic disease before general anaesthesia","Carotid Doppler ultrasound assessing cerebrovascular disease risk","Chest X-ray screening for cardiomegaly"],a:0,e:"Aortic root dilatation is the most life-threatening cardiovascular manifestation of Marfan syndrome; echocardiography to measure aortic root diameter is mandatory before any surgical intervention as anaesthesia-related haemodynamic changes can precipitate aortic dissection in patients with significant dilatation.<br><br>Beta-blocker therapy to reduce aortic wall stress is initiated when dilatation is identified; elective aortic root repair is recommended when diameter exceeds 5 cm; multidisciplinary cardiology input is essential for perioperative risk stratification. Mandatory cardiovascular assessment before surgery in Marfan is a recurring multidisciplinary point.<br><br>ECG (B) detects arrhythmias but not the primary Marfan cardiovascular risk; coronary angiography (C) is invasive and not indicated here; carotid Doppler (D) assesses cerebrovascular disease; chest X-ray (E) is insufficiently sensitive for aortic root measurement.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which of the following correctly pairs the condition with its specific lens finding?",o:["Marfan syndrome causing oil droplet cataract on retroillumination","Weill-Marchesani causing superotemporal ectopia lentis with intact","Homocystinuria causing sunflower cataract from copper deposition","Wilson disease causing anterior lenticonus from type IV collagen defect","Alport syndrome causing pathognomonic anterior lenticonus"],a:4,e:"Anterior lenticonus is pathognomonic of Alport syndrome; the forward conical protrusion of the central anterior lens surface results from localised type IV collagen deficiency in the anterior lens capsule, a direct consequence of COL4A gene mutations.<br><br>Each condition has a distinct lens signature; Marfan causes superotemporal ectopia lentis; homocystinuria causes inferonasal dislocation; Wilson disease causes sunflower cataract; Weill-Marchesani causes microspherophakia with inferior subluxation.<br><br>Oil droplet cataract (A) is galactosaemia; sunflower cataract (C) is Wilson disease not homocystinuria; anterior lenticonus (D) is Alport not Wilson disease; superotemporal ectopia lentis (B) is Marfan syndrome not Weill-Marchesani.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Phacodonesis differs from iridodonesis in that phacodonesis specifically indicates which finding?",o:["Phacodonesis indicates corneal endothelial pathology from lens contact","Iridodonesis occurs exclusively after cataract surgery not spontaneously","Both terms describe identical signs","Phacodonesis occurs only in Marfan syndrome not other zonulopathies","Phacodonesis is tremulousness of the lens; iridodonesis is tremulousness of the iris"],a:4,e:"Phacodonesis refers to wobbling of the crystalline lens with rapid eye movements on slit-lamp; iridodonesis is similar oscillation of the iris from loss of posterior lens support; both indicate zonular compromise of increasing severity.<br><br>Phacodonesis often precedes iridodonesis; together they serve as reliable clinical indicators of zonular instability requiring modified surgical technique including capsular tension ring use and reduced fluidics.<br><br>Corneal pathology (A) does not cause phacodonesis; iridodonesis is not exclusively postoperative (B); phacodonesis occurs in all causes of zonular weakness not only Marfan (D); they are distinct signs affecting different structures (C).<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which is the most appropriate refractive correction for a child with unilateral aphakia following lensectomy for traumatic ectopia lentis?",o:["High-plus aphakic spectacle lenses for full field correction","Multifocal spectacle lenses addressing both distance and near vision","Piggyback IOL system adjusting refractive power postoperatively","Extended wear silicone contact lens avoiding aniseikonia","Epikeratophakia to restore corneal refractive power permanently"],a:3,e:"Extended wear silicone contact lenses are preferred for unilateral paediatric aphakia following lensectomy; they avoid the severe aniseikonia and optical distortions of high-plus spectacle lenses, allowing full field correction with better optical quality.<br><br>Compliance with insertion and removal is managed by parents; regular follow-up ensures appropriate power adjustments as the eye grows; patching of the fellow eye must accompany contact lens wear to treat the invariably coexisting amblyopia.<br><br>High-plus aphakic spectacles (A) cause significant aniseikonia in unilateral cases; multifocal spectacles (B) do not address aniseikonia; piggyback IOL (C) is used for secondary power adjustment; epikeratophakia (E) is rarely performed in modern practice.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which condition features ectopia lentis with tall stature, arachnodactyly, and inferonasal lens dislocation with ruptured zonules?",o:["Marfan syndrome with superotemporal dislocation and intact visible zonules","Stickler syndrome with presenile cataract and optically empty vitreous","Weill-Marchesani syndrome with inferior dislocation and short stature","Ehlers-Danlos syndrome with connective tissue fragility and joint laxity","Homocystinuria with cystathionine beta-synthase"],a:4,e:"Homocystinuria produces a Marfanoid phenotype with tall stature and arachnodactyly; however, the lens dislocates inferonasally with completely ruptured invisible zonules, distinguishing it critically from Marfan syndrome where lens displaces superotemporally with intact visible zonules.<br><br>The metabolic nature means systemic complications of thromboembolism and intellectual disability accompany the skeletal and ocular features; this combination of Marfanoid appearance with inferior dislocation and thromboembolic history is a classic high-yield distinguishing scenario.<br><br>Marfan syndrome (A) causes superotemporal dislocation with intact zonules; Stickler syndrome (B) causes myopia and retinal detachment without classic ectopia lentis; Weill-Marchesani (C) causes inferior dislocation but with short stature; Ehlers-Danlos (D) causes ectopia lentis without the Marfanoid habitus.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Retinal detachment in ectopia lentis is most significantly increased by which specific factor?",o:["Concurrent high axial myopia with peripheral retinal thinning and lattice degeneration","Superotemporal direction of lens displacement in Marfan syndrome","Use of cycloplegic drops during conservative management of subluxation","Presence of nuclear sclerosis in the subluxated lens substance","Age of onset of ectopia lentis occurring"],a:0,e:"High axial myopia in Marfan syndrome produces peripheral retinal thinning, lattice degeneration, and vitreous syneresis; these changes dramatically increase rhegmatogenous retinal detachment risk, compounded by vitreous disruption from zonular instability and surgical manipulation.<br><br>Preoperative peripheral retinal examination with prophylactic treatment of lattice degeneration before lens surgery is essential; patients must be counselled that lifetime retinal detachment risk in Marfan syndrome with high myopia is substantially elevated regardless of lens surgery status.<br><br>Superotemporal lens displacement direction (B) is not a retinal risk factor; cycloplegic drops (C) do not increase detachment risk; nuclear sclerosis (D) does not predispose to detachment; age of onset (E) influences amblyopia risk not retinal detachment.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which systemic feature is shared by both Marfan syndrome and homocystinuria making clinical differentiation difficult on phenotype alone?",o:["Intellectual disability and neurological impairment specific to homocystinuria","Tall stature, arachnodactyly, and high arched palate present in both conditions","Aortic root dilatation specific to Marfan syndrome cardiovascular phenotype","Thromboembolic events specific to homocystinuria due to platelet hyperaggregability","Sensorineural"],a:1,e:"Both Marfan syndrome and homocystinuria produce a Marfanoid phenotype with tall stature, long limbs, arachnodactyly, and high arched palate; this skeletal similarity makes distinction impossible on phenotype alone, necessitating biochemical testing.<br><br>The urine nitroprusside test and plasma homocysteine measurement differentiate homocystinuria from Marfan; echocardiography identifies aortic root dilatation in Marfan; the distinction is clinically critical because perioperative thromboembolic risk and anaesthetic implications differ dramatically.<br><br>Intellectual disability (A) and thromboembolism (D) occur only in homocystinuria; aortic root dilatation (C) is specific to Marfan syndrome; sensorineural deafness (E) is specific to Alport syndrome with renal involvement.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which modification reduces rhexis runout risk during capsulorhexis in a patient with significant Marfan syndrome zonular weakness?",o:["Making the rhexis as large as possible to decompress the capsular bag equator","Performing a posterior rhexis instead of standard anterior capsulorhexis","Using smaller rhexis with slow controlled tearing and good viscoelastic support","Using scissors rather than a cystotome or forceps for better control","Performing rhexis under air rather than"],a:2,e:"In zonular weakness, the capsular bag lacks normal posterior counter-traction; the anterior capsule stretches and rhexis can run peripherally toward the equator if tension is not carefully controlled; a smaller rhexis with gentle tearing under good viscoelastic support minimises this risk.<br><br>Maintaining anterior chamber depth throughout prevents surge-induced shallowing destabilising the bag; iris hooks provide additional stabilisation; CTR placement after rhexis completion further stabilises the bag for subsequent steps. Capsulorhexis modifications reducing runout in a weak-zonule eye are an emphasised surgical pearl.<br><br>A large rhexis (A) increases runout risk in a floppy bag; posterior rhexis (B) is performed only in specific paediatric cases; scissors (D) provide less controlled tearing than continuous curvilinear technique; rhexis under air (E) provides poor visualisation and no capsular support.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which of the following correctly identifies the gene and chromosome involved in autosomal recessive Weill-Marchesani syndrome?",o:["FBN1 on chromosome 15q21 causing autosomal dominant Marfan phenotype","CBS on chromosome 21q22 causing homocystinuria with thromboembolism","OCRL1 on chromosome Xq26 causing Lowe oculocerebrorenal syndrome","ADAMTS10 on chromosome 19p13 causing Weill-Marchesani recessive form","PAX6 on chromosome 11p13 causing aniridia with foveal hypoplasia"],a:3,e:"The autosomal recessive form of Weill-Marchesani syndrome is caused by mutations in ADAMTS10 on chromosome 19p13; ADAMTS10 encodes a metalloprotease involved in fibrillin microfibril assembly, explaining shared features with Marfan syndrome which involves fibrillin-1 directly.<br><br>Loss of ADAMTS10 function disrupts fibrillin microfibril organisation, producing short stature, brachydactyly, joint stiffness, and microspherophakia; the autosomal dominant form caused by FBN1 mutations produces an overlapping phenotype reflecting the functional connection between both proteins.<br><br>FBN1 chromosome 15q (A) is autosomal dominant Weill-Marchesani or Marfan; CBS chromosome 21q (B) is homocystinuria; OCRL1 Xq26 (C) is Lowe syndrome; PAX6 chromosome 11p (E) causes aniridia.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient presents with lens subluxation, seizures, fair skin, and elevated urinary sulphite on metabolic screening. What is the most likely diagnosis?",o:["Homocystinuria detected by positive urine nitroprusside test","Hyperlysinaemia with lysine accumulation and mild connective tissue involvement","Marfan syndrome from FBN1 gene mutation on chromosome 15q21","Galactosaemia presenting with oil droplet cataract and reducing urine substances","Molybdenum cofactor deficiency causing functional"],a:4,e:"Molybdenum cofactor deficiency causes functional sulphite oxidase deficiency; elevated urinary sulphite combined with ectopia lentis, seizures, and fair skin is the characteristic presentation; fair skin results from impaired melanin synthesis due to sulphite accumulation affecting tyrosinase activity.<br><br>The condition is autosomal recessive and usually fatal in infancy in severe forms; the urinary sulphite dipstick test is a rapid bedside screening tool turning positive in affected patients; a cyclic pyranopterin monophosphate substitute has shown benefit in specific subtypes.<br><br>Homocystinuria (A) is detected by nitroprusside test not sulphite dipstick; hyperlysinaemia (B) involves lysine not sulphite; Marfan syndrome (C) has no metabolic urinary abnormality; galactosaemia (D) presents with reducing substances not elevated sulphite.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which term best describes partial lens displacement with residual zonular attachment as distinct from complete dislocation?",o:["Subluxation implying partial displacement with residual zonular fibres intact","Luxation implying partial displacement with some zonular fibres remaining","Phacodonesis referring to horizontal lens displacement without vertical component","Iridodonesis referring to partial lens displacement with iris involvement","Ectopia lentis"],a:0,e:"Subluxation implies partial zonular rupture with the lens remaining in the posterior chamber but decentred; some zonular fibres remain intact providing residual support, explaining why the lens does not fall freely into the anterior chamber or vitreous.<br><br>Luxation or complete dislocation implies total zonular rupture with no residual support; the lens is free to migrate anteriorly or posteriorly; this distinction determines surgical approach as subluxation may allow anterior segment surgery while complete luxation usually requires pars plana vitrectomy.<br><br>Luxation refers to complete dislocation not partial displacement (B); phacodonesis describes lens tremulousness not displacement direction (C); iridodonesis describes iris tremulousness not partial lens displacement (D); ectopia lentis refers to all forms of displacement including subluxation (E).<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which finding on anterior segment examination is most specific for pseudoexfoliation syndrome in a patient with early lens subluxation?",o:["Krukenberg spindle on the inferior corneal endothelium from pigment dispersion","Corneal guttata centrally indicating Fuchs endothelial corneal dystrophy","Brown mid-peripheral iris transillumination defects from posterior iris pigment loss","Posterior embryotoxon visible at the limbus suggesting Axenfeld-Rieger syndrome","Pseudoexfoliative material on the anterior lens capsule showing three-zone pattern"],a:4,e:"The classic slit-lamp finding of pseudoexfoliation on the anterior lens capsule is a central grey-white disc, a clear intermediate zone scraped by the iris, and a peripheral granular ring; this three-zone pattern is pathognomonic and visible on dilated examination.<br><br>The intermediate clear zone results from mechanical rubbing of the posterior iris against the anterior capsule as the pupil moves; the material deposits also on zonular fibres, ciliary processes, trabecular meshwork, and corneal endothelium, explaining the associated glaucoma and surgical risks.<br><br>Krukenberg spindle (A) is pigment dispersion syndrome not pseudoexfoliation; brown iris transillumination defects (C) are characteristic of pigment dispersion; posterior embryotoxon (D) is Axenfeld-Rieger syndrome; corneal guttata (B) indicate Fuchs endothelial dystrophy.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which dietary modification forms the cornerstone of long-term medical management to reduce lens dislocation progression in homocystinuria?",o:["Low fat diet with omega-3 supplementation reducing vascular inflammation","High protein diet to support connective tissue and zonular fibre synthesis","High calcium","Low carbohydrate diet to reduce general oxidative stress on zonular fibres","Low methionine diet with cysteine supplementation reducing homocysteine substrate"],a:4,e:"Dietary restriction of methionine reduces substrate availability for homocysteine production; cysteine supplementation compensates for the deficiency caused by the blocked synthetic pathway; together they reduce plasma homocysteine, slowing zonular damage progression.<br><br>Betaine supplementation further reduces homocysteine by promoting remethylation back to methionine; this combined dietary and pharmacological approach also decreases the thromboembolic risk representing the most life-threatening systemic complication.<br><br>Low fat diet (A) has no specific role in homocystinuria; high protein intake (B) would worsen methionine load; low carbohydrate diet (D) does not address the specific metabolic defect; calcium supplementation (C) has no evidence base in zonular strengthening here.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which complication is most specific to intracapsular cataract extraction compared to extracapsular techniques when performed for a dislocated lens?",o:["Posterior capsule opacification from residual lens epithelial cell proliferation","Elschnig pearl formation from equatorial lens epithelial cell migration","Soemmering ring formation from residual equatorial lens epithelial proliferation","Vitreous loss with subsequent retinal detachment and cystoid macular oedema","IOL"],a:3,e:"Intracapsular extraction removes the entire lens including capsule, invariably disrupting the anterior vitreous face; vitreous loss increases the risk of retinal detachment, chronic cystoid macular oedema, and vitreous touch to the corneal endothelium causing decompensation.<br><br>These vitreous-related complications are significantly less common with extracapsular techniques where the preserved posterior capsule maintains the barrier between anterior and posterior segments; this superior safety profile explains why intracapsular extraction has been largely abandoned.<br><br>Posterior capsule opacification (A), Elschnig pearl formation (B), and Soemmering ring (C) all require a residual capsule exclusive to extracapsular techniques; IOL decentration within the bag (E) requires a capsular bag absent in intracapsular surgery.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which is the most appropriate management of a child with bilateral ectopia lentis where the lens is subluxated but partially within the visual axis and vision is 6/18 bilaterally?",o:["Immediate bilateral simultaneous lensectomy to prevent further progression","Nd:YAG laser applied to zonular remnants to complete the dislocation safely","Bilateral patching alternately without optical correction to stimulate each eye","Oral carbonic anhydrase inhibitors to prophylactically reduce intraocular pressure","Optical correction of"],a:4,e:"When a subluxated lens retains a position providing correctable vision of 6/18 or better, conservative optical management is the appropriate first-line approach; cycloplegic refraction guides spectacle or contact lens prescription, and amblyopia treatment is initiated if anisometropic amblyopia is present.<br><br>Regular monitoring every three to six months assesses for progressive subluxation, worsening vision, or secondary glaucoma; deferring surgery avoids anaesthetic risks while preserving the option for lens removal if optical rehabilitation fails.<br><br>Immediate bilateral lensectomy (A) is not justified when vision is correctable; Nd:YAG to zonular remnants (B) is not a recognised treatment; patching without correction (C) would worsen vision; carbonic anhydrase inhibitors (D) are not prophylactically indicated without raised IOP.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which IOL fixation method provides the most stable long-term result following pars plana lensectomy in Marfan syndrome when no capsular support exists?",o:["Scleral-sutured or sutureless scleral-fixated posterior chamber IOL","Anterior chamber angle-fixated IOL implanted behind the cornea","Iris-sutured posterior chamber IOL fixated to the anterior iris surface","In-the-bag IOL with capsular tension ring for equatorial support","Piggyback IOL system implanted within the anterior chamber space"],a:0,e:"Scleral fixation of a posterior chamber IOL places the optic and haptics behind the iris in the anatomically correct position; this avoids corneal endothelial contact risks of anterior chamber IOLs while providing stable long-term centration through direct scleral anchorage.<br><br>Sutureless techniques including glued IOL and flanged haptic intrascleral fixation have reduced suture erosion and late IOL dislocation risks seen with traditional sutured methods; these approaches offer excellent long-term outcomes in complex cases without capsular support.<br><br>Angle-fixated AC IOL (B) risks chronic endothelial loss and UGH syndrome; iris-sutured IOL (C) is less stable long-term; in-the-bag implantation (D) requires a capsular bag absent after complete lensectomy; piggyback in the anterior chamber (E) is not a standard fixation technique.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which skeletal dysplasia associated with ectopia lentis is characterised by short stature and short fingers contrasting with the Marfanoid tall habitus?",o:["Achondroplasia from FGFR3 mutation without associated ectopia lentis","Spondyloepiphyseal dysplasia without classic ectopia lentis association","Osteogenesis imperfecta with bone fragility and blue sclerae","Kniest dysplasia with short trunk dwarfism without lens subluxation","Weill-Marchesani syndrome with brachydactyly and microspherophakia"],a:4,e:"Weill-Marchesani syndrome produces an anti-Marfan phenotype; while Marfan causes tall stature and long digits, Weill-Marchesani causes proportionate short stature, brachydactyly with short stubby fingers, limited joint mobility, and microspherophakia with inferior lens subluxation.<br><br>Despite opposite skeletal phenotypes, both Marfan and Weill-Marchesani involve disruption of fibrillin microfibril biology, reflecting how the same molecular pathway produces diametrically opposite phenotypic outcomes depending on the specific mutation and downstream signalling effects.<br><br>Achondroplasia (A) causes short stature from FGFR3 mutation without ectopia lentis; osteogenesis imperfecta (C) causes bone fragility without classic lens subluxation; Kniest dysplasia (D) causes short trunk dwarfism without lens subluxation; spondyloepiphyseal dysplasia (B) lacks ectopia lentis association.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which pharmacological agent most reduces the rate of aortic root dilatation in Marfan syndrome before elective ophthalmic surgery?",o:["Calcium channel blockers reducing systemic vascular resistance","ACE inhibitors alone targeting the renin-angiotensin system","Beta-blockers such as atenolol or propranolol reducing aortic wall stress","Diuretics reducing systemic fluid load and cardiac preload","Antiplatelet agents"],a:2,e:"Beta-blockers reduce aortic wall stress by lowering heart rate and blood pressure, decreasing the pulsatile mechanical strain on the structurally weak aortic root; long-term therapy slows the rate of aortic root dilatation and reduces the risk of aortic dissection.<br><br>Angiotensin receptor blockers such as losartan have also shown benefit by blocking TGF-beta-mediated aortic remodelling, which is dysregulated due to fibrillin-1 deficiency; combined beta-blocker and ARB therapy is increasingly used in clinical practice.<br><br>Calcium channel blockers (A) are not first-line for aortic protection in Marfan; ACE inhibitors (B) have less evidence than ARBs in this context; diuretics (D) are not indicated for aortic protection; antiplatelet agents (E) target thrombosis not structural aortic deterioration.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"In pyridoxine non-responsive homocystinuria, which treatment combination is most appropriate after pyridoxine failure is confirmed?",o:["High-dose vitamin C supplementation as an antioxidant to protect zonular fibres","Copper supplementation to restore lysyl oxidase function and collagen crosslinking","Zinc acetate therapy targeting copper accumulation in Wilson disease management","Betaine supplementation combined with dietary methionine restriction","Riboflavin supplementation targeting other metabolic cofactor pathways"],a:3,e:"In pyridoxine non-responsive homocystinuria, betaine remethylates homocysteine to methionine reducing plasma homocysteine levels; combined with dietary methionine restriction to reduce substrate load, this forms the cornerstone of treatment in non-responsive cases.<br><br>Cysteine supplementation replaces the deficient downstream product; regular monitoring of plasma homocysteine, methionine, and cysteine guides dose adjustments; folate and vitamin B12 supplementation support the remethylation pathway alongside betaine.<br><br>Vitamin C (A) has antioxidant properties but no specific role in homocystinuria; copper supplementation (B) treats Menkes disease; zinc acetate (C) treats Wilson disease; riboflavin (E) is a cofactor in pathways unrelated to homocystinuria.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which condition causes ectopia lentis through defective copper metabolism rather than a structural protein or enzymatic defect?",o:["Marfan syndrome from fibrillin-1 structural microfibril defect","Ehlers-Danlos syndrome from defective collagen synthesis and crosslinking","Homocystinuria from cystathionine beta-synthase enzymatic deficiency","Weill-Marchesani syndrome from ADAMTS10 or fibrillin-1 gene mutations","Menkes disease from ATP7A"],a:4,e:"Menkes kinky hair disease is caused by ATP7A mutations causing systemic copper deficiency; this impairs lysyl oxidase, a copper-dependent enzyme essential for collagen and elastin crosslinking; defective connective tissue crosslinking weakens zonular fibres causing ectopia lentis.<br><br>Unlike the structural protein defects of Marfan and homocystinuria, Menkes disease operates through a metabolic enzymatic mechanism; the condition is X-linked recessive, affects males predominantly, and presents with progressive neurodegeneration, hypopigmentation, and kinky brittle hair.<br><br>Marfan syndrome (A) involves fibrillin-1 structural defect; Ehlers-Danlos (B) involves collagen synthesis defects not copper; homocystinuria (C) involves CBS enzyme deficiency not copper; Weill-Marchesani (D) involves ADAMTS10 or fibrillin-1 not copper metabolism.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 9-year-old child presents with bilateral inferonasal lens subluxation, developmental delay, and a history of thromboembolic episodes. Which diagnosis is most likely?",o:["Marfan syndrome","Homocystinuria","Weill-Marchesani syndrome","Wilson disease","Stickler syndrome"],a:1,e:"Homocystinuria classically causes inferonasal ectopia lentis along with intellectual disability and thromboembolic tendency.<br><br>Marfan syndrome (A) usually presents with superotemporal lens displacement and normal intelligence.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract is most strongly associated with prolonged steroid therapy?",o:["Posterior subcapsular cataract","Lamellar cataract","Rosette cataract","Coronary cataract","Cerulean cataract"],a:0,e:"Posterior subcapsular cataracts commonly occur in patients receiving long-term corticosteroids and may significantly impair near vision early.<br><br>Of its important systemic associations.<br><br>Rosette cataracts (C) are classically traumatic rather than steroid-induced.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which lens abnormality is classically associated with Marfan syndrome?",o:["Inferonasal lens displacement","Microspherophakia","Posterior lenticonus","Superotemporal ectopia lentis","Aphakia"],a:3,e:"Marfan syndrome produces bilateral superotemporal lens subluxation because of fibrillin-related zonular weakness.<br><br>Microspherophakia (B) is more typical of Weill-Marchesani syndrome.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract morphology is most characteristic after blunt ocular trauma?",o:["Lamellar cataract","Blue-dot cataract","PSC cataract","Coronary cataract","Rosette cataract"],a:4,e:"Blunt trauma produces rosette-shaped posterior cortical opacities due to shock-wave disruption of lens fibers.<br><br>Lamellar cataracts (A) are congenital rather than traumatic.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which condition is strongly associated with microspherophakia and short stature?",o:["Marfan syndrome","Homocystinuria","Ehlers-Danlos syndrome","Stickler syndrome","Weill-Marchesani syndrome"],a:4,e:"Weill-Marchesani syndrome is characterized by short stature, brachydactyly, microspherophakia, and ectopia lentis.<br><br>The spherical lens predisposes patients to pupillary block glaucoma.<br><br>Marfan syndrome (A) typically presents with tall stature rather than short stature.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom is most characteristic of posterior subcapsular cataract?",o:["Severe glare and difficulty in bright light","Peripheral field constriction","Sudden painful blindness","Flashes and floaters","Diplopia only in darkness"],a:0,e:"Posterior subcapsular cataracts scatter centrally entering light rays and therefore produce disproportionate glare symptoms.<br><br>Patients commonly complain of poor near vision and night-driving difficulty despite relatively mild opacities.<br><br>Peripheral field constriction (B) is more typical of glaucoma.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which congenital cataract often requires urgent surgery to prevent deprivation amblyopia?",o:["Sutural cataract","Blue-dot cataract","Dense bilateral congenital cataract","Coronary cataract","Cerulean cataract"],a:2,e:"Dense congenital cataracts block visual stimulation during critical developmental periods and rapidly produce amblyopia.<br><br>Early surgical intervention is strongly emphasized in pediatric ophthalmology recalls.<br><br>Blue-dot cataracts (B) are usually visually insignificant.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract is associated with infrared radiation exposure in glass workers?",o:["Rosette cataract","Lamellar cataract","Coronary cataract","PSC cataract","Glassblower's cataract"],a:4,e:"Infrared radiation exposure damages lens proteins and produces characteristic posterior cortical opacities called glassblower's cataract.<br><br>Rosette cataracts (A) are traumatic rather than occupational.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which lens-induced glaucoma occurs because of leakage of lens proteins from hypermature cataract?",o:["Pigmentary glaucoma","Phacolytic glaucoma","Neovascular glaucoma","Juvenile glaucoma","Congenital glaucoma"],a:1,e:"Leakage of high-molecular-weight lens proteins obstructs trabecular outflow causing phacolytic glaucoma.<br><br>Pigmentary glaucoma (A) results from pigment dispersion rather than lens protein leakage.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which postoperative cataract complication is treated with Nd:YAG laser capsulotomy?",o:["Endophthalmitis","Suprachoroidal hemorrhage","Posterior capsule opacification","Iris prolapse","Cystoid macular edema"],a:2,e:"Posterior capsule opacification develops due to proliferation of residual lens epithelial cells after cataract surgery.<br><br>Nd:YAG capsulotomy rapidly restores visual clarity by creating a posterior capsular opening. PCO treated by Nd:YAG capsulotomy is a heavily emphasised late-complication fact.<br><br>Endophthalmitis (A) is an infectious emergency requiring antimicrobial treatment.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which metabolic disorder is classically associated with sunflower cataract?",o:["Diabetes mellitus","Homocystinuria","Galactosemia","Hyperparathyroidism","Wilson disease"],a:4,e:"Copper deposition within the lens in Wilson disease produces sunflower cataracts and Kayser-Fleischer rings.<br><br>Galactosemia (C) more commonly causes oil-droplet cataracts.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which phenomenon is commonly associated with nuclear sclerosis cataract?",o:["Peripheral field loss","Severe photophobia","Painful red eye","Colored halos only","Second sight"],a:4,e:"Nuclear sclerosis increases the refractive index of the lens nucleus causing acquired myopia and temporary improvement in near vision.<br><br>Painful red eye (C) suggests glaucoma or inflammation rather than uncomplicated nuclear cataract.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which direction of lens displacement is typical of homocystinuria?",o:["Superotemporal","Nasal only","Inferotemporal","Superior only","Inferonasal"],a:4,e:"Homocystinuria classically causes inferonasal ectopia lentis because of defective connective tissue supporting the zonules.<br><br>Marfan syndrome typically causes superotemporal lens displacement.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is most essential before cataract surgery for intraocular lens power calculation?",o:["Gonioscopy","Biometry","Fluorescein angiography","Visual field testing","Hess charting"],a:1,e:"Biometry measures axial length and corneal power for accurate intraocular lens calculation before cataract surgery.<br><br>Correct IOL power is essential for achieving optimal postoperative refractive outcome.<br><br>Visual field testing (D) evaluates optic nerve function rather than IOL power.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which cataract surgery technique uses ultrasonic fragmentation of the nucleus?",o:["Intracapsular extraction","Couching","Phacoemulsification","Discission","Linear extraction"],a:2,e:"Phacoemulsification uses ultrasound energy to emulsify the nucleus through a small incision with rapid visual rehabilitation.<br><br>It is the standard modern cataract surgery technique worldwide.<br><br>Couching (B) is an obsolete historical procedure.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which congenital infection is classically associated with cataract, deafness, and cardiac defects?",o:["Toxoplasmosis","Cytomegalovirus","Syphilis","Herpes simplex","Rubella"],a:4,e:"Congenital rubella syndrome classically presents with cataracts, sensorineural deafness, and congenital heart disease.<br><br>Maternal first-trimester infection carries the highest fetal risk.<br><br>Toxoplasmosis (A) more commonly causes chorioretinitis than congenital cataract.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which type of congenital cataract is usually visually insignificant and discovered incidentally?",o:["Dense total cataract","Morgagnian cataract","Lamellar cataract","Posterior polar cataract","Blue-dot cataract"],a:4,e:"Blue-dot cataracts are small punctate congenital lens opacities that usually do not significantly impair vision.<br><br>Recognition of visually insignificant congenital cataracts is clinically important.<br><br>Dense congenital cataracts (A) cause severe visual deprivation and amblyopia.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which complication is particularly associated with microspherophakia?",o:["Retinal detachment","Corneal ulceration","Pupillary block glaucoma","Endophthalmitis","Optic neuritis"],a:2,e:"The spherical lens in microspherophakia tends to move anteriorly and precipitate pupillary block glaucoma.<br><br>Endophthalmitis (D) is unrelated to microspherophakia.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which structure is preserved during extracapsular cataract extraction?",o:["Entire lens capsule","Posterior capsule","Lens nucleus","Corneal endothelium","Zonules completely intact always"],a:1,e:"Extracapsular extraction removes the lens nucleus and cortex while preserving the posterior capsule for IOL support.<br><br>Posterior capsule preservation reduces vitreous-related complications.<br><br>Entire capsule removal (A) occurs during intracapsular extraction.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which statement regarding ectopia lentis is most accurate?",o:["Marfan syndrome causes inferonasal lens displacement","Homocystinuria causes superotemporal lens displacement","Microspherophakia has no glaucoma association","Marfan syndrome classically causes superotemporal lens subluxation","Ectopia lentis never affects vision significantly"],a:3,e:"Marfan syndrome produces superotemporal lens displacement due to fibrillin-related zonular weakness.<br><br>Homocystinuria (B) classically causes inferonasal displacement, while microspherophakia (C) strongly predisposes to glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 65-year-old diabetic patient complains of marked glare while driving at night despite only mild lens opacity on examination. Which cataract type most likely explains this symptom?",o:["Nuclear sclerosis","Posterior subcapsular cataract","Lamellar cataract","Rosette cataract","Coronary cataract"],a:1,e:"Posterior subcapsular cataracts scatter centrally entering light rays near the nodal point of the eye, causing disproportionate glare and near-vision difficulty.<br><br>Of its associations with diabetes, steroids, and uveitis.<br><br>Nuclear sclerosis (A) more commonly produces gradual myopic shift and second sight rather than early severe glare.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"A tall adolescent with arachnodactyly and pectus excavatum is found to have bilateral lens subluxation. Which direction of displacement is classically expected?",o:["Inferonasal","Inferotemporal","Superior only","Superotemporal","Central displacement"],a:3,e:"Marfan syndrome classically causes bilateral superotemporal ectopia lentis because of fibrillin-related zonular weakness.<br><br>Inferonasal displacement (A) is more typical of homocystinuria.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which postoperative cataract surgery complication presents with severe ocular pain, hypopyon, and profound visual loss?",o:["Posterior capsule opacification","Cystoid macular edema","Posterior vitreous detachment","Corneal astigmatism","Endophthalmitis"],a:4,e:"Postoperative endophthalmitis is a devastating intraocular infection characterized by pain, redness, hypopyon, and severe visual loss.<br><br>Posterior capsule opacification (A) causes gradual painless visual decline rather than acute inflammation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which metabolic disorder is classically associated with oil-droplet cataract in infancy?",o:["Wilson disease","Homocystinuria","Diabetes mellitus","Galactosemia","Hyperparathyroidism"],a:3,e:"Accumulation of galactose metabolites within the lens produces osmotic damage leading to characteristic oil-droplet cataracts.<br><br>Wilson disease (A) is associated with sunflower cataracts rather than oil-droplet cataracts.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which complication is particularly associated with microspherophakia in Weill-Marchesani syndrome?",o:["Retinal artery occlusion","Corneal ulceration","Optic neuritis","Vitreous hemorrhage","Pupillary block glaucoma"],a:4,e:"Microspherophakia produces a small spherical lens that tends to move anteriorly, predisposing to pupillary block glaucoma.<br><br>Optic neuritis (C) and vitreous hemorrhage (D) are unrelated to microspherophakia.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 45-year-old teacher complains he no longer needs his reading glasses after wearing them for ten years. He now reads newspapers comfortably without spectacles. Slit-lamp shows a brunescent central lens opacity. What is the phenomenon responsible?",o:["Second sight","Ciliary spasm","Corneal change","Vitreous shift","Capsule scatter"],a:0,e:"Second sight occurs when progressive nuclear sclerosis increases the refractive index of the hardening nucleus, producing index myopia; this myopic shift temporarily corrects pre-existing presbyopia, allowing comfortable near vision without spectacles previously required.<br><br>This improvement is transient; as nuclear density increases further, progressive light scattering overwhelms the myopic benefit, causing deterioration of both near and distance vision; the brunescent opacity on slit-lamp confirms the diagnosis.<br><br>Ciliary spasm (B) does not produce sustained myopic shift; corneal change (C) does not occur in nuclear cataract; vitreous shift (D) does not alter refraction meaningfully; capsule scatter (E) causes glare and near difficulty not a myopic shift.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 6-week-old infant is brought by parents who noticed a white reflex in the left eye on photographs. Examination under anaesthesia shows a dense central opacity occupying the entire left pupil. The right eye is normal. B-scan shows no posterior segment abnormality. What is the single most important next step?",o:["Urgent MRI orbits","Atropine penalisation","Bilateral eye patching","Metabolic screening","Lens extraction and patching"],a:4,e:"Dense unilateral congenital cataract causes complete visual deprivation during the most critical period of cortical visual development; surgery must be performed within the first six to ten weeks of life, followed immediately by optical rehabilitation and patching of the normal eye to prevent irreversible deprivation amblyopia.<br><br>Every day of delay worsens the amblyopia prognosis irreversibly; once retinoblastoma is excluded clinically and by B-scan, surgical intervention takes absolute priority over any further investigation.<br><br>Urgent MRI (A) is indicated only if B-scan suggests a posterior mass; bilateral patching without surgery (C) is harmful as the opacity remains; metabolic screening (D) is secondary to immediate surgical need; atropine penalisation (B) cannot rehabilitate a visually deprived eye with a dense opacity in place.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 35-year-old female on long-term oral prednisolone for asthma presents with bilateral gradual blurring worse in bright light and difficulty reading. Slit-lamp shows bilateral posterior subcapsular opacities. What is the causative mechanism?",o:["Aldose reductase path","Polyol accumulation","Lens epithelial migration","Zonular calcification","Nuclear denaturation"],a:2,e:"Corticosteroids inhibit lens epithelial cell differentiation and stimulate their aberrant migration toward the posterior pole; the accumulating disordered cells beneath the posterior capsule scatter light, causing glare and disproportionate near vision difficulty relative to opacity size.<br><br>The posterior subcapsular location interferes maximally with vision in bright light when miosis concentrates rays through the affected zone; even a small opacity here reduces visual quality dramatically, explaining significant disability despite relatively preserved Snellen acuity.<br><br>Aldose reductase path (A) and polyol accumulation (B) cause diabetic cataract; zonular calcification (D) is unrelated to steroid use; nuclear denaturation (E) produces age-related nuclear sclerosis not posterior subcapsular change.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 3-year-old child presents with a squint. Fundal examination is normal. Slit-lamp shows a small white opacity at the anterior pole of the lens bilaterally, each less than 2 mm. Vision is 6/9 bilaterally. What is the most appropriate management?",o:["Bilateral lensectomy","Alternate eye patching","Urgent metabolic tests","Spectacles and monitoring","Nd:YAG laser"],a:3,e:"Bilateral anterior polar cataracts less than 2 mm are stationary, non-progressive, and rarely visually significant; when vision is 6/9 bilaterally with no anisometropia, conservative management with optical correction of any refractive error and regular monitoring is the appropriate first-line approach.<br><br>Surgery is reserved for cases where the opacity enlarges, vision deteriorates despite optical correction, or amblyopia becomes resistant to spectacle treatment; the stable non-progressive nature of anterior polar cataract makes early surgical intervention unjustified.<br><br>Bilateral lensectomy (A) is not indicated for small stationary opacities with good vision; alternate patching (B) without optical correction is insufficient; urgent metabolic tests (C) are not indicated for anterior polar cataract; Nd:YAG laser (E) treats posterior capsule opacification not anterior polar opacities.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 70-year-old farmer presents with severe eye pain, red eye, and vision of hand movements. He had a white mature cataract for two years. Slit-lamp shows corneal oedema, shallow anterior chamber, and a swollen white lens. IOP is 54 mmHg. What is the diagnosis?",o:["Phacolytic type","Lens particle type","Neovascular type","Primary closure type","Phacomorphic type"],a:4,e:"The intumescent swollen lens has expanded sufficiently to push the iris-lens diaphragm anteriorly, shallowing the anterior chamber and closing the drainage angle; the resulting acute angle closure elevation of IOP to 54 mmHg with corneal oedema and severe pain is classic phacomorphic glaucoma.<br><br>Emergency management includes topical IOP-lowering agents, systemic acetazolamide, and intravenous mannitol; definitive treatment is prompt lens extraction, which immediately relieves the mechanical angle closure and restores normal anterior chamber anatomy.<br><br>Phacolytic type (A) occurs with hypermature cataract and an open angle; lens particle type (B) follows surgery not an intumescent lens; neovascular type (C) follows retinal ischaemia with rubeosis; primary closure type (D) occurs in a predisposed eye without an intumescent lens as the precipitant.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 55-year-old diabetic woman presents two weeks after uneventful phacoemulsification with progressive painless blurring. Slit-lamp shows mild anterior chamber flare, small white cortical particles floating freely, and IOP of 38 mmHg. What is the diagnosis?",o:["Lens particle glaucoma","Toxic segment syndrome","Acute endophthalmitis","Capsule opacification","Steroid response"],a:0,e:"Retained cortical lens particles following phacoemulsification trigger macrophage infiltration; these macrophage-laden cells and free cortical particles physically obstruct the trabecular meshwork, producing open-angle elevation of IOP and low-grade anterior chamber inflammation two weeks postoperatively.<br><br>Management involves intensive topical anti-inflammatory therapy and IOP-lowering agents; if particles remain visible and IOP is uncontrolled, surgical anterior chamber washout removes the retained material definitively, resolving both the inflammation and elevated pressure simultaneously.<br><br>Toxic segment syndrome (B) presents acutely within 48 hours with diffuse corneal oedema; acute endophthalmitis (C) causes pain, hypopyon, and vitreous involvement; capsule opacification (D) causes painless blurring months later without raised IOP; steroid response (E) occurs without visible cortical particles in the anterior chamber.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 25-year-old male with intellectual disability, marfanoid habitus, and a history of pulmonary embolism at age 20 presents with inferiorly dislocated lenses bilaterally. Urine nitroprusside test is strongly positive. Which perioperative precaution is most critical if lens surgery is planned?",o:["Echocardiography first","Hydration and anticoagulation","Avoid all mydriatics","Preoperative pilocarpine","Avoid general anaesthesia"],a:1,e:"This patient has homocystinuria confirmed by a positive nitroprusside test; homocysteine-mediated endothelial damage and platelet hyperaggregability create a profound prothrombotic state dramatically worsened by anaesthesia, surgical stress, and dehydration, potentially causing fatal stroke or pulmonary embolism perioperatively.<br><br>Haematological liaison to plan anticoagulation, preoperative optimisation of plasma homocysteine with betaine and pyridoxine, ensuring adequate hydration throughout, and minimising anaesthetic duration are mandatory specific precautions unique to homocystinuria.<br><br>Echocardiography first (A) is the priority in Marfan not homocystinuria; avoiding mydriatics (C) is relevant in microspherophakia; preoperative pilocarpine (D) worsens pupil block when the lens is anteriorly displaced; avoiding general anaesthesia (E) is not always feasible and hydration-anticoagulation remains critical regardless of anaesthetic type.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 68-year-old man undergoes phacoemulsification. During cortical aspiration the surgeon notices sudden deepening of the anterior chamber and loss of the red reflex. The nuclear fragment moves posteriorly. What has most likely occurred?",o:["Suprachoroidal bleed","Zonular dialysis","Capsule rupture","Iris prolapse","Wound dehiscence"],a:2,e:"Sudden anterior chamber deepening combined with loss of red reflex and posterior movement of nuclear fragments are the classic intraoperative signs of posterior capsule rupture; vitreous prolapsing anteriorly through the rent causes the chamber to deepen and the red reflex to disappear.<br><br>The phaco tip must be withdrawn immediately; anterior vitrectomy is performed to clear vitreous from the anterior segment; IOL placement strategy is then modified based on the extent of capsular and zonular damage, with sulcus or scleral fixation replacing in-the-bag implantation. Recognising a posterior capsule rupture during cortical aspiration is a high-stakes intraoperative scenario.<br><br>Suprachoroidal bleed (A) causes sudden shallowing not deepening; zonular dialysis (B) causes bag instability without red reflex loss; iris prolapse (D) is visible at the wound without causing red reflex loss; wound dehiscence (E) is a postoperative not an intraoperative event.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 14-year-old girl with fair skin, lens subluxation, intractable seizures since infancy, and profound intellectual disability undergoes metabolic screening. Urine nitroprusside is negative. Urinary sulphite dipstick is strongly positive. What is the diagnosis?",o:["Homocystinuria","Galactosaemia","Marfan syndrome","Molybdenum deficiency","Hyperlysinaemia"],a:3,e:"Molybdenum cofactor deficiency causes functional sulphite oxidase deficiency; the positive urinary sulphite dipstick with a negative nitroprusside test excludes homocystinuria and confirms sulphite accumulation; the clinical triad of ectopia lentis, intractable seizures, and intellectual disability with fair skin is characteristic.<br><br>Fair skin results from sulphite-mediated inhibition of tyrosinase impairing melanin synthesis; the condition is autosomal recessive and usually fatal in infancy in severe forms; cyclic pyranopterin monophosphate substitute has shown benefit in the MOCODA subtype specifically.<br><br>Homocystinuria (A) gives a positive nitroprusside not sulphite dipstick; galactosaemia (B) presents with oil droplet cataract and reducing urinary substances; Marfan syndrome (C) has no metabolic urinary abnormality; hyperlysinaemia (E) involves lysine accumulation with milder neurological features.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 72-year-old woman presents with sudden severe unilateral eye pain, corneal oedema, and vision of counting fingers. She has had a white cataract for three years but refused surgery. Slit-lamp shows a shrunken wrinkled lens capsule, milky fluid in the anterior chamber, and open angle on gonioscopy. IOP is 46 mmHg. What is the diagnosis?",o:["Phacomorphic type","Primary closure type","Neovascular type","Lens particle type","Phacolytic type"],a:4,e:"The hypermature Morgagnian cataract has a permeable capsule through which liquefied high-molecular-weight lens proteins leak into the anterior chamber; macrophages engulfing these proteins together with free lens proteins physically obstruct the trabecular meshwork producing open-angle IOP elevation despite a wrinkled shrunken capsule.<br><br>The milky white material in the anterior chamber confirms lens protein leakage; urgent IOP reduction medically followed by lens extraction removes the source of trabecular obstruction; the open angle on gonioscopy critically distinguishes phacolytic from phacomorphic glaucoma.<br><br>Phacomorphic type (A) involves a swollen intumescent lens with angle closure not an open angle; primary closure type (B) occurs in a predisposed eye without lens protein leakage; neovascular type (C) shows rubeosis iridis on examination; lens particle type (D) follows surgical intervention not a spontaneous hypermature cataract.<br><br><em>(Parson's Diseases of the Eye)</em>"},
];